  22,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Rediseñando la fila de disputa con más espaciado y un layout responsivo más claro, inspirado en las tarjetas móviles de partidos.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  return (\n    <article\n      id={rowId}\n      data-name=\"notifications-dispute-row\"\n      className={cn(\n        ''rounded-2xl border shadow-sm transition-[box-shadow,transform] duration-200 hover:shadow-md'',\n        ''px-4 py-4 sm:px-5 sm:py-4 lg:px-6 lg:py-5'',\n        tone,\n      )}\n    >\n      <div className=\"flex flex-col gap-4 lg:flex-row lg:items-stretch lg:gap-6 xl:gap-8\">\n        <div id={`${rowId}-meta`} data-name=\"dispute-row-meta\" className=\"min-w-0 flex-1 space-y-3\">\n          <div className=\"flex flex-col gap-2 sm:flex-row sm:flex-wrap sm:items-center sm:gap-x-3 sm:gap-y-2\">\n            <div className=\"flex flex-wrap items-center gap-2\">\n              <span\n                id={`${rowId}-group`}\n                data-name=\"dispute-row-group\"\n                className=\"rounded-md bg-white/70 px-2 py-1 text-[11px] font-semibold uppercase tracking-wide text-slate-700 sm:text-xs\"\n              >\n                {match.groupName}\n              </span>\n              <span\n                id={`${rowId}-status`}\n                data-name=\"dispute-row-status\"\n                className={cn(\n                  ''rounded-full border px-2.5 py-0.5 text-[11px] font-semibold tracking-tight sm:text-xs'',\n                  match.status === ''closed'' && ''border-green-300 bg-white/80 text-green-900'',\n                  match.status === ''validated'' && ''border-emerald-300 bg-white/80 text-emerald-900'',\n                  match.status === ''player_confirmed'' && ''border-yellow-300 bg-white/80 text-yellow-900'',\n                  match.status === ''score_disputed'' && ''border-amber-300 bg-white/80 text-amber-950'',\n                  match.status === ''score_submitted'' && ''border-blue-300 bg-white/80 text-blue-900'',\n                  match.status === ''pending_score'' && ''border-neutral-300 bg-white/80 text-neutral-800'',\n                  match.status === ''cancelled'' && ''border-slate-300 bg-white/70 text-slate-700'',\n                )}\n              >\n                {statusShortLabel(match.status)}\n              </span>\n            </div>\n            {!quickReview ? (\n              <span\n                id={`${rowId}-submitted-at`}\n                data-name=\"dispute-row-submitted-at\"\n                className=\"shrink-0 tabular-nums text-[11px] font-medium text-slate-500 sm:ml-auto sm:text-xs\"\n              >\n                {shortDate(match.score_submitted_at)}\n              </span>\n            ) : null}\n          </div>\n\n          <p\n            id={`${rowId}-players`}\n            data-name=\"dispute-row-players\"\n            className=\"text-pretty text-base font-semibold leading-snug text-slate-950 sm:text-lg\"\n          >\n            <span className=\"uppercase tracking-tight\">{match.playerAName}</span>{'' ''}\n            <span className=\"font-normal text-slate-400\">vs</span>{'' ''}\n            <span className=\"uppercase tracking-tight\">{match.playerBName}</span>\n          </p>\n\n          {!quickReview ? (\n            isDisputed && disputeSnippet ? (\n              <div\n                id={`${rowId}-context`}\n                data-name=\"dispute-row-context\"\n                className=\"space-y-1.5 rounded-xl border border-amber-200/80 bg-white/60 px-3 py-2.5 sm:px-4 sm:py-3\"\n                title={`${match.tournamentName} · ${disputeSnippet}`}\n              >\n                <p\n                  id={`${rowId}-tournament`}\n                  data-name=\"dispute-row-tournament\"\n                  className=\"text-xs font-medium text-slate-600 sm:text-sm\"\n                >\n                  {match.tournamentName}\n                </p>\n                <p className=\"text-pretty text-xs leading-relaxed text-amber-950 sm:text-sm\">{disputeSnippet}</p>\n              </div>\n            ) : (\n              <p\n                id={`${rowId}-tournament`}\n                data-name=\"dispute-row-tournament\"\n                className=\"text-xs font-medium text-slate-600 sm:text-sm\"\n              >\n                {match.tournamentName}\n              </p>\n            )\n          ) : null}\n\n          {!quickReview && match.admin_notes ? (\n            <p\n              className=\"rounded-lg border border-slate-200/80 bg-white/50 px-3 py-2 text-xs leading-relaxed text-slate-600\"\n              title={match.admin_notes}\n            >\n              <span className=\"font-medium text-slate-700\">Nota:</span> {match.admin_notes}\n            </p>\n          ) : null}\n\n          {!quickReview && (match.status === ''closed'' || match.status === ''validated'') ? (\n            <p className=\"text-xs text-slate-500\">\n              Cerrado {shortDate(match.admin_validated_at ?? match.closed_at)}\n            </p>\n          ) : null}\n        </div>\n\n        <div\n          id={`${rowId}-score-actions`}\n          data-name=\"dispute-row-score-actions\"\n          className=\"flex min-w-0 flex-col gap-4 border-t border-slate-200/70 pt-4 lg:w-[min(100%,22rem)] lg:shrink-0 lg:border-l lg:border-t-0 lg:pl-6 lg:pt-0 xl:w-[min(100%,24rem)]\"\n        >\n          <div\n            id={`${rowId}-score`}\n            data-name=\"dispute-row-score\"\n            className=\"rounded-xl border border-slate-200/70 bg-white/70 px-4 py-3 sm:px-5 sm:py-3.5\"\n          >\n            <p className=\"text-[11px] font-semibold uppercase tracking-wide text-slate-500\">Marcador</p>\n            <p\n              id={`${rowId}-score-value`}\n              data-name=\"dispute-row-score-value\"\n              className=\"mt-1 font-mono text-xl font-bold tabular-nums leading-none tracking-tight text-slate-950 sm:text-2xl