={() => onCorrect(match)}\n                >\n                  <Pencil className=\"size-3 opacity-80\" />\n                  Corregir\n                </Button>\n              </>\n            )}\n          </div>\n        </div>\n      </div>\n    </article>\n  )", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "            className=\"absolute left-0 top-0 w-full px-3 pb-3 pt-1 sm:px-4 sm:pb-4 sm:pt-1.5\"", "old_string": "            className=\"absolute left-0 top-0 w-full px-2 pb-1.5 pt-0\"", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultsVirtualList.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "            estimateRowHeight={168}", "old_string": "            estimateRowHeight={96}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminNotificationsPage.tsx"}}]}}'
