INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0029',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  29,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Implementando filas colapsables: resumen compacto por defecto y detalle completo al expandir.\n\n[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "contents": "import { Ban, CheckCircle2, ChevronDown, Pencil } from ''lucide-react''\nimport { useState } from ''react''\n\nimport { Button } from ''@/components/ui/button''\nimport { cn } from ''@/lib/utils''\nimport type { AdminMatchRecord } from ''@/services/admin''\nimport type { MatchStatus } from ''@/types/database''\n\nfunction formatScore(match: AdminMatchRecord) {\n  return match.score_raw?.map((set) => `${set.a}-${set.b}`).join('' · '') ?? ''—''\n}\n\nfunction shortDate(iso: string | null | undefined) {\n  if (!iso) return ''—''\n  const d = new Date(iso)\n  if (Number.isNaN(d.getTime())) return ''—''\n  return new Intl.DateTimeFormat(''es'', { dateStyle: ''short'', timeStyle: ''short'' }).format(d)\n}\n\nfunction statusShortLabel(status: MatchStatus): string {\n  switch (status) {\n    case ''pending_score'':\n      return ''Sin marcador''\n    case ''score_submitted'':\n      return ''Confirmado · validación''\n    case ''score_disputed'':\n      return ''Revisión disputa''\n    case ''player_confirmed'':\n      return ''Pendiente validación''\n    case ''closed'':\n      return ''Oficial jugador''\n    case ''validated'':\n      return ''Validado admin''\n    case ''cancelled'':\n      return ''Cancelado''\n    default:\n      return status\n  }\n}\n\nfunction rowTone(status: MatchStatus): string {\n  switch (status) {\n    case ''closed'':\n      return ''border-green-200 bg-green-50/90 hover:bg-green-50''\n    case ''validated'':\n      return ''border-emerald-200 bg-emerald-50/90 hover:bg-emerald-50''\n    case ''player_confirmed'':\n      return ''border-yellow-200 bg-yellow-50/90 hover:bg-yellow-50''\n    case ''score_disputed'':\n      return ''border-amber-200 bg-amber-50/90 hover:bg-amber-50''\n    case ''score_submitted'':\n      return ''border-blue-200 bg-blue-50/90 hover:bg-blue-50''\n    case ''pending_score'':\n      return ''border-neutral-200 bg-neutral-50/90 hover:bg-neutral-50''\n    default:\n      return ''border-slate-200 bg-slate-50/90 hover:bg-slate-50''\n  }\n}\n\nfunction winnerLabel(match: AdminMatchRecord): string {\n  if (match.winner_id === match.player_a_id) return match.playerAName\n  if (match.winner_id === match.player_b_id) return match.playerBName\n  return ''—''\n}\n\nfunction statusBadgeClass(status: MatchStatus): string {\n  switch (status) {\n    case ''closed'':\n      return ''border-green-300 bg-white/80 text-green-900''\n    case ''validated'':\n      return ''border-emerald-300 bg-white/80 text-emerald-900''\n    case ''player_confirmed'':\n      return ''border-yellow-300 bg-white/80 text-yellow-900''\n    case ''score_disputed'':\n      return ''border-amber-300 bg-white/80 text-amber-950''\n    case ''score_submitted'':\n      return ''border-blue-300 bg-white/80 text-blue-900''\n    case ''pending_score'':\n      return ''border-neutral-300 bg-white/80 text-neutral-800''\n    case ''cancelled'':\n      return ''border-slate-300 bg-white/70 text-slate-700''\n    default:\n      return ''border-slate-300 bg-white/70 text-slate-700''\n  }\n}\n\nfunction DisputeActionButtons({\n  rowId,\n  match,\n  isDisputed,\n  canValidateLegacy,\n  onValidateAsIs,\n  onInvalidate,\n  onCorrect,\n  onConfirm,\n}: {\n  rowId: string\n  match: AdminMatchRecord\n  isDisputed: boolean\n  canValidateLegacy: boolean\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  onInvalidate?: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onConfirm: (match: AdminMatchRecord) => void\n}) {\n  return (\n    <div\n      id={`${rowId}-actions`}\n      data-name=\"dispute-row-actions\"\n      className=\"grid grid-cols-2 gap-2 sm:flex sm:flex-wrap sm:justify-end lg:grid-cols-1 xl:grid-cols-2\"\n    >\n      {isDisputed ? (\n        <>\n          <Button\n            id={`${rowId}-btn-validate`}\n            name={`validate-dispute-${match.id}`}\n            data-name=\"dispute-action-validate\"\n            size=\"sm\"\n            title=\"Marcar como válido (sin cambiar marcador)\"\n            className=\"col-span-2 h-10 border-transparent bg-emerald-600 text-white hover:bg-emerald-700 sm:col-span-1 sm:h-9 lg:col-span-1 xl:col-span-2\"\n            onClick={() => onValidateAsIs?.(match)}\n            disabled={!onValidateAsIs}\n          >\n            <CheckCircle2 className=\"size-3.5 opacity-90\" />\n            Válido\n          </Button>\n          <Button\n            id={`${rowId}-btn-invalidate`}\n            name={`invalidate-dispute-${match.id}`}\n            data-name=\"dispute-action-invalidate\"\n            size=\"sm\"\n            variant=\"destructive\"\n            title=\"Invalidar partido (cancelado, fuera del ranking)\"\n            className=\"h-10 sm:h-9\"\n            onClick={() => onInvalidate?.(match)}\n            disabled={!onInvalidate}\n          >\n            <Ban className=\"size-3.5 opacity-90\" />\n            Invalidar\n          </Button>\n          <Button\n            id={`${rowId}-btn-correct`}\n            name={`correct-dispute-${match.id}`}\n            data-name=\"dispute-action-correct\"\n            size=\"sm\"\n            variant=\"outline\"\n            title=\"Corregir marcador\"\n            className=\"h-10 border-slate-300 bg-white sm:h-9\"\n            onClick={() => onCorrect(match)}\n          >\n            <Pencil className=\"size-3.5 opacity-80\" />\n            Corregir\n          </Button>\n        </>\n      ) : (\n        <>\n          <Button\n            id={`${rowId}-btn-validate-legacy`}\n            name={`validate-match-${match.id}`}\n            data-name=\"dispute-action-validate-legacy\"\n            size=\"sm\"\n            disabled={!canValidateLegacy}\n            title={\n              canValidateLegacy\n                ? undefined\n                : ''Solo cuando el rival ya aceptó el marcador (pendiente de validación).''\n            }\n            className=\"col-span-2 h-10 border-transparent bg-emerald-600 text-white hover:bg-emerald-700 sm:col-span-1 sm:h-9 lg:col-span-1 xl:col-span-2\"\n            onClick={() => onConfirm(match)}\n          >\n            <CheckCircle2 className=\"size-3.5 opacity-90\" />\n            Validar\n          </Button>\n          <Button\n            id={`${rowId}-btn-correct-legacy`}\n            name={`correct-match-${match.id}`}\n            data-name=\"dispute-action-correct-legacy\"\n            size=\"sm\"\n            variant=\"outline\"\n            title=\"Corregir marcador\"\n            className=\"col-span-2 h-10 border-slate-300 bg-white sm:col-span-1 sm:h-9 lg:col-span-1 xl:col-span-2\"\n            onClick={() => onCorrect(match)}\n          >\n            <Pencil className=\"size-3.5 opacity-80\" />\n            Corregir\n          </Button>\n        </>\n      )}\n    </div>\n  )\n}\n\nexport function AdminResultReviewRow({\n  match,\n  quickReview,\n  onConfirm,\n  onCorrect,\n  onValidateAsIs,\n  onInvalidate,\n}: {\n  match: AdminMatchRecord\n  quickReview: boolean\n  onConfirm: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  onInvalidate?: (match: AdminMatchRecord) => void\n}) {\n  const [expanded, setExpanded] = useState(false)\n  const isDisputed = match.status === ''score_disputed''\n  const canValidateLegacy = match.status === ''player_confirmed'' || match.status === ''score_submitted''\n  const tone = rowTone(match.status)\n  const rowId = `admin-notifications-dispute-${match.id}`\n  const collapsible = !quickReview\n\n  const disputeSnippet =\n    !quickReview && isDisputed\n      ? [\n          match.dispute_reason ? `Motivo: ${match.dispute_reason}` : null,\n          match.disputedByLabel ? `Refutó: ${match.disputedByLabel}` : null,\n        ]\n          .filter(Boolean)\n          .join('' · '')\n      : ''''\n\n  const summaryHint =\n    isDisputed && disputeSnippet\n      ? disputeSnippet\n      : !quickReview\n        ? match.tournamentName\n        : null\n\n  if (!collapsible) {\n    return (\n      <article\n        id={rowId}\n        data-name=\"notifications-dispute-row\"\n        data-expanded=\"true\"\n        className={cn(\n          ''rounded-2xl border shadow-sm transition-[box-shadow,transform] duration-200 hover:shadow-md'',\n          ''px-4 py-4 sm:px-5 sm:py-4 lg:px-6 lg:py-5'',\n          tone,\n        )}\n      >\n        <div className=\"flex flex-col gap-4 lg:flex-row lg:items-stretch lg:gap-6 xl:gap-8\">\n          <div id={`${rowId}-meta`} data-name=\"dispute-row-meta\" className=\"min-w-0 flex-1 space-y-3\">\n            <div className=\"flex flex-wrap items-center gap-2\">\n              <span\n                id={`${rowId}-group`}\n                data-name=\"dispute-row-group\"\n                className=\"rounded-md bg-white/70 px-2 py-1 text-[11px] font-semibold uppercase tracking-wide text-slate-700 sm:text-xs\"\n              >\n                {match.groupName}\n              </span>\n              <span\n                id={`${rowId}-status`}\n                data-name=\"dispute-row-status\"\n                className={cn(\n                  ''rounded-full border px-2.5 py-0.5 text-[11px] font-semibold tracking-tight sm:text-xs'',\n                  statusBadgeClass(match.status),\n                )}\n              >\n                {statusShortLabel(match.status)}\n              </span>\n            </div>\n            <p\n              id={`${rowId}-players`}\n              data-name=\"dispute-row-players\"\n              className=\"text-pretty text-base font-semibold leading-snug text-slate-950 sm:text-lg\"\n            >\n              <span className=\"uppercase tracking-tight\">{match.playerAName}</span>{'' ''}\n              <span className=\"font-normal text-slate-400\">vs</span>{'' ''}\n              <span className=\"uppercase tracking-tight\">{match.playerBName}</span>\n            </p>\n          </div>\n          <div\n            id={`${rowId}-score-actions`}\n            data-name=\"dispute-row-score-actions\"\n            className=\"flex min-w-0 flex-col gap-4 border-t border-slate-200/70 pt-4 lg:w-[min(100%,22rem)] lg:shrink-0 lg:border-l lg:border-t-0 lg:pl-6 lg:pt-0 xl:w-[min(100%,24rem)]\"\n          >\n            <div\n              id={`${rowId}-score`}\n              data-name=\"dispute-row-score\"\n              className=\"rounded-xl border border-slate-200/70 bg-white/70 px-4 py-3 sm:px-5 sm:py-3.5\"\n            >\n              <p\n                id={`${rowId}-score-value`}\n                data-name=\"dispute-row-score-value\"\n                className=\"font-mono text-xl font-bold tabular-nums leading-none tracking-tight text-slate-950 sm:text-2xl\"\n              >\n                {formatScore(match)}\n              </p>\n              <p className=\"mt-2 text-xs font-medium text-slate-800\">\n                Ganador: <span className=\"text-slate-950\">{winnerLabel(match)}</span>\n              </p>\n            </div>\n            <DisputeActionButtons\n              rowId={rowId}\n              match={match}\n              isDisputed={isDisputed}\n              canValidateLegacy={canValidateLegacy}\n              onValidateAsIs={onValidateAsIs}\n              onInvalidate={onInvalidate}\n              onCorrect={onCorrect}\n              onConfirm={onConfirm}\n            />\n          </div>\n        </div>\n      </article>\n    )\n  }\n\n  return (\n    <article\n      id={rowId}\n      data-name=\"notifications-dispute-row\"\n      data-expanded={expanded ? ''true'' : ''false''}\n      className={cn(\n        ''rounded-2xl border shadow-sm transition-[box-shadow,transform] duration-200 hover:shadow-md'',\n        expanded ? ''px-4 py-4 sm:px-5 sm:py-4 lg:px-6 lg:py-5'' : ''px-3 py-3 sm:px-4 sm:py-3.5'',\n        tone,\n      )}\n    >\n      <button\n        id={`${rowId}-toggle`}\n        name={`toggle-dispute-${match.id}`}\n        data-name=\"dispute-row-toggle\"\n        type=\"button\"\n        aria-expanded={expanded}\n        aria-controls={`${rowId}-details`}\n        onClick={() => setExpanded((open) => !open)}\n        className=\"flex w-full min-w-0 items-start gap-3 rounded-xl text-left outline-none transition-colors hover:bg-white/40 focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25 focus-visible:ring-offset-2 focus-visible:ring-offset-transparent sm:gap-4\"\n      >\n        <div id={`${rowId}-summary`} data-name=\"dispute-row-summary\" className=\"min-w-0 flex-1 space-y-2\">\n          <div className=\"flex flex-wrap items-center gap-2\">\n            <span\n              id={`${rowId}-group`}\n              data-name=\"dispute-row-group\"\n              className=\"rounded-md bg-white/70 px-2 py-1 text-[11px] font-semibold uppercase tracking-wide text-slate-700 sm:text-xs\"\n            >\n              {match.groupName}\n            </span>\n            <span\n              id={`${rowId}-status`}\n              data-name=\"dispute-row-status\"\n              className={cn(\n                ''rounded-full border px-2.5 py-0.5 text-[11px] font-semibold tracking-tight sm:text-xs'',\n                statusBadgeClass(match.status),\n              )}\n            >\n              {statusShortLabel(match.status)}\n            </span>\n            <span\n              id={`${rowId}-submitted-at`}\n              data-name=\"dispute-row-submitted-at\"\n              className=\"ml-auto shrink-0 tabular-nums text-[11px] font-medium text-slate-500 sm:text-xs\"\n            >\n              {shortDate(match.score_submitted_at)}\n            </span>\n          </div>\n\n          <div className=\"flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between sm:gap-4\">\n            <div className=\"min-w-0 flex-1 space-y-1\">\n              <p\n                id={`${rowId}-players`}\n                data-name=\"dispute-row-players\"\n                className=\"line-clamp-2 text-pretty text-sm font-semibold leading-snug text-slate-950 sm:line-clamp-1 sm:text-base\"\n              >\n                <span className=\"uppercase tracking-tight\">{match.playerAName}</span>{'' ''}\n                <span className=\"font-normal text-slate-400\">vs</span>{'' ''}\n                <span className=\"uppercase tracking-tight\">{match.playerBName}</span>\n              </p>\n              {summaryHint ? (\n                <p\n                  id={expanded ? undefined : `${rowId}-context`}\n                  data-name=\"dispute-row-summary-hint\"\n                  className={cn(\n                    ''line-clamp-2 text-xs leading-relaxed sm:line-clamp-1 sm:text-[13px]'',\n                    isDisputed && disputeSnippet ? ''text-amber-950'' : ''text-slate-600'',\n                  )}\n                  title={summaryHint}\n                >\n                  {summaryHint}\n                </p>\n              ) : null}\n            </div>\n\n            <div\n              id={`${rowId}-score-compact`}\n              data-name=\"dispute-row-score-compact\"\n              className=\"flex shrink-0 items-center gap-2 rounded-lg border border-slate-200/70 bg-white/70 px-3 py-2 sm:flex-col sm:items-end sm:gap-0 sm:border-0 sm:bg-transparent sm:px-0 sm:py-0\"\n            >\n              <span className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-500 sm:hidden\">Marcador</span>\n              <span\n                id={`${rowId}-score-value`}\n                data-name=\"dispute-row-score-value\"\n                className=\"font-mono text-base font-bold tabular-nums leading-none tracking-tight text-slate-950 sm:text-lg\"\n              >\n                {formatScore(match)}\n              </span>\n            </div>\n          </div>\n        </div>\n\n        <span\n          id={`${rowId}-chevron`}\n          data-name=\"dispute-row-chevron\"\n          className=\"mt-0.5 flex size-8 shrink-0 items-center justify-center rounded-lg bg-white/60 text-slate-500 sm:size-9\"\n          aria-hidden\n        >\n          <ChevronDown className={cn(''size-4 transition-transform duration-200'', expanded && ''rotate-180'')} />\n        </span>\n      </button>\n\n      {expanded ? (\n        <div\n          id={`${rowId}-details`}\n          data-name=\"dispute-row-details\"\n          className=\"mt-4 border-t border-slate-200/70 pt-4 sm:mt-5 sm:pt-5\"\n        >\n          <div className=\"flex flex-col gap-4 lg:flex-row lg:items-stretch lg:gap-6 xl:gap-8\">\n            <div id={`${rowId}-meta`} data-name=\"dispute-row-meta\" className=\"min-w-0 flex-1 space-y-3\">\n              {isDisputed && disputeSnippet ? (\n                <div\n                  id={`${rowId}-context`}\n                  data-name=\"dispute-row-context\"\n                  className=\"space-y-1.5 rounded-xl border border-amber-200/80 bg-white/60 px-3 py-2.5 sm:px-4 sm:py-3\"\n                >\n                  <p\n                    id={`${rowId}-tournament`}\n                    data-name=\"dispute-row-tournament\"\n                    className=\"text-xs font-medium text-slate-600 sm:text-sm\"\n                  >\n                    {match.tournamentName}\n                  </p>\n                  <p className=\"text-pretty text-xs leading-relaxed text-amber-950 sm:text-sm\">{disputeSnippet}</p>\n                </div>\n              ) : (\n                <p\n                  id={`${rowId}-tournament`}\n                  data-name=\"dispute-row-tournament\"\n                  className=\"text-xs font-medium text-slate-600 sm:text-sm\"\n                >\n                  {match.tournamentName}\n                </p>\n              )}\n\n              {match.admin_notes ? (\n                <p\n                  className=\"rounded-lg border border-slate-200/80 bg-white/50 px-3 py-2 text-xs leading-relaxed text-slate-600\"\n                  title={match.admin_notes}\n                >\n                  <span className=\"font-medium text-slate-700\">Nota:</span> {match.admin_notes}\n                </p>\n              ) : null}\n\n              {match.status === ''closed'' || match.status === ''validated'' ? (\n                <p className=\"text-xs text-slate-500\">\n                  Cerrado {shortDate(match.admin_validated_at ?? match.closed_at)}\n                </p>\n              ) : null}\n            </div>\n\n            <div\n              id={`${rowId}-score-actions`}\n              data-name=\"dispute-row-score-actions\"\n              className=\"flex min-w-0 flex-col gap-4 lg:w-[min(100%,22rem)] lg:shrink-0 lg:border-l lg:border-slate-200/70 lg:pl-6 xl:w-[min(100%,24rem)]\"\n            >\n              <div\n                id={`${rowId}-score`}\n                data-name=\"dispute-row-score\"\n                className=\"rounded-xl border border-slate-200/70 bg-white/70 px-4 py-3 sm:px-5 sm:py-3.5\"\n              >\n                <p className=\"text-[11px] font-semibold uppercase tracking-wide text-slate-500\">Marcador</p>\n                <p className=\"mt-1 font-mono text-xl font-bold tabular-nums leading-none tracking-tight text-slate-950 sm:text-2xl\">\n                  {formatScore(match)}\n                </p>\n                <p\n                  className=\"mt-2.5 space-y-1 text-xs leading-relaxed text-slate-700 sm:text-[13px]\"\n                  title={`Ganador: ${winnerLabel(match)} · Registró: ${match.scoreSubmittedByLabel ?? ''—''}`}\n                >\n                  <span className=\"block\">\n                    <span className=\"font-medium text-slate-600\">Ganador:</span>{'' ''}\n                    <span className=\"text-slate-950\">{winnerLabel(match)}</span>\n                  </span>\n                  <span className=\"block\">\n                    <span className=\"font-medium text-slate-600\">Registró:</span>{'' ''}\n                    <span className=\"text-slate-800\">{match.scoreSubmittedByLabel ?? ''—''}</span>\n                  </span>\n                </p>\n              </div>\n\n              <DisputeActionButtons\n                rowId={rowId}\n                match={match}\n                isDisputed={isDisputed}\n                canValidateLegacy={canValidateLegacy}\n                onValidateAsIs={onValidateAsIs}\n                onInvalidate={onInvalidate}\n                onCorrect={onCorrect}\n                onConfirm={onConfirm}\n              />\n            </div>\n          </div>\n        </div>\n      ) : null}\n    </article>\n  )\n}\n"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "            estimateRowHeight={112}", "old_string": "            estimateRowHeight={168}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminNotificationsPage.tsx"}}]}}'
