INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0033',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  33,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Cada fila de disputa ahora es colapsable. Por defecto arranca **cerrada** con un resumen compacto; al pulsar se expande con todo el detalle y las acciones.\n\n### Colapsado (resumen)\n- Grupo, estado y fecha\n- Jugadores (`A vs B`)\n- Una línea de contexto: motivo/refutación o torneo\n- Marcador compacto\n- Chevron indicador (`admin-notifications-dispute-{id}-toggle`)\n\n### Expandido (completo)\n- Bloque de disputa con torneo y motivo completo\n- Notas de admin (si hay)\n- Panel de marcador con ganador y quien registró\n- Botones: **Válido**, **Invalidar**, **Corregir**\n\n### Detalles técnicos\n- Toggle accesible: `aria-expanded`, `aria-controls`, `data-expanded=\"true|false\"`\n- IDs nuevos: `-toggle`, `-summary`, `-details`, `-chevron`, `-score-compact`\n- La lista virtual ajusta la altura al expandir (TanStack mide en runtime)\n- `estimateRowHeight` bajado a `112` para el estado colapsado por defecto\n\nHaz clic en cualquier fila (p. ej. `#admin-notifications-dispute-eb62cae2-79c8-406f-8161-24c04908eadd`) para alternar entre resumen y vista completa.\n\n[REDACTED]"}]}}'
);

