INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0048',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  48,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Cambios aplicados en **1. Filtros de exportación**:\n\n### Texto de ayuda → icono ℹ️\n- El párrafo largo se quitó del subtítulo.\n- Hay un botón de información (`#admin-export-filters-info`) junto al título.\n- **Hover:** tooltip nativo con el texto completo.\n- **Click/tap:** panel desplegable (útil en móvil) con el mismo contenido.\n\n### Categoría y grupo → default «Todos»\n- Opción por defecto renombrada a **«Todos»** (antes «Todas las categorías» / «Todos los grupos»).\n- Los selects muestran **«Todos»** al cargar y al cambiar de torneo.\n- El valor interno sigue siendo “sin filtro” (`null` en la exportación).\n\n### Responsivo\n- Filtros en **1 columna** en móvil, **2** en tablet, **3** en desktop.\n- Selects con `w-full` y `min-w-0` para evitar desbordes.\n- Grupo ocupa fila completa en tablet (`sm:col-span-2`) y vuelve a la tercera columna en `lg`.\n- Icono de info alineado arriba en móvil y centrado en pantallas más anchas.\n- Panel de ayuda con ancho máximo `min(100vw - 2rem, 20rem)`.\n\nRecarga `/admin/exports` para verlo.\n\n[REDACTED]"}]}}'
);

