INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0084',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  84,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "const PREVIEW_PAGE_SIZE = 25\n\nconst RANKING_PREVIEW_COLUMNS = [''id'', ''nombre'', ''grupo'', ''ranking'', ''puntos'', ''juegos''] as const\n\ntype RankingSortKey = ''id'' | ''nombre'' | ''grupo''\n\nconst RANKING_COLUMN_LABELS: Record<(typeof RANKING_PREVIEW_COLUMNS)[number], string> = {\n  id: ''ID'',\n  nombre: ''Nombre'',\n  grupo: ''Grupo'',\n  ranking: ''Ranking'',\n  puntos: ''Puntos'',\n  juegos: ''Juegos'',\n}\n\nfunction rankingSortValue(row: ExportablePlayerRankingRow, key: RankingSortKey): string {\n  return row[key] ?? ''''\n}\n\nfunction ExportCollapsiblePreviewShell({\n  id,\n  title,\n  summary,\n  expanded,\n  onToggle,\n  toolbar,\n  children,\n  footer,\n}: {\n  id: string\n  title: string\n  summary: string\n  expanded: boolean\n  onToggle: () => void\n  toolbar?: React.ReactNode\n  children: React.ReactNode\n  footer?: React.ReactNode\n}) {\n  return (\n    <section\n      id={id}\n      data-name=\"export-preview-panel\"\n      data-expanded={expanded ? ''true'' : ''false''}\n      className=\"overflow-hidden rounded-xl border border-slate-200/90 bg-white shadow-sm\"\n    >\n      <button\n        id={`${id}-toggle`}\n        type=\"button\"\n        aria-expanded={expanded}\n        aria-controls={`${id}-panel`}\n        onClick={onToggle}\n        className={cn(\n          ''flex w-full items-start gap-3 px-3 py-3 text-left outline-none transition-colors sm:items-center sm:px-4 sm:py-3.5'',\n          ''hover:bg-slate-50/90 focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25 focus-visible:ring-inset'',\n        )}\n      >\n        <span className=\"min-w-0 flex-1\">\n          <span className=\"block text-sm font-semibold text-slate-900\">{title}</span>\n          <span className=\"mt-0.5 block text-xs leading-relaxed text-slate-500\">{summary}</span>\n        </span>\n        <span\n          className=\"flex size-9 shrink-0 items-center justify-center rounded-lg border border-[#1F5A4C]/30 bg-[#1F5A4C]/5 text-[#1F5A4C]\"\n          aria-hidden\n        >\n          <ChevronDown className={cn(''size-4 transition-transform duration-200'', expanded && ''rotate-180'')} />\n        </span>\n      </button>\n\n      {expanded ? (\n        <div id={`${id}-panel`} className=\"border-t border-slate-100\">\n          {toolbar ? (\n            <div className=\"flex flex-col gap-2 border-b border-slate-100 bg-slate-50/60 px-3 py-2.5 sm:flex-row sm:flex-wrap sm:items-center sm:justify-between sm:px-4\">\n              {toolbar}\n            </div>\n          ) : null}\n          {children}\n          {footer ? <div className=\"border-t border-slate-100 bg-slate-50/40 px-3 py-2.5 sm:px-4\">{footer}</div> : null}\n        </div>\n      ) : null}\n    </section>\n  )\n}\n\nfunction ExportPreviewLoadMore({\n  visibleCount,\n  totalCount,\n  onLoadMore,\n}: {\n  visibleCount: number\n  totalCount: number\n  onLoadMore: () => void\n}) {\n  if (visibleCount >= totalCount) return null\n  const remaining = totalCount - visibleCount\n  return (\n    <button\n      type=\"button\"\n      onClick={onLoadMore}\n      className=\"mx-auto flex items-center gap-2 rounded-lg border border-slate-200 bg-white px-4 py-1.5 text-sm text-slate-600 shadow-sm hover:bg-slate-50\"\n    >\n      <ChevronDown className=\"size-4\" aria-hidden />\n      Ver {Math.min(PREVIEW_PAGE_SIZE, remaining).toLocaleString(''es-MX'')} más\n      <span className=\"text-xs text-slate-400\">({remaining.toLocaleString(''es-MX'')} restantes)</span>\n    </button>\n  )\n}\n\nfunction ExportRankingPreview({\n  rows,\n  resetKey,\n}: {\n  rows: ExportablePlayerRankingRow[]\n  resetKey: string\n}) {\n  const [expanded, setExpanded] = useState(true)\n  const [visibleCount, setVisibleCount] = useState(PREVIEW_PAGE_SIZE)\n  const [sort, setSort] = useState<{ key: RankingSortKey; direction: ''asc'' | ''desc'' }>({\n    key: ''nombre'',\n    direction: ''asc'',\n  })\n\n  useEffect(() => {\n    setExpanded(true)\n    setVisibleCount(PREVIEW_PAGE_SIZE)\n    setSort({ key: ''nombre'', direction: ''asc'' })\n  }, [resetKey])\n\n  const sortedRows = useMemo(() => {\n    const list = [...rows]\n    list.sort((a, b) => {\n      const av = rankingSortValue(a, sort.key)\n      const bv = rankingSortValue(b, sort.key)\n      const cmp = av.localeCompare(bv, ''es'', { numeric: true, sensitivity: ''base'' })\n      return sort.direction === ''asc'' ? cmp : -cmp\n    })\n    return list\n  }, [rows, sort])\n\n  const visibleRows = sortedRows.slice(0, visibleCount)\n\n  const sortToolbar = (\n    <div className=\"flex flex-wrap items-center gap-2\">\n      <span className=\"text-xs font-medium text-slate-600\">Ordenar por</span>\n      {([''id'', ''nombre'', ''grupo''] as const).map((key) => {\n        const active = sort.key === key\n        return (\n          <Button\n            key={key}\n            id={`admin-export-ranking-sort-${key}`}\n            type=\"button\"\n            size=\"sm\"\n            variant={active ? ''default'' : ''outline''}\n            className={cn(''h-8 text-xs capitalize'', active && ''bg-[#1F5A4C] hover:bg-[#1F5A4C]/90'')}\n            onClick={() =>\n              setSort((prev) =>\n                prev.key === key\n                  ? { key, direction: prev.direction === ''asc'' ? ''desc'' : ''asc'' }\n                  : { key, direction: ''asc'' },\n              )\n            }\n          >\n            {key === ''id'' ? ''ID'' : key === ''nombre'' ? ''Nombre'' : ''Grupo''}\n            {active ? (sort.direction === ''asc'' ? '' ↑'' : '' ↓'') : null}\n          </Button>\n        )\n      })}\n    </div>\n  )\n\n  return (\n    <ExportCollapsiblePreviewShell\n      id=\"admin-export-ranking-preview\"\n      title=\"Ranking de jugadores\"\n      summary={`${rows.length.toLocaleString(''es-MX'')} jugador(es) · mostrando ${Math.min(visibleCount, rows.length).toLocaleString(''es-MX'')} de ${rows.length.toLocaleString(''es-MX'')}`}\n      expanded={expanded}\n      onToggle={() => setExpanded((open) => !open)}\n      toolbar={sortToolbar}\n      footer={\n        <ExportPreviewLoadMore\n          visibleCount={visibleCount}\n          totalCount={sortedRows.length}\n          onLoadMore={() => setVisibleCount((n) => n + PREVIEW_PAGE_SIZE)}\n        />\n      }\n    >\n      <div className=\"max-h-[min(28rem,60vh)] overflow-auto\">\n        <Table>\n          <TableHeader className=\"sticky top-0 z-10 bg-slate-50/95 backdrop-blur-sm\">\n            <TableRow className=\"hover:bg-slate-50/95\">\n              {RANKING_PREVIEW_COLUMNS.map((c) => (\n                <TableHead\n                  key={c}\n                  className=\"whitespace-nowrap px-3 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-slate-600 sm:px-4\"\n                >\n                  {RANKING_COLUMN_LABELS[c]}\n                </TableHead>\n              ))}\n            </TableRow>\n          </TableHeader>\n          <TableBody>\n            {visibleRows.map((row, rowIndex) => (\n              <TableRow\n                key={`${row.id}-${row.grupo}-${rowIndex}`}\n                className={cn(''text-xs'', rowIndex % 2 === 1 && ''bg-slate-50/40'')}\n              >\n                {RANKING_PREVIEW_COLUMNS.map((c) => (\n                  <TableCell\n                    key={c}\n                    className={cn(\n                      ''px-3 py-2 sm:px-4'',\n                      c === ''id'' && ''font-mono tabular-nums text-slate-600'',\n                      c === ''nombre'' && ''min-w-[8rem] max-w-[14rem] font-medium text-slate-900'',\n                      c === ''grupo'' && ''max-w-[10rem] truncate text-slate-700'',\n                      (c === ''ranking'' || c === ''puntos'' || c === ''juegos'') && ''tabular-nums text-slate-800'',\n                    )}\n                    title={c === ''nombre'' || c === ''grupo'' ? row[c] : undefined}\n                  >\n                    {row[c] || ''—''}\n                  </TableCell>\n                ))}\n              </TableRow>\n            ))}\n          </TableBody>\n        </Table>\n      </div>\n    </ExportCollapsiblePreviewShell>\n  )\n}\n\ntype MatchPreviewRow = ReturnType<typeof matchToImportCompatibleRow>\n\nfunction formatMatchPreviewScore(row: MatchPreviewRow): string {\n  const sets: string[] = []\n  if (row.set_1_a || row.set_1_b) sets.push(`${row.set_1_a || ''0''}-${row.set_1_b || ''0''}`)\n  if (row.set_2_a || row.set_2_b) sets.push(`${row.set_2_a || ''0''}-${row.set_2_b || ''0''}`)\n  if (row.set_3_a || row.set_3_b) sets.push(`${row.set_3_a || ''0''}-${row.set_3_b || ''0''}`)\n  return sets.length ? sets.join('' · '') : ''—''\n}\n\nfunction ExportMatchResultsPreview({\n  rows,\n  resetKey,\n}: {\n  rows: MatchPreviewRow[]\n  resetKey: string\n}) {\n  const [expanded, setExpanded] = useState(true)\n  const [visibleCount, setVisibleCount] = useState(PREVIEW_PAGE_SIZE)\n\n  useEffect(() => {\n    setExpanded(true)\n    setVisibleCount(PREVIEW_PAGE_SIZE)\n  }, [resetKey])\n\n  const visibleRows = rows.slice(0, visibleCount)\n\n  if (!rows.length) {\n    return (\n      <p className=\"rounded-xl border border-dashed border-slate-200 bg-slate-50/70 px-4 py-6 text-center text-sm text-slate-500\">\n        No hay partidos para los filtros seleccionados.\n      </p>\n    )\n  }\n\n  return (\n    <ExportCollapsiblePreviewShell\n      id=\"admin-export-matches-preview\"\n      title=\"Partidos y resultados\"\n      summary={`${rows.length.toLocaleString(''es-MX'')} partido(s) · mostrando ${Math.min(visibleCount, rows.length).toLocaleString(''es-MX'')} de ${rows.length.toLocaleString(''es-MX'')}`}\n      expanded={expanded}\n      onToggle={() => setExpanded((open) => !open)}\n      footer={\n        <ExportPreviewLoadMore\n          visibleCount={visibleCount}\n          totalCount={rows.length}\n          onLoadMore={() => setVisibleCount((n) => n + PREVIEW_PAGE_SIZE)}\n        />\n      }\n    >\n      <div className=\"max-h-[min(28rem,60vh)] overflow-auto\">\n        <Table>\n          <TableHeader className=\"sticky top-0 z-10 bg-slate-50/95 backdrop-blur-sm\">\n            <TableRow className=\"hover:bg-slate-50/95\">\n              <TableHead className=\"whitespace-nowrap px-3 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-slate-600 sm:px-4\">\n                Grupo\n              </TableHead>\n              <TableHead className=\"min-w-[10rem] whitespace-nowrap px-3 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-slate-600 sm:px-4\">\n                Partido\n              </TableHead>\n              <TableHead className=\"whitespace-nowrap px-3 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-slate-600 sm:px-4\">\n                IDs\n              </TableHead>\n              <TableHead className=\"whitespace-nowrap px-3 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-slate-600 sm:px-4\">\n                Marcador\n              </TableHead>\n              <TableHead className=\"whitespace-nowrap px-3 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-slate-600 sm:px-4\">\n                Ganador\n              </TableHead>\n              <TableHead className=\"whitespace-nowrap px-3 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-slate-600 sm:px-4\">\n                Tipo\n              </TableHead>\n              <TableHead className=\"whitespace-nowrap px-3 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-slate-600 sm:px-4\">\n                Estado\n              </TableHead>\n            </TableRow>\n          </TableHeader>\n          <TableBody>\n            {visibleRows.map((row, rowIndex) => (\n              <TableRow\n                key={`${row.group_name}-${row.player_a_id}-${row.player_b_id}-${rowIndex}`}\n                className={cn(''text-xs'', rowIndex % 2 === 1 && ''bg-slate-50/40'')}\n              >\n                <TableCell className=\"max-w-[9rem] truncate px-3 py-2 font-medium text-slate-700 sm:px-4\" title={row.group_name}>\n                  {row.group_name || ''—''}\n                </TableCell>\n                <TableCell className=\"min-w-[10rem] max-w-[14rem] px-3 py-2 sm:px-4\">\n                  <p className=\"truncate font-medium text-slate-900\" title={`${row.player_a_name} vs ${row.player_b_name}`}>\n                    {row.player_a_name} <span className=\"font-normal text-slate-400\">vs</span> {row.player_b_name}\n                  </p>\n                </TableCell>\n                <TableCell className=\"px-3 py-2 font-mono text-[11px] leading-snug text-slate-600 sm:px-4\">\n                  <span className=\"block truncate\" title={row.player_a_id}>\n                    A: {row.player_a_id || ''—''}\n                  </span>\n                  <span className=\"block truncate\" title={row.player_b_id}>\n                    B: {row.player_b_id || ''—''}\n                  </span>\n                </TableCell>\n                <TableCell className=\"whitespace-nowrap px-3 py-2 font-mono tabular-nums text-slate-900 sm:px-4\">\n                  {formatMatchPreviewScore(row)}\n                </TableCell>\n                <TableCell className=\"max-w-[8rem] truncate px-3 py-2 font-mono text-[11px] text-slate-700 sm:px-4\" title={row.winner_id}>\n                  {row.winner_id || ''—''}\n                </TableCell>\n                <TableCell className=\"whitespace-nowrap px-3 py-2 text-slate-700 sm:px-4\">{row.result_type || ''—''}</TableCell>\n                <TableCell className=\"whitespace-nowrap px-3 py-2 sm:px-4\">\n                  <Badge variant=\"secondary\" className=\"h-5 px-1.5 text-[10px] font-medium\">\n                    {row.status || ''—''}\n                  </Badge>\n                </TableCell>\n              </TableRow>\n            ))}\n          </TableBody>\n        </Table>\n      </div>\n    </ExportCollapsiblePreviewShell>\n  )\n}\n", "old_string": "const PREVIEW_COLUMNS = [\n  ''id'',\n  ''nombre'',\n  ''torneo'',\n  ''categoria'',\n  ''grupo'',\n  ''contraseña'',\n  ''ranking'',\n  ''puntos'',\n  ''juegos'',\n] as const\n\nconst MATCH_RESULTS_PREVIEW_COLUMNS: MatchResultsImportHeader[] = [\n  ''tournament_name'',\n  ''category_name'',\n  ''group_name'',\n  ''player_a_id'',\n  ''player_a_name'',\n  ''player_b_id'',\n  ''player_b_name'',\n  ''set_1_a'',\n  ''set_1_b'',\n  ''set_2_a'',\n  ''set_2_b'',\n  ''winner_id'',\n  ''result_type'',\n  ''status'',\n]\n\nconst PREVIEW_CHUNK_SIZE = 25\nconst MATCH_RESULTS_PREVIEW_LIMIT = 12\n\nfunction chunkPreviewRows(rows: ExportablePlayerRankingRow[], size: number): ExportablePlayerRankingRow[][] {\n  const chunks: ExportablePlayerRankingRow[][] = []\n  for (let i = 0; i < rows.length; i += size) {\n    chunks.push(rows.slice(i, i + size))\n  }\n  return chunks\n}\n\nfunction ExportPreviewChunkList({\n  rows,\n  columns,\n  resetKey,\n}: {\n  rows: ExportablePlayerRankingRow[]\n  columns: readonly (typeof PREVIEW_COLUMNS)[number][]\n  resetKey: string\n}) {\n  const chunks = useMemo(() => chunkPreviewRows(rows, PREVIEW_CHUNK_SIZE), [rows])\n  const defaultExpanded = useMemo(\n    () => new Set<number>(chunks.length === 1 ? [0] : []),\n    [chunks.length, resetKey],\n  )\n  const [expandedChunks, setExpandedChunks] = useState<Set<number>>(defaultExpanded)\n\n  useEffect(() => {\n    setExpandedChunks(defaultExpanded)\n  }, [defaultExpanded])\n\n  const allExpanded = chunks.length > 0 && expandedChunks.size === chunks.length\n  const toggleChunk = (index: number) => {\n    setExpandedChunks((prev) => {\n      const next = new Set(prev)\n      if (next.has(index)) next.delete(index)\n      else next.add(index)\n      return next\n    })\n  }\n\n  return (\n    <div id=\"admin-export-preview-list\" data-name=\"export-preview-list\" className=\"space-y-3\">\n      {chunks.length > 1 ? (\n        <div className=\"flex flex-wrap items-center justify-end gap-2\">\n          <Button\n            id=\"admin-export-preview-expand-all\"\n            type=\"button\"\n            variant=\"outline\"\n            size=\"sm\"\n            className=\"h-8\"\n            onClick={() => setExpandedChunks(new Set(chunks.map((_, i) => i)))}\n            disabled={allExpanded}\n          >\n            Expandir todo\n          </Button>\n          <Button\n            id=\"admin-export-preview-collapse-all\"\n            type=\"button\"\n            variant=\"outline\"\n            size=\"sm\"\n            className=\"h-8\"\n            onClick={() => setExpandedChunks(new Set())}\n            disabled={expandedChunks.size === 0}\n          >\n            Contraer todo\n          </Button>\n        </div>\n      ) : null}\n\n      {chunks.map((chunk, chunkIndex) => {\n        const expanded = expandedChunks.has(chunkIndex)\n        const start = chunkIndex * PREVIEW_CHUNK_SIZE + 1\n        const end = start + chunk.length - 1\n        const chunkId = `admin-export-preview-chunk-${chunkIndex}`\n\n        return (\n          <section\n            key={chunkId}\n            id={chunkId}\n            data-name=\"export-preview-chunk\"\n            data-expanded={expanded ? ''true'' : ''false''}\n            className=\"overflow-hidden rounded-xl border border-slate-200/90 bg-white shadow-sm\"\n          >\n            <button\n              id={`${chunkId}-toggle`}\n              type=\"button\"\n              aria-expanded={expanded}\n              aria-controls={`${chunkId}-panel`}\n              onClick={() => toggleChunk(chunkIndex)}\n              className={cn(\n                ''flex w-full items-center gap-3 px-3 py-3 text-left outline-none transition-colors sm:px-4 sm:py-3.5'',\n                ''hover:bg-slate-50/90 focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25 focus-visible:ring-inset'',\n              )}\n            >\n              <span className=\"min-w-0 flex-1\">\n                <span className=\"block text-sm font-semibold text-slate-900\">\n                  Jugadores {start.toLocaleString(''es-MX'')}–{end.toLocaleString(''es-MX'')}\n                </span>\n                <span className=\"mt-0.5 block text-xs text-slate-500\">\n                  {chunk.length.toLocaleString(''es-MX'')} fila{chunk.length === 1 ? '''' : ''s''} en este bloque\n                </span>\n              </span>\n              <span\n                className={cn(\n                  ''flex size-8 shrink-0 items-center justify-center rounded-lg border border-[#1F5A4C]/30 bg-[#1F5A4C]/5 text-[#1F5A4C] sm:size-9'',\n                )}\n                aria-hidden\n              >\n                <ChevronDown className={cn(''size-4 transition-transform duration-200'', expanded && ''rotate-180'')} />\n              </span>\n            </button>\n\n            {expanded ? (\n              <div id={`${chunkId}-panel`} className=\"border-t border-slate-100\">\n                <div className=\"overflow-x-auto\">\n                  <Table>\n                    <TableHeader>\n                      <TableRow className=\"bg-slate-50/90\">\n                        {columns.map((c) => (\n                          <TableHead\n                            key={c}\n                            className=\"whitespace-nowrap px-3 text-xs font-semibold uppercase tracking-wide sm:px-4\"\n                          >\n                            {c.replace(/_/g, '' '')}\n                          </TableHead>\n                        ))}\n                      </TableRow>\n                    </TableHeader>\n                    <TableBody>\n                      {chunk.map((r, rowIndex) => (\n                        <TableRow key={`${r.id}-${r.grupo}-${chunkIndex}-${rowIndex}`} className=\"text-xs\">\n                          {columns.map((c) => (\n                            <TableCell key={c} className=\"max-w-[12rem] truncate px-3 sm:max-w-[14rem] sm:px-4\">\n                              {r[c]}\n                            </TableCell>\n                          ))}\n                        </TableRow>\n                      ))}\n                    </TableBody>\n                  </Table>\n                </div>\n              </div>\n            ) : null}\n          </section>\n        )\n      })}\n    </div>\n  )\n}\n\nfunction MatchResultsPreviewTable({\n  rows,\n}: {\n  rows: ReturnType<typeof matchToImportCompatibleRow>[]\n}) {\n  const previewRows = rows.slice(0, MATCH_RESULTS_PREVIEW_LIMIT)\n\n  if (!rows.length) {\n    return (\n      <p className=\"rounded-xl border border-dashed border-slate-200 bg-slate-50/70 px-4 py-6 text-center text-sm text-slate-500\">\n        No hay partidos para los filtros seleccionados.\n      </p>\n    )\n  }\n\n  return (\n    <div className=\"overflow-hidden rounded-xl border border-slate-200/90 bg-white shadow-sm\">\n      <div className=\"flex flex-wrap items-center justify-between gap-2 border-b border-slate-100 bg-slate-50/80 px-3 py-2.5\">\n        <p className=\"text-sm font-semibold text-slate-900\">\n          Primeras {previewRows.length.toLocaleString(''es-MX'')} filas de partidos/resultados\n        </p>\n        <span className=\"text-xs font-medium tabular-nums text-slate-500\">\n          {rows.length.toLocaleString(''es-MX'')} fila{rows.length === 1 ? '''' : ''s''} en el CSV\n        </span>\n      </div>\n      <div className=\"overflow-x-auto\">\n        <Table>\n          <TableHeader>\n            <TableRow className=\"bg-white\">\n              {MATCH_RESULTS_PREVIEW_COLUMNS.map((c) => (\n                <TableHead key={c} className=\"whitespace-nowrap px-3 text-xs font-semibold uppercase tracking-wide\">\n                  {c.replace(/_/g, '' '')}\n                </TableHead>\n              ))}\n            </TableRow>\n          </TableHeader>\n          <TableBody>\n            {previewRows.map((row, rowIndex) => (\n              <TableRow key={`${row.group_name}-${row.player_a_id}-${row.player_b_id}-${rowIndex}`} className=\"text-xs\">\n                {MATCH_RESULTS_PREVIEW_COLUMNS.map((c) => (\n                  <TableCell key={c} className=\"max-w-[13rem] truncate px-3\">\n                    {row[c] || ''—''}\n                  </TableCell>\n                ))}\n              </TableRow>\n            ))}\n          </TableBody>\n        </Table>\n      </div>\n    </div>\n  )\n}\n", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminExportsPage.tsx"}}]}}'
);

