INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0093',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  93,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "}\n\nexport function AdminExportsPage() {", "old_string": "}\n\n/* PLACEHOLDER_REMOVE_OLD_PREVIEW */\n  const chunks: ExportablePlayerRankingRow[][] = []\n  for (let i = 0; i < rows.length; i += size) {\n    chunks.push(rows.slice(i, i + size))\n  }\n  return chunks\n}\n\nfunction ExportPreviewChunkList({\n  rows,\n  columns,\n}: {\n  rows: ExportablePlayerRankingRow[]\n  columns: readonly (typeof PREVIEW_COLUMNS)[number][]\n}) {\n  const chunks = useMemo(() => chunkPreviewRows(rows, PREVIEW_CHUNK_SIZE), [rows])\n  const defaultExpanded = useMemo(\n    () => new Set<number>(chunks.length === 1 ? [0] : []),\n    [chunks.length],\n  )\n  const [expandedChunks, setExpandedChunks] = useState<Set<number>>(defaultExpanded)\n\n  const allExpanded = chunks.length > 0 && expandedChunks.size === chunks.length\n  const toggleChunk = (index: number) => {\n    setExpandedChunks((prev) => {\n      const next = new Set(prev)\n      if (next.has(index)) next.delete(index)\n      else next.add(index)\n      return next\n    })\n  }\n\n  return (\n    <div id=\"admin-export-preview-list\" data-name=\"export-preview-list\" className=\"space-y-3\">\n      {chunks.length > 1 ? (\n        <div className=\"flex flex-wrap items-center justify-end gap-2\">\n          <Button\n            id=\"admin-export-preview-expand-all\"\n            type=\"button\"\n            variant=\"outline\"\n            size=\"sm\"\n            className=\"h-8\"\n            onClick={() => setExpandedChunks(new Set(chunks.map((_, i) => i)))}\n            disabled={allExpanded}\n          >\n            Expandir todo\n          </Button>\n          <Button\n            id=\"admin-export-preview-collapse-all\"\n            type=\"button\"\n            variant=\"outline\"\n            size=\"sm\"\n            className=\"h-8\"\n            onClick={() => setExpandedChunks(new Set())}\n            disabled={expandedChunks.size === 0}\n          >\n            Contraer todo\n          </Button>\n        </div>\n      ) : null}\n\n      {chunks.map((chunk, chunkIndex) => {\n        const expanded = expandedChunks.has(chunkIndex)\n        const start = chunkIndex * PREVIEW_CHUNK_SIZE + 1\n        const end = start + chunk.length - 1\n        const chunkId = `admin-export-preview-chunk-${chunkIndex}`\n\n        return (\n          <section\n            key={chunkId}\n            id={chunkId}\n            data-name=\"export-preview-chunk\"\n            data-expanded={expanded ? ''true'' : ''false''}\n            className=\"overflow-hidden rounded-xl border border-slate-200/90 bg-white shadow-sm\"\n          >\n            <button\n              id={`${chunkId}-toggle`}\n              type=\"button\"\n              aria-expanded={expanded}\n              aria-controls={`${chunkId}-panel`}\n              onClick={() => toggleChunk(chunkIndex)}\n              className={cn(\n                ''flex w-full items-center gap-3 px-3 py-3 text-left outline-none transition-colors sm:px-4 sm:py-3.5'',\n                ''hover:bg-slate-50/90 focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25 focus-visible:ring-inset'',\n              )}\n            >\n              <span className=\"min-w-0 flex-1\">\n                <span className=\"block text-sm font-semibold text-slate-900\">\n                  Jugadores {start.toLocaleString(''es-MX'')}–{end.toLocaleString(''es-MX'')}\n                </span>\n                <span className=\"mt-0.5 block text-xs text-slate-500\">\n                  {chunk.length.toLocaleString(''es-MX'')} fila{chunk.length === 1 ? '''' : ''s''} en este bloque\n                </span>\n              </span>\n              <span\n                className={cn(\n                  ''flex size-8 shrink-0 items-center justify-center rounded-lg border border-[#1F5A4C]/30 bg-[#1F5A4C]/5 text-[#1F5A4C] sm:size-9'',\n                )}\n                aria-hidden\n              >\n                <ChevronDown className={cn(''size-4 transition-transform duration-200'', expanded && ''rotate-180'')} />\n              </span>\n            </button>\n\n            {expanded ? (\n              <div id={`${chunkId}-panel`} className=\"border-t border-slate-100\">\n                <div className=\"overflow-x-auto\">\n                  <Table>\n                    <TableHeader>\n                      <TableRow className=\"bg-slate-50/90\">\n                        {columns.map((c) => (\n                          <TableHead\n                            key={c}\n                            className=\"whitespace-nowrap px-3 text-xs font-semibold uppercase tracking-wide sm:px-4\"\n                          >\n                            {c.replace(/_/g, '' '')}\n                          </TableHead>\n                        ))}\n                      </TableRow>\n                    </TableHeader>\n                    <TableBody>\n                      {chunk.map((r, rowIndex) => (\n                        <TableRow key={`${r.id}-${r.grupo}-${chunkIndex}-${rowIndex}`} className=\"text-xs\">\n                          {columns.map((c) => (\n                            <TableCell key={c} className=\"max-w-[12rem] truncate px-3 sm:max-w-[14rem] sm:px-4\">\n                              {r[c]}\n                            </TableCell>\n                          ))}\n                        </TableRow>\n                      ))}\n                    </TableBody>\n                  </Table>\n                </div>\n              </div>\n            ) : null}\n          </section>\n        )\n      })}\n    </div>\n  )\n}\n\nfunction MatchResultsPreviewTable({\n  rows,\n}: {\n  rows: ReturnType<typeof matchToImportCompatibleRow>[]\n}) {\n  const previewRows = rows.slice(0, MATCH_RESULTS_PREVIEW_LIMIT)\n\n  if (!rows.length) {\n    return (\n      <p className=\"rounded-xl border border-dashed border-slate-200 bg-slate-50/70 px-4 py-6 text-center text-sm text-slate-500\">\n        No hay partidos para los filtros seleccionados.\n      </p>\n    )\n  }\n\n  return (\n    <div className=\"overflow-hidden rounded-xl border border-slate-200/90 bg-white shadow-sm\">\n      <div className=\"flex flex-wrap items-center justify-between gap-2 border-b border-slate-100 bg-slate-50/80 px-3 py-2.5\">\n        <p className=\"text-sm font-semibold text-slate-900\">\n          Primeras {previewRows.length.toLocaleString(''es-MX'')} filas de partidos/resultados\n        </p>\n        <span className=\"text-xs font-medium tabular-nums text-slate-500\">\n          {rows.length.toLocaleString(''es-MX'')} fila{rows.length === 1 ? '''' : ''s''} en el CSV\n        </span>\n      </div>\n      <div className=\"overflow-x-auto\">\n        <Table>\n          <TableHeader>\n            <TableRow className=\"bg-white\">\n              {MATCH_RESULTS_PREVIEW_COLUMNS.map((c) => (\n                <TableHead key={c} className=\"whitespace-nowrap px-3 text-xs font-semibold uppercase tracking-wide\">\n                  {c.replace(/_/g, '' '')}\n                </TableHead>\n              ))}\n            </TableRow>\n          </TableHeader>\n          <TableBody>\n            {previewRows.map((row, rowIndex) => (\n              <TableRow key={`${row.group_name}-${row.player_a_id}-${row.player_b_id}-${rowIndex}`} className=\"text-xs\">\n                {MATCH_RESULTS_PREVIEW_COLUMNS.map((c) => (\n                  <TableCell key={c} className=\"max-w-[13rem] truncate px-3\">\n                    {row[c] || ''—''}\n                  </TableCell>\n                ))}\n              </TableRow>\n            ))}\n          </TableBody>\n        </Table>\n      </div>\n    </div>\n  )\n}\n\nexport function AdminExportsPage() {", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminExportsPage.tsx"}}]}}'
