on useAdminDisputeInboxCount() {\n  const resultsQ = useQuery({\n    queryKey: [''admin-disputed-results''],\n    queryFn: getAdminDisputedResults,\n    refetchInterval: 15_000,\n    refetchOnWindowFocus: true,\n  })\n\n  const count = resultsQ.data?.length ?? 0", "old_string": "import { tabFilterRows } from ''@/components/admin/results/adminResultsReviewUtils''\nimport { getAdminResults } from ''@/services/admin''\n\n/** Partidos en `score_disputed` — misma bandeja que `/admin/notifications`. */\nexport function useAdminDisputeInboxCount() {\n  const resultsQ = useQuery({\n    queryKey: [''admin-results''],\n    queryFn: getAdminResults,\n    refetchInterval: 15_000,\n    refetchOnWindowFocus: true,\n  })\n\n  const count = useMemo(() => {\n    if (!resultsQ.data) return 0\n    return tabFilterRows(resultsQ.data, ''disputed'').length\n  }, [resultsQ.data])", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\useAdminDisputeInboxCount.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import { useQuery } from ''@tanstack/react-query''", "old_string": "import { useMemo } from ''react''\nimport { useQuery } from ''@tanstack/react-query''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\useAdminDisputeInboxCount.ts"}}]}}'
);

