  149,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Restringiendo las acciones admin en partidos refutados: solo validar o corregir el marcador.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "old_string": "import { Ban, CheckCircle2, ChevronDown, Pencil } from ''lucide-react''", "new_string": "import { CheckCircle2, ChevronDown, Pencil } from ''lucide-react''"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "old_string": "function DisputeActionButtons({\n  rowId,\n  match,\n  isDisputed,\n  canValidateLegacy,\n  onValidateAsIs,\n  onInvalidate,\n  onCorrect,\n  onConfirm,\n}: {\n  rowId: string\n  match: AdminMatchRecord\n  isDisputed: boolean\n  canValidateLegacy: boolean\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  onInvalidate?: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onConfirm: (match: AdminMatchRecord) => void\n}) {\n  return (\n    <div\n      id={`${rowId}-actions`}\n      data-name=\"dispute-row-actions\"\n      className=\"grid grid-cols-2 gap-2 sm:flex sm:flex-wrap sm:justify-end lg:grid-cols-1 xl:grid-cols-2\"\n    >\n      {isDisputed ? (\n        <>\n          <Button\n            id={`${rowId}-btn-validate`}\n            name={`validate-dispute-${match.id}`}\n            data-name=\"dispute-action-validate\"\n            size=\"sm\"\n            title=\"Marcar como válido (sin cambiar marcador)\"\n            className=\"col-span-2 h-10 border-transparent bg-emerald-600 text-white hover:bg-emerald-700 sm:col-span-1 sm:h-9 lg:col-span-1 xl:col-span-2\"\n            onClick={() => onValidateAsIs?.(match)}\n            disabled={!onValidateAsIs}\n          >\n            <CheckCircle2 className=\"size-3.5 opacity-90\" />\n            Válido\n          </Button>\n          <Button\n            id={`${rowId}-btn-invalidate`}\n            name={`invalidate-dispute-${match.id}`}\n            data-name=\"dispute-action-invalidate\"\n            size=\"sm\"\n            variant=\"destructive\"\n            title=\"Invalidar partido (cancelado, fuera del ranking)\"\n            className=\"h-10 sm:h-9\"\n            onClick={() => onInvalidate?.(match)}\n            disabled={!onInvalidate}\n          >\n            <Ban className=\"size-3.5 opacity-90\" />\n            Invalidar\n          </Button>\n          <Button\n            id={`${rowId}-btn-correct`}\n            name={`correct-dispute-${match.id}`}\n            data-name=\"dispute-action-correct\"\n            size=\"sm\"\n            variant=\"outline\"\n            title=\"Corregir marcador\"\n            className=\"h-10 border-slate-300 bg-white sm:h-9\"\n            onClick={() => onCorrect(match)}\n          >\n            <Pencil className=\"size-3.5 opacity-80\" />\n            Corregir\n          </Button>\n        </>\n      ) : (", "new_string": "function DisputeActionButtons({\n  rowId,\n  match,\n  isDisputed,\n  canValidateLegacy,\n  onValidateAsIs,\n  onCorrect,\n  onConfirm,\n}: {\n  rowId: string\n  match: AdminMatchRecord\n  isDisputed: boolean\n  canValidateLegacy: boolean\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onConfirm: (match: AdminMatchRecord) => void\n}) {\n  return (\n    <div\n      id={`${rowId}-actions`}\n      data-name=\"dispute-row-actions\"\n      className=\"grid grid-cols-2 gap-2 sm:flex sm:flex-wrap sm:justify-end lg:grid-cols-1 xl:grid-cols-2\"\n    >\n      {isDisputed ? (\n        <>\n          <Button\n            id={`${rowId}-btn-validate`}\n            name={`validate-dispute-${match.id}`}\n            data-name=\"dispute-action-validate\"\n            size=\"sm\"\n            title=\"Validar el marcador registrado sin cambios\"\n            className=\"col-span-2 h-10 border-transparent bg-emerald-600 text-white hover:bg-emerald-700 sm:col-span-1 sm:h-9 lg:col-span-1 xl:col-span-2\"\n            onClick={() => onValidateAsIs?.(match)}\n            disabled={!onValidateAsIs}\n          >\n            <CheckCircle2 className=\"size-3.5 opacity-90\" />\n            Validar\n          </Button>\n          <Button\n            id={`${rowId}-btn-correct`}\n            name={`correct-dispute-${match.id}`}\n            data-name=\"dispute-action-correct\"\n            size=\"sm\"\n            variant=\"outline\"\n            title=\"Corregir marcador y validar\"\n            className=\"col-span-2 h-10 border-slate-300 bg-white sm:col-span-1 sm:h-9 lg:col-span-1 xl:col-span-2\"\n            onClick={() => onCorrect(match)}\n          >\n            <Pencil className=\"size-3.5 opacity-80\" />\n            Corregir marcador\n          </Button>\n        </>\n      ) : ("}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "old_string": "  onConfirm,\n  onCorrect,\n  onValidateAsIs,\n  onInvalidate,\n}: {\n  match: AdminMatchRecord\n  quickReview: boolean\n  onConfirm: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  onInvalidate?: (match: AdminMatchRecord) => void\n}) {", "new_string": "  onConfirm,\n  onCorrect,\n  onValidateAsIs,\n}: {\n  match: AdminMatchRecord\n  quickReview: boolean\n  onConfirm: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n}) {"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "old_string": "              onValidateAsIs={onValidateAsIs}\n              onInvalidate={onInvalidate}\n              onCorrect={onCorrect}\n              onConfirm={onConfirm}\n            />\n          </div>\n        </div>\n      </article>\n    )\n  }", "new_string": "              onValidateAsIs={onValidateAsIs}\n              onCorrect={onCorrect}\n              onConfirm={onConfirm}\n            />\n          </div>\n        </div>\n      </article>\n    )\n  }"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "old_string": "                onValidateAsIs={onValidateAsIs}\n                onInvalidate={onInvalidate}\n                onCorrect={onCorrect}\n                onConfirm={onConfirm}\n              />", "new_string": "                onValidateAsIs={onValidateAsIs}\n                onCorrect={onCorrect}\n                onConfirm={onConfirm}\n              />"}}]}}'
