 !showRegister(match) && match.status !== ''score_disputed'' ? (\n                              <DropdownMenuItem\n                                className=\"cursor-pointer gap-2\"\n                                onClick={() => onEditResult(match)}\n                              >\n                                <Pencil className=\"size-3.5 opacity-80\" />\n                                Corregir marcador\n                              </DropdownMenuItem>\n                            ) : null}", "old_string": "                            {canAdminEditMatch(match) && onEditResult && !showRegister(match) ? (\n                              <DropdownMenuItem\n                                className=\"cursor-pointer gap-2\"\n                                onClick={() => onEditResult(match)}\n                              >\n                                <Pencil className=\"size-3.5 opacity-80\" />\n                                Corregir marcador\n                              </DropdownMenuItem>\n                            ) : null}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\matches\\AdminMatchTable.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "                            {match.status === ''score_disputed'' && onEditResult ? (\n                              <DropdownMenuItem\n                                className=\"cursor-pointer gap-2 font-medium text-amber-950\"\n                                onClick={() => onEditResult(match)}\n                              >\n                                <Pencil className=\"size-3.5 opacity-80\" />\n                                Corregir marcador\n                              </DropdownMenuItem>\n                            ) : null}", "old_string": "                            {match.status === ''score_disputed'' && onEditResult ? (\n                              <DropdownMenuItem\n                                className=\"cursor-pointer gap-2 font-medium text-amber-950\"\n                                onClick={() => onEditResult(match)}\n                              >\n                                <Pencil className=\"size-3.5 opacity-80\" />\n                                Resolver refutación…\n                              </DropdownMenuItem>\n                            ) : null}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\matches\\AdminMatchTable.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "                    {canAdminEditMatch(match) && onEditResult && !showRegister(match) && match.status !== ''score_disputed'' ? (\n                      <DropdownMenuItem className=\"cursor-pointer gap-2\" onClick={() => onEditResult(match)}>\n                        <Pencil className=\"size-3.5\" />\n                        Corregir\n                      </DropdownMenuItem>\n                    ) : null}", "old_string": "                    {canAdminEditMatch(match) && onEditResult && !showRegister(match) ? (\n                      <DropdownMenuItem className=\"cursor-pointer gap-2\" onClick={() => onEditResult(match)}>\n                        <Pencil className=\"size-3.5\" />\n                        Corregir\n                      </DropdownMenuItem>\n                    ) : null}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\matches\\AdminMatchTable.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "                    {match.status === ''score_disputed'' && onEditResult ? (\n                      <DropdownMenuItem className=\"cursor-pointer gap-2\" onClick={() => onEditResult(match)}>\n                        <Pencil className=\"size-3.5\" />\n                        Corregir marcador\n                      </DropdownMenuItem>\n                    ) : null}", "old_string": "                    {match.status === ''score_disputed'' && onEditResult ? (\n                      <DropdownMenuI