INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0151',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  151,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Read", "input": {"limit": 80, "offset": 165, "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminMatchesPage.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  const [sets, setSets] = useState<ScoreSet[]>([{ a: 0, b: 0 }])\n  const [adminNote, setAdminNote] = useState('''')\n\n  useEffect(() => {\n    if (!open || !match) return\n    setSets(match.score_raw?.length ? match.score_raw.map((s) => ({ a: s.a, b: s.b })) : [{ a: 0, b: 0 }])\n    setAdminNote(match.admin_notes ?? '''')\n  }, [match, open])", "old_string": "  const [sets, setSets] = useState<ScoreSet[]>([{ a: 0, b: 0 }])\n  const [adminNote, setAdminNote] = useState('''')\n  /** Solo disputa: si está activo, «Confirmar resultado» pasa a validado; si no, sigue en revisión. */\n  const [applyValidateFromDispute, setApplyValidateFromDispute] = useState(true)\n\n  useEffect(() => {\n    if (!open || !match) return\n    setSets(match.score_raw?.length ? match.score_raw.map((s) => ({ a: s.a, b: s.b })) : [{ a: 0, b: 0 }])\n    setAdminNote(match.admin_notes ?? '''')\n    setApplyValidateFromDispute(true)\n  }, [match, open])", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminScoreCorrectionModal.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  const disputed = match.status === ''score_disputed''\n\n  const submit = (closeAfter: boolean) => {\n    const validation = validateScoreWithRules(sets, effectiveRules)\n    if (!validation.ok) {\n      toast.error(validation.errors[0] ?? ''Marcador inválido'')\n      return\n    }\n    if (disputed && !closeAfter) return\n    onSubmit({ match, sets, closeAfter: disputed ? true : closeAfter, adminNote })\n  }", "old_string": "  const disputed = match.status === ''score_disputed''\n\n  const submit = (closeAfter: boolean) => {\n    const validation = validateScoreWithRules(sets, effectiveRules)\n    if (!validation.ok) {\n      toast.error(validation.errors[0] ?? ''Marcador inválido'')\n      return\n    }\n    const effectiveCloseAfter = disputed ? closeAfter && applyValidateFromDispute : closeAfter\n    onSubmit({ match, sets, closeAfter: effectiveCloseAfter, adminNote })\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminScoreCorrectionModal.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "        {disputed ? (\n          <p className=\"rounded-xl border border-amber-200/90 bg-amber-50/90 p-3 text-sm leading-relaxed text-amber-950\">\n            Corrige el marcador si hace falta y confirma para validarlo oficialmente y cerrar la disputa.\n          </p>\n        ) : (\n          <p className=\"rounded-xl border border-slate-200 bg-slate-50 p-3 text-sm leading-relaxed text-slate-700\">\n            Guarda una corrección para dejarla pendiente de cierre, o confirma el resultado para hacerlo oficial y\n            enviarlo al ranking.\n          </p>\n        )}\n        <div id={`${elementIdPrefix}-actions`} data-name=\"score-correction-actions\" className=\"flex flex-col-reverse gap-2 sm:flex-row sm:justify-end\">\n          <Button\n            type=\"button\"\n            id={`${elementIdPrefix}-cancel`}\n            name=\"cancel-score-correction\"\n            data-name=\"score-correction-cancel\"\n            variant=\"outline\"\n            onClick={() => onOpenChange(false)}\n          >\n            Cancelar\n          </Button>\n          {!disputed ? (\n            <Button\n              type=\"button\"\n              id={`${elementIdPrefix}-save-draft`}\n              name=\"save-score-correction\"\n              data-name=\"score-correction-save-draft\"\n              variant=\"outline\"\n              onClick={() => submit(false)}\n            >\n              Guardar corrección\n            </Button>\n          ) : null}\n          <Button\n            type=\"button\"\n            id={`${elementIdPrefix}-confirm`}\n            name=\"confirm-score-correction\"\n            data-name=\"score-correction-confirm\"\n            onClick={() => submit(true)}\n          >\n            {disputed ? ''Validar marcador corregido'' : ''Confirmar resultado''}\n          </Button>\n        </div>", "old_string": "        {disputed ? (\n          <div\n            id={`${elementIdPrefix}-validate-option`}\n            data-name=\"score-correction-validate-option\"\n            className=\"space-y-2 rounded-xl border border-amber-200/90 bg-amber-50/90 p-3\"\n          >\n            <label className=\"flex cursor-pointer items-start gap-2.5 text-sm leading-snug text-amber-950\">\n              <input\n                id={`${elementIdPrefix}-validate-checkbox`}\n                name=\"apply-validate-from-dispute\"\n                data-name=\"score-correction-apply-validate\"\n                type=\"checkbox\"\n                className=\"mt-0.5 size-4 shrink-0 rounded border-amber-400 text-[#1F5A4C] focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/30\"\n                checked={applyValidateFromDispute}\n                onChange={(e) => setApplyValidateFromDispute(e.target.checked)}\n              />\n              <span>\n                <span className=\"font-semibold\">Aplicar y validar oficialmente</span>\n                <span className=\"mt-0.5 block text-xs font-normal text-amber-900/90\">\n                  Si está marcado, «Confirmar resultado» cierra la revisión y el marcador queda validado para el ranking.\n                  Desmárcalo para guardar cambios y seguir en «pendiente de revisión».\n                </span>\n              </span>\n            </label>\n          </div>\n        ) : null}\n        <p className=\"rounded-xl border border-slate-200 bg-slate-50 p-3 text-sm leading-relaxed text-slate-700\">\n          {disputed ? (\n            <>\n              «Guardar corrección» actualiza el marcador pero puede dejar el partido en revisión según la casilla de\n              validación. «Confirmar resultado» valida y envía al ranking solo si «Aplicar y validar oficialmente» está\n              activo.\n            </>\n          ) : (\n            <>\n              Guarda una corrección para dejarla pendiente de cierre, o confirma el resultado para hacerlo oficial y\n              enviarlo al ranking.\n            </>\n          )}\n        </p>\n        <div id={`${elementIdPrefix}-actions`} data-name=\"score-correction-actions\" className=\"flex flex-col-reverse gap-2 sm:flex-row sm:justify-end\">\n          <Button\n            type=\"button\"\n            id={`${elementIdPrefix}-cancel`}\n            name=\"cancel-score-correction\"\n            data-name=\"score-correction-cancel\"\n            variant=\"outline\"\n            onClick={() => onOpenChange(false)}\n          >\n            Cancelar\n          </Button>\n          <Button\n            type=\"button\"\n            id={`${elementIdPrefix}-save-draft`}\n            name=\"save-score-correction\"\n            data-name=\"score-correction-save-draft\"\n            variant=\"outline\"\n            onClick={() => submit(false)}\n          >\n            Guardar corrección\n          </Button>\n          <Button\n            type=\"button\"\n            id={`${elementIdPrefix}-confirm`}\n            name=\"confirm-score-correction\"\n            data-name=\"score-correction-confirm\"\n            onClick={() => submit(true)}\n          >\n            Confirmar resultado\n          </Button>\n        </div>", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminScoreCorrectionModal.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export async function correctAdminScore(input: {\n  match: MatchRow\n  sets: ScoreSet[]\n  actorUserId: string\n  closeAfter?: boolean\n}): Promise<MatchRow | undefined> {\n  if (input.match.status === ''score_disputed'' && input.closeAfter === false) {\n    throw new Error(''En un partido refutado solo puedes validar o corregir y validar el marcador.'')\n  }\n  const explicit: MatchStatus =\n    input.match.status === ''score_disputed'' && input.closeAfter === false ? ''score_disputed'' : ''closed''", "old_string": "export async function correctAdminScore(input: {\n  match: MatchRow\n  sets: ScoreSet[]\n  actorUserId: string\n  closeAfter?: boolean\n}): Promise<MatchRow | undefined> {\n  const explicit: MatchStatus =\n    input.match.status === ''score_disputed'' && input.closeAfter === false ? ''score_disputed'' : ''closed''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\matches.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "/** Invalidación administrativa con auditoría vía RPC (logs). */\nexport async function adminInvalidateMatchResult(match: MatchRow): Promise<void> {\n  if (match.status === ''score_disputed'') {\n    throw new Error(''No puedes invalidar un partido refutado; valida o corrige el marcador.'')\n  }\n  const { error } = await supabase.rpc(''admin_set_match_result'', {", "old_string": "/** Invalidación administrativa con auditoría vía RPC (logs). */\nexport async function adminInvalidateMatchResult(match: MatchRow): Promise<void> {\n  const { error } = await supabase.rpc(''admin_set_match_result'', {", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\matches.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  if (match.status === ''score_disputed'') return ''Corregir marcador''", "old_string": "  if (match.status === ''score_disputed'') return ''Resolver refutación''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\matches\\MatchScoreModal.tsx"}}]}}'
