INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0162',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  162,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Encontré que los botones solo aparecen al expandir la fila; añadiendo pruebas unitarias, acciones visibles sin expandir y corrección de invalidación de caché.\n\n[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\matches.adminValidate.test.ts", "contents": "import { beforeEach, describe, expect, it, vi } from ''vitest''\n\nimport type { MatchRow } from ''@/types/database''\n\nconst rpcMock = vi.fn()\n\nvi.mock(''@/lib/supabase'', () => ({\n  supabase: {\n    rpc: (...args: unknown[]) => rpcMock(...args),\n  },\n}))\n\nimport { adminValidateDisputedWithoutChanges } from ''@/services/matches''\n\nfunction disputedMatch(overrides?: Partial<MatchRow>): MatchRow {\n  return {\n    id: ''match-1'',\n    status: ''score_disputed'',\n    winner_id: ''player-a-gp'',\n    score_raw: [{ a: 6, b: 4 }],\n    result_type: ''normal'',\n    game_type: ''best_of_3'',\n  } as MatchRow\n}\n\ndescribe(''adminValidateDisputedWithoutChanges'', () => {\n  beforeEach(() => {\n    rpcMock.mockReset()\n    rpcMock.mockResolvedValue({ error: null })\n  })\n\n  it(''valida disputa vía admin_set_match_result → validated'', async () => {\n    const match = disputedMatch()\n    await adminValidateDisputedWithoutChanges(match)\n\n    expect(rpcMock).toHaveBeenCalledOnce()\n    expect(rpcMock).toHaveBeenCalledWith(''admin_set_match_result'', {\n      p_match_id: ''match-1'',\n      p_score: [{ a: 6, b: 4 }],\n      p_winner_id: ''player-a-gp'',\n      p_status: ''validated'',\n      p_result_type: ''normal'',\n      p_game_type: ''best_of_3'',\n    })\n  })\n\n  it(''rechaza partidos que no están en score_disputed'', async () => {\n    await expect(\n      adminValidateDisputedWithoutChanges(disputedMatch({ status: ''closed'' })),\n    ).rejects.toThrow(''Solo aplica a partidos pendientes de revisión administrativa.'')\n    expect(rpcMock).not.toHave