putedMut.mutate(m)}\n              />\n            )}\n          />\n        )}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminNotificationsPage.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "        onSubmit={(input) => correctMut.mutate(input)}\n        submitPending={correctMut.isPending}\n      />", "old_string": "        onSubmit={(input) => correctMut.mutate(input)}\n      />", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminNotificationsPage.tsx"}}]}}'
