  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  elementIdPrefix = ''admin-score-correction'',\n  submitPending = false,\n}: {\n  match: AdminMatchRecord | null\n  rules: TournamentRules | null\n  open: boolean\n  onOpenChange: (open: boolean) => void\n  onSubmit: (input: { match: AdminMatchRecord; sets: ScoreSet[]; closeAfter: boolean; adminNote: string }) => void\n  /** Título del modal (p. ej. registrar / corregir / resolver refutación). */\n  title?: string\n  /** Subtítulo; por defecto “Jugador A vs Jugador B”. */\n  description?: string\n  /** Prefijo para ids y data-name de controles del modal. */\n  elementIdPrefix?: string\n  submitPending?: boolean\n}) {", "old_string": "  elementIdPrefix = ''admin-score-correction'',\n}: {\n  match: AdminMatchRecord | null\n  rules: TournamentRules | null\n  open: boolean\n  onOpenChange: (open: boolean) => void\n  onSubmit: (input: { match: AdminMatchRecord; sets: ScoreSet[]; closeAfter: boolean; adminNote: string }) => void\n  /** Título del modal (p. ej. registrar / corregir / resolver refutación). */\n  title?: string\n  /** Subtítulo; por defecto “Jugador A vs Jugador B”. */\n  description?: string\n  /** Prefijo para ids y data-name de controles del modal. */\n  elementIdPrefix?: string\n}) {", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminScoreCorrectionModal.tsx"}}, {"type": "tool_use", "name": "Read", "input": {"limit": 15, "offset": 478, "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminMatchesPage.tsx"}}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\matches.adminValidate.test.ts", "contents": "import { beforeEach, describe, expect, it, vi } from ''vitest''\n\nimport type { MatchRow } from ''@/types/database''\n\nconst rpcMock = vi.fn()\nconst singleMock = vi.fn()\n\nvi.mock(''@/lib/supabase'', () => ({\n  supabase: {\n    rpc: (...args: unknown[]) => rpcMock(...args),\n    from: () => ({\n      select: () => ({\n        eq: () => ({\n          single: () => singleMock(),\n        }),\n      }),\n    }),\n  },\n}))\n\nimport { adminValidateDisputedWithoutChanges } from ''@/services/matches''\n\nfunction disputedMatch(overrides?: Partial<MatchRow>): MatchRow {\n  return {\n    id: ''match-1'',\n    status: ''score_disputed'',\n    winner_id: ''player-a-gp'',\n    score_raw: [{ a: 6, b: 4 }],\n    result_type: ''normal'',\n    game_type: ''best_of_3'',\n    ...overrides,\n  } as MatchRow\n}\n\ndescribe(''adminValidateDisputedWithoutChanges'', () => {\n  beforeEach(() => {\n    rpcMock.mockReset()\n    singleMock.mockReset()\n    rpcMock.mockResolvedValue({ error: null })\n    singleMock.mockImplementation(async () => ({\n      data: disputedMatch(),\n      error: null,\n    }))\n  })\n\n  it(''valida disputa vía admin_set_match_result → validated'', async () => {\n    const match = disputedMatch()\n    await adminValidateDisputedWithoutChanges(match)\n\n    expect(singleMock).toHaveBeenCalledOnce()\n    expect(rpcMock).toHaveBeenCalledOnce()\n    expect(rpcMock).toHaveBeenCalledWith(''admin_set_match_result'', {\n      p_match_id: ''match-1'',\n      p_score: [{ a: 6, b: 4 }],\n      p_winner_id: ''player-a-gp'',\n      p_status: ''validated'',\n      p_result_type: ''normal'',\n      p_game_type: ''best_of_3'',\n    })\n  })\n\n  it(''rechaza partidos que no están en score_disputed'', async () => {\n    singleMock.mockResolvedValueOnce({\n      data: disputedMatch({ status: ''closed'' }),\n      error: null,\n    })\n\n    await expect(adminValidateDisputedWithoutChanges(disputedMatch())).rejects.toThrow(\n      ''Solo aplica a partidos pendientes de revisión administrativa.'',\n    )\n    expect(rpcMock).not.toHaveBeenCalled()\n  })\n\n  it(''rechaza si falta ganador'', async () => {\n    singleMock.mockResolvedValueOnce({\n      data: disputedMatch({ winner_id: null }),\n      error: null,\n    })\n\n    await expect(adminValidateDisputedWithoutChanges(disputedMatch())).rejects.toThrow(\n      ''Falta ganador en el registro actual.'',\n    )\n    expect(rpcMock).not.toHaveBeenCalled()\n  })\n\n  it(''propaga errores del RPC (p. ej. no admin)'', async () => {\n    rpcMock.mockResolvedValue({ error: { message: ''Solo staff'', code: ''P0001'' } })\n    await expect(adminValidateDisputedWithoutChanges(disputedMatch())).rejects.toThrow(''Solo staff'')\n  })\n})\n"}}]}}'
);

