INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0189',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  189,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Creando componentes de layout compartidos y rediseñando las cards de jugador y admin con mejor jerarquía visual y menos ruido.\n\n[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchCardLayout.tsx", "contents": "import type { ReactNode } from ''react''\n\nimport { cn } from ''@/lib/utils''\n\nexport type MatchCardAccent = ''neutral'' | ''pending'' | ''success'' | ''warning'' | ''dispute'' | ''muted''\n\nconst accentBar: Record<MatchCardAccent, string> = {\n  neutral: ''bg-slate-300'',\n  pending: ''bg-sky-500'',\n  success: ''bg-emerald-500'',\n  warning: ''bg-amber-500'',\n  dispute: ''bg-amber-500'',\n  muted: ''bg-slate-400'',\n}\n\nconst accentBorder: Record<MatchCardAccent, string> = {\n  neutral: ''border-slate-200/90'',\n  pending: ''border-sky-200/90'',\n  success: ''border-emerald-200/90'',\n  warning: ''border-amber-200/90'',\n  dispute: ''border-amber-200/90'',\n  muted: ''border-slate-200/80'',\n}\n\nexport function MatchCardShell({\n  id,\n  dataName,\n  accent = ''neutral'',\n  className,\n  children,\n}: {\n  id?: string\n  dataName?: string\n  accent?: MatchCardAccent\n  className?: string\n  children: ReactNode\n}) {\n  return (\n    <article\n      id={id}\n      data-name={dataName}\n      className={cn(\n        ''overflow-hidden rounded-xl border bg-white shadow-sm ring-1 ring-black/[0.03]'',\n        accentBorder[accent],\n        className,\n      )}\n    >\n      <div className={cn(''h-1 w-full'', accentBar[accent])} aria-hidden />\n      <div className=\"p-4 sm:p-[1.125rem]\">{children}</div>\n    </article>\n  )\n}\n\nexport function MatchCardHeader({\n  eyebrow,\n  title,\n  badge,\n  meta,\n  className,\n}: {\n  eyebrow?: ReactNode\n  title: ReactNode\n  badge?: ReactNode\n  meta?: ReactNode\n  className?: string\n}) {\n  return (\n    <header className={cn(''flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between'', className)}>\n      <div className=\"min-w-0 flex-1 space-y-1\">\n        {eyebrow ? (\n          <p className=\"text-[11px] font-semibold uppercase tracking-wide text-slate-500\">{eyebrow}</p>\n        ) : null}\n        <h3 className=\"text-pretty text-base font-semibold leading-snug text-[#102A43] sm:text-[1.05rem]\">{title}</h3>\n        {meta ? <p className=\"text-xs leading-relaxed text-slate-500\">{meta}</p> : null}\n      </div>\n      {badge ? <div className=\"shrink-0\">{badge}</div> : null}\n    </header>\n  )\n}\n\nexport function MatchCardScoreBlock({\n  label,\n  score,\n  hint,\n  className,\n}: {\n  label: string\n  score: ReactNode\n  hint?: ReactNode\n  className?: string\n}) {\n  return (\n    <div\n      className={cn(\n        ''flex flex-col justify-center rounded-lg border border-slate-200/80 bg-slate-50/80 px-3 py-2.5 sm:min-w-[9.5rem]'',\n        className,\n      )}\n    >\n      <p className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-500\">{label}</p>\n      <p className=\"mt-0.5 font-mono text-xl font-bold tabular-nums leading-none tracking-tight text-[#102A43] sm:text-2xl\">\n        {score}\n      </p>\n      {hint ? <p className=\"mt-1.5 text-xs leading-snug text-slate-600\">{hint}</p> : null}\n    </div>\n  )\n}\n\nexport function MatchCardBodyGrid({ children, className }: { children: ReactNode; className?: string }) {\n  return (\n    <div className={cn(''mt-4 grid gap-3 sm:grid-cols-[minmax(0,1fr)_auto] sm:items-start'', className)}>\n      {children}\n    </div>\n  )\n}\n\nexport function MatchCardFacts({ children, className }: { children: ReactNode; className?: string }) {\n  return (\n    <dl className={cn(''grid gap-2 text-sm'', className)}>\n      {children}\n    </dl>\n  )\n}\n\nexport function MatchCardFact({ label, value }: { label: string; value: ReactNode }) {\n  return (\n    <div className=\"grid gap-0.5 sm:grid-cols-[5.5rem_minmax(0,1fr)] sm:items-baseline sm:gap-3\">\n      <dt className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-400 sm:text-right\">{label}</dt>\n      <dd className=\"min-w-0 font-medium leading-snug text-slate-700\">{value}</dd>\n    </div>\n  )\n}\n\nexport function MatchCardMessage({ children, className }: { children: ReactNode; className?: string }) {\n  return (\n    <p className={cn(''mt-3 text-sm leading-relaxed text-slate-600'', className)}>{children}</p>\n  )\n}\n\nexport function MatchCardCallout({\n  title,\n  children,\n  variant = ''warning'',\n  className,\n}: {\n  title?: string\n  children: ReactNode\n  variant?: ''warning'' | ''info''\n  className?: string\n}) {\n  return (\n    <div\n      className={cn(\n        ''mt-3 rounded-lg border px-3 py-2.5 text-sm leading-relaxed'',\n        variant === ''warning''\n          ? ''border-amber-200/90 bg-amber-50/90 text-amber-950''\n          : ''border-slate-200/90 bg-slate-50/90 text-slate-700'',\n        className,\n      )}\n    >\n      {title ? <p className=\"text-[10px] font-semibold uppercase tracking-wide text-inherit opacity-80\">{title}</p> : null}\n      <div className={title ? ''mt-1'' : undefined}>{children}</div>\n    </div>\n  )\n}\n\nexport function MatchCardFooter({ children, className }: { children: ReactNode; className?: string }) {\n  return (\n    <footer className={cn(''mt-4 flex flex-col gap-2 border-t border-slate-200/80 pt-4 sm:flex-row sm:flex-wrap sm:justify-end'', className)}>\n      {children}\n    </footer>\n  )\n}\n\nexport function StatusPill({ label, toneClass }: { label: string; toneClass: string }) {\n  return (\n    <span className={cn(''inline-flex rounded-full border px-2.5 py-0.5 text-[11px] font-semibold leading-tight'', toneClass)}>\n      {label}\n    </span>\n  )\n}\n"}}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerRegisteredMatchCard.tsx", "contents": "import { Button } from ''@/components/ui/button''\nimport { MatchScoreTimeline } from ''@/components/player/MatchScoreTimeline''\nimport {\n  MatchCardBodyGrid,\n  MatchCardCallout,\n  MatchCardFact,\n  MatchCardFacts,\n  MatchCardFooter,\n  MatchCardHeader,\n  MatchCardMessage,\n  MatchCardScoreBlock,\n  MatchCardShell,\n  StatusPill,\n  type MatchCardAccent,\n} from ''@/components/shared/MatchCardLayout''\nimport {\n  calculateMatchGamesDifference,\n  getMatchOutcome,\n  getPointsForPlayerInMatch,\n} from ''@/lib/playerDashboard''\nimport { getPlayerPerspectiveScore } from ''@/lib/matchUserPerspective''\nimport {\n  importResultTypeBothPenalized,\n  importResultTypeUsesDefaultPoints,\n} from ''@/lib/matchResultSemantics''\nimport { matchStatusLabels, matchStatusToneClasses } from ''@/lib/matchStatus''\nimport type { GroupPlayer, MatchGameType, MatchResultType, MatchRow, TournamentRules } from ''@/types/database''\n\nfunction gameTypeLabel(gt: MatchGameType | null | undefined): string {\n  if (gt === ''long_set'') return ''Set largo''\n  if (gt === ''sudden_death'') return ''Muerte súbita''\n  if (gt === ''best_of_3_short_tiebreak'') return ''2 de 3 (tie-break corto)''\n  return ''Al mejor de 3''\n}\n\nfunction outcomeLine(match: MatchRow, myGroupPlayerId: string, resultType: MatchResultType | null): string {\n  if (importResultTypeBothPenalized(match.result_type)) return ''No reportado · penalización''\n  if (match.winner_id == null) return ''—''\n  const walkoverLike = importResultTypeUsesDefaultPoints(resultType)\n  const w = getMatchOutcome(match, myGroupPlayerId)\n  if (walkoverLike) {\n    if (w === ''win'') return ''Ganaste (W.O./DEF)''\n    if (w === ''loss'') return ''Perdiste (W.O./DEF)''\n  }\n  if (resultType === ''retired'') {\n    if (w === ''win'') return ''Ganaste (retiro)''\n    if (w === ''loss'') return ''Perdiste (retiro)''\n  }\n  if (w === ''win'') return ''Ganaste''\n  if (w === ''loss'') return ''Perdiste''\n  return ''—''\n}\n\nfunction signed(n: number) {\n  if (n > 0) return `+${n}`\n  return String(n)\n}\n\nfunction pointsPhrase(points: number) {\n  const sign = points >= 0 ? ''+'' : ''''\n  return `${sign}${points} ${Math.abs(points) === 1 ? ''pt'' : ''pts''}`\n}\n\nexport function PlayerRegisteredMatchCard({\n  match,\n  rivalName,\n  myGroupPlayerId,\n  players,\n  rules,\n  variant,\n  trackingMessage,\n  onRefute,\n}: {\n  match: MatchRow\n  rivalName: string\n  myGroupPlayerId: string\n  players: GroupPlayer[]\n  rules: TournamentRules\n  variant: ''disputed'' | ''official'' | ''tracking''\n  trackingMessage?: string\n  onRefute?: () => void\n}) {\n  const perspectiveScore = getPlayerPerspectiveScore(match, myGroupPlayerId)\n  const winnerPlayer = match.winner_id ? players.find((p) => p.id === match.winner_id) : null\n  const winnerScore = winnerPlayer ? getPlayerPerspectiveScore(match, winnerPlayer.id) : perspectiveScore\n  const hasScore = Boolean(match.score_raw?.length || match.game_type === ''sudden_death'')\n\n  let accent: MatchCardAccent = ''neutral''\n  let badgeLabel = matchStatusLabels[match.status]\n  let badgeTone = matchStatusToneClasses[match.status]\n\n  if (variant === ''disputed'') {\n    accent = ''dispute''\n    badgeLabel = ''En revisión''\n    badgeTone = matchStatusToneClasses.score_disputed\n  } else if (variant === ''official'') {\n    accent = match.status === ''validated'' ? ''success'' : ''success''\n    badgeLabel = match.status === ''validated'' ? ''Validado'' : ''Oficial''\n    badgeTone = match.status === ''validated'' ? matchStatusToneClasses.validated : matchStatusToneClasses.closed\n  } else if (match.status === ''score_submitted'') {\n    accent = ''pending''\n    badgeLabel = ''Provisional''\n    badgeTone = ''border-emerald-200 bg-emerald-50 text-emerald-800''\n  }\n\n  const officialCounted =\n    variant === ''official'' && (match.status === ''closed'' || match.status === ''validated'') && match.winner_id != null\n  const cancelled = match.status === ''cancelled''\n  const pts = officialCounted ? getPointsForPlayerInMatch(match, myGroupPlayerId, rules) : null\n  const gamesDiff = officialCounted ? calculateMatchGamesDifference(myGroupPlayerId, match) : null\n\n  return (\n    <MatchCardShell accent={accent}>\n      <MatchCardHeader\n        eyebrow={`Formato · ${gameTypeLabel(match.game_type)}`}\n        title={`Vs. ${rivalName}`}\n        badge={<StatusPill label={badgeLabel} toneClass={badgeTone} />}\n      />\n\n      <MatchCardBodyGrid>\n        <div className=\"min-w-0 space-y-3\">\n          {variant === ''disputed'' ? (\n            <>\n              <MatchCardMessage>\n                Organización revisará el marcador. Hasta entonces no cuenta para la tabla del grupo.\n              </MatchCardMessage>\n              <MatchCardFacts>\n                {winnerPlayer ? <MatchCardFact label=\"Ganador\" value={winnerPlayer.display_name} /> : null}\n                {match.dispute_reason ? (\n                  <MatchCardFact label=\"Motivo\" value={match.dispute_reason} />\n                ) : null}\n              </MatchCardFacts>\n            </>\n          ) : null}\n\n          {variant === ''official'' && !cancelled ? (\n            <MatchCardFacts>\n              <MatchCardFact label=\"Resultado\" value={outcomeLine(match, myGroupPlayerId, match.result_type)} />\n            </MatchCardFacts>\n          ) : null}\n\n          {variant === ''official'' && cancelled ? (\n            <MatchCardMessage>Partido cancelado.</MatchCardMessage>\n          ) : null}\n\n          {variant === ''tracking'' && trackingMessage ? (\n            <MatchCardMessage>{trackingMessage}</MatchCardMessage>\n          ) : null}\n\n          {(variant === ''disputed'' || officialCounted) && !cancelled ? (\n            <MatchScoreTimeline matchId={match.id} collapsible defaultCollapsed />\n          ) : null}\n        </div>\n\n        {hasScore && !cancelled ? (\n          <MatchCardScoreBlock\n            label={variant === ''disputed'' ? ''Marcador registrado'' : ''Tu marcador''}\n            score={variant === ''disputed'' ? winnerScore : perspectiveScore}\n            hint={\n              variant === ''disputed'' && winnerPlayer\n                ? `Vista del ganador · ${winnerPlayer.display_name}`\n                : pts != null && gamesDiff != null\n                  ? `${pointsPhrase(pts)} · Juegos ${signed(gamesDiff)}`\n                  : undefined\n            }\n          />\n        ) : null}\n      </MatchCardBodyGrid>\n\n      {onRefute ? (\n        <MatchCardFooter>\n          <p className=\"mr-auto hidden max-w-md text-xs leading-relaxed text-slate-500 sm:block\">\n            Si no coincide con lo jugado, puedes refutarlo.\n          </p>\n          <Button type=\"button\" variant=\"outline\" className=\"min-h-11 w-full sm:w-auto\" onClick={onRefute}>\n            Refutar resultado\n          </Button>\n        </MatchCardFooter>\n      ) : null}\n    </MatchCardShell>\n  )\n}\n"}}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0190',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  190,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"contents": "import { ChevronDown } from ''lucide-react''\nimport { useState } from ''react''\nimport { useQuery } from ''@tanstack/react-query''\n\nimport { listMatchScoreLogs } from ''@/services/matches''\nimport { cn } from ''@/lib/utils''\n\nfunction describeAction(actionType: string): string {\n  switch (actionType) {\n    case ''player_a_submit'':\n      return ''Jugador A registró marcador''\n    case ''player_b_submit'':\n      return ''Jugador B registró marcador''\n    case ''player_resubmit_after_dispute'':\n      return ''Reenvío tras disputa (histórico)''\n    case ''opponent_reject'':\n      return ''Rival refutó resultado''\n    case ''player_disputed'':\n      return ''Marcador refutado por rival''\n    case ''match_validated'':\n      return ''Resultado validado por administración''\n    case ''admin_score_corrected'':\n      return ''Marcador corregido por administración''\n    case ''admin_invalidate_match'':\n      return ''Partido invalidado por administración''\n    case ''admin_update'':\n      return ''Actualización administrativa''\n    default:\n      return actionType.replace(/_/g, '' '')\n  }\n}\n\nexport function MatchScoreTimeline({\n  matchId,\n  className,\n  collapsible = false,\n  defaultCollapsed = false,\n}: {\n  matchId: string\n  className?: string\n  collapsible?: boolean\n  defaultCollapsed?: boolean\n}) {\n  const [open, setOpen] = useState(!defaultCollapsed)\n  const q = useQuery({\n    queryKey: [''matchScoreLogs'', matchId],\n    queryFn: () => listMatchScoreLogs(matchId),\n    staleTime: 60_000,\n  })\n\n  if (q.isLoading) {\n    return <p className={cn(''text-xs text-slate-400'', className)}>Cargando historial…</p>\n  }\n  if (q.isError) return null\n  const rows = q.data ?? []\n  if (!rows.length) return null\n\n  const list = (\n    <ul className=\"space-y-1.5 text-xs text-slate-600\">\n      {rows.map((row) => (\n        <li key={row.id} className=\"flex gap-2 border-l-2 border-[#1F5A4C]/20 pl-2\">\n          <time className=\"shrink-0 text-[10px] tabular-nums text-slate-400\">\n            {new Date(row.created_at).toLocaleString(undefined, {\n              day: ''2-digit'',\n              month: ''short'',\n              hour: ''2-digit'',\n              minute: ''2-digit'',\n            })}\n          </time>\n          <span>{describeAction(row.action_type)}</span>\n        </li>\n      ))}\n    </ul>\n  )\n\n  if (!collapsible) {\n    return (\n      <div className={cn(''border-t border-slate-200/80 pt-3'', className)}>\n        <p className=\"mb-2 text-[10px] font-semibold uppercase tracking-wide text-slate-400\">Historial</p>\n        {list}\n      </div>\n    )\n  }\n\n  return (\n    <div className={cn(''border-t border-slate-200/80 pt-2'', className)}>\n      <button\n        type=\"button\"\n        className=\"flex w-full items-center gap-1.5 rounded-md py-1 text-left text-xs font-medium text-slate-600 hover:text-[#102A43] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25\"\n        aria-expanded={open}\n        onClick={() => setOpen((v) => !v)}\n      >\n        <ChevronDown className={cn(''size-3.5 shrink-0 transition-transform'', open && ''rotate-180'')} aria-hidden />\n        Historial ({rows.length})\n      </button>\n      {open ? <div className=\"mt-2\">{list}</div> : null}\n    </div>\n  )\n}\n", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\MatchScoreTimeline.tsx"}}, {"type": "tool_use", "name": "Write", "input": {"contents": "import { useCallback, useRef, useState } from ''react''\nimport { useQueryClient } from ''@tanstack/react-query''\nimport { toast } from ''sonner''\n\nimport { ScoreSubmissionModal } from ''@/components/matches/ScoreSubmissionModal''\nimport { MatchScoreTimeline } from ''@/components/player/MatchScoreTimeline''\nimport {\n  MatchCardBodyGrid,\n  MatchCardCallout,\n  MatchCardFooter,\n  MatchCardHeader,\n  MatchCardMessage,\n  MatchCardScoreBlock,\n  MatchCardShell,\n  StatusPill,\n  type MatchCardAccent,\n} from ''@/components/shared/MatchCardLayout''\nimport { Button } from ''@/components/ui/button''\nimport {\n  Dialog,\n  DialogContent,\n  DialogDescription,\n  DialogFooter,\n  DialogHeader,\n  DialogTitle,\n} from ''@/components/ui/dialog''\nimport { Textarea } from ''@/components/ui/textarea''\nimport {\n  canRejectScore,\n  canSubmitScore,\n  getOpponentInMatch,\n  isMatchPlayerA,\n  isPendingScoreStatus,\n  matchDisplayStatus,\n  matchStatusLabels,\n  matchStatusToneClasses,\n} from ''@/lib/matchStatus''\nimport { getPlayerPerspectiveScore } from ''@/lib/matchUserPerspective''\nimport {\n  mergeMatchAfterPlayerSubmit,\n  patchPlayerViewModelAfterOpponentReject,\n  patchPlayerViewModelMatches,\n} from ''@/lib/playerDashboardMatchCache''\nimport {\n  PLAYER_SCORE_DISPUTE_REASON_MAX_LENGTH,\n  validatePlayerScoreDisputeReason,\n} from ''@/lib/playerScoreDispute''\nimport { isPlayerSubmitPerfEnabled } from ''@/lib/playerSubmitPerf''\nimport { cn } from ''@/lib/utils''\nimport {\n  preparePlayerScoreSubmissionSync,\n  rejectPlayerScore,\n  submitPlayerScore,\n} from ''@/services/matches''\nimport type { PlayerViewModel } from ''@/services/playerViewModel''\nimport type { GroupPlayer, MatchRow, TournamentRules } from ''@/types/database''\n\nfunction cardAccent(match: MatchRow, canSubmit: boolean): MatchCardAccent {\n  if (match.status === ''score_disputed'') return ''dispute''\n  if (canSubmit || isPendingScoreStatus(match.status)) return ''pending''\n  if (match.status === ''closed'' || match.status === ''validated'') return ''success''\n  return ''neutral''\n}\n\nfunction shortActionCopy(\n  match: MatchRow,\n  canReject: boolean,\n  canSubmit: boolean,\n  iSubmittedPending: boolean,\n): string {\n  if (match.status === ''cancelled'') return ''Partido cancelado.''\n  if (match.status === ''score_disputed'') {\n    return ''En revisión por organización. El marcador aún no cuenta para la tabla.''\n  }\n  if (match.status === ''validated'') return ''Validado por organización · cuenta para la tabla.''\n  if (match.status === ''closed'') {\n    return canReject\n      ? ''Resultado oficial. Refuta solo si no coincide con lo jugado.''\n      : ''Resultado oficial · ya impacta el ranking.''\n  }\n  if (match.status === ''score_submitted'') {\n    return iSubmittedPending\n      ? ''Registraste el marcador. Tu rival puede refutarlo.''\n      : ''Tu rival registró el marcador. Puedes refutarlo si no coincide.''\n  }\n  if (canSubmit) return ''Registra el marcador para cerrar este partido.''\n  if (isPendingScoreStatus(match.status)) return ''Pendiente de marcador.''\n  return ''Partido en seguimiento.''\n}\n\nexport function PlayerMatchActionCard({\n  match,\n  players,\n  rules,\n  myGroupPlayerId,\n  userId,\n  groupName,\n  onAfterMatchMutation,\n  className,\n}: {\n  match: MatchRow\n  players: GroupPlayer[]\n  rules: TournamentRules\n  myGroupPlayerId: string\n  userId: string\n  groupName: string\n  onAfterMatchMutation: (payload: { match: MatchRow }) => void\n  className?: string\n}) {\n  const qc = useQueryClient()\n  const [scoreOpen, setScoreOpen] = useState(false)\n  const [rejectOpen, setRejectOpen] = useState(false)\n  const [rejectReason, setRejectReason] = useState('''')\n  const [busy, setBusy] = useState(false)\n  const submitInFlightRef = useRef(false)\n  const rejectInFlightRef = useRef(false)\n\n  const rival = getOpponentInMatch(match, myGroupPlayerId, players)\n  const perspectiveScore = getPlayerPerspectiveScore(match, myGroupPlayerId)\n  const winnerPlayer = match.winner_id ? players.find((p) => p.id === match.winner_id) : null\n  const disputedScore = winnerPlayer ? getPlayerPerspectiveScore(match, winnerPlayer.id) : perspectiveScore\n  const canSubmit = rules.allow_player_score_entry && canSubmitScore(match, userId)\n  const canReject = rules.allow_player_score_entry && canRejectScore(match, userId)\n  const hasScore = Boolean(match.score_raw?.length || match.game_type === ''sudden_death'')\n\n  const iSubmittedPending =\n    match.status === ''score_submitted'' &&\n    (match.score_submitted_by === userId ||\n      (match.score_submitted_by == null && isMatchPlayerA(match, userId)))\n\n  const displayStatus = matchDisplayStatus(match) as MatchRow[''status'']\n  const isOfficialLike = match.status === ''closed'' || match.status === ''validated''\n  const statusLabel = isOfficialLike\n    ? match.status === ''validated''\n      ? matchStatusLabels.validated\n      : matchStatusLabels.closed\n    : matchStatusLabels[displayStatus]\n  const statusTone = isOfficialLike\n    ? match.status === ''validated''\n      ? matchStatusToneClasses.validated\n      : matchStatusToneClasses.closed\n    : matchStatusToneClasses[displayStatus]\n\n  const handleReject = useCallback(async () => {\n    if (rejectInFlightRef.current) return\n    const parsed = validatePlayerScoreDisputeReason(rejectReason)\n    if (!parsed.ok) {\n      toast.error(parsed.message)\n      return\n    }\n    rejectInFlightRef.current = true\n    setBusy(true)\n    try {\n      const serverMatch = await rejectPlayerScore({ matchId: match.id, disputeReason: parsed.reason })\n      const merged = patchPlayerViewModelAfterOpponentReject(qc, userId, serverMatch ?? match, parsed.reason)\n      void qc.invalidateQueries({ queryKey: [''admin-disputed-results''] })\n      void qc.invalidateQueries({ queryKey: [''admin-results''] })\n      void qc.invalidateQueries({ queryKey: [''admin-matches''] })\n      void qc.invalidateQueries({ queryKey: [''admin-overview''] })\n      toast.message(''Resultado refutado'', {\n        description: ''Organización revisará el marcador.'',\n      })\n      setRejectOpen(false)\n      setRejectReason('''')\n      onAfterMatchMutation({ match: merged })\n    } catch (error) {\n      toast.error(error instanceof Error ? error.message : ''No se pudo refutar el marcador'')\n    } finally {\n      rejectInFlightRef.current = false\n      setBusy(false)\n    }\n  }, [rejectReason, match, userId, qc, onAfterMatchMutation])\n\n  return (\n    <MatchCardShell accent={cardAccent(match, canSubmit)} className={className}>\n      <MatchCardHeader\n        eyebrow={groupName}\n        title={`Vs. ${rival?.display_name ?? ''Rival''}`}\n        badge={<StatusPill label={statusLabel} toneClass={statusTone} />}\n      />\n\n      <MatchCardBodyGrid>\n        <MatchCardMessage>{shortActionCopy(match, canReject, canSubmit, iSubmittedPending)}</MatchCardMessage>\n\n        {hasScore ? (\n          <MatchCardScoreBlock\n            label={match.status === ''score_disputed'' ? ''Marcador registrado'' : ''Marcador''}\n            score={match.status === ''score_disputed'' ? disputedScore : perspectiveScore}\n            hint={\n              match.status === ''score_disputed'' && winnerPlayer\n                ? `Ganador · ${winnerPlayer.display_name}`\n                : undefined\n            }\n          />\n        ) : null}\n      </MatchCardBodyGrid>\n\n      {match.status === ''score_disputed'' && match.dispute_reason ? (\n        <MatchCardCallout title=\"Motivo de refutación\">{match.dispute_reason}</MatchCardCallout>\n      ) : null}\n\n      {match.status === ''score_disputed'' || match.status === ''validated'' ? (\n        <MatchScoreTimeline matchId={match.id} collapsible defaultCollapsed className=\"mt-3\" />\n      ) : null}\n\n      {(canSubmit || canReject) && (\n        <MatchCardFooter>\n          {canSubmit ? (\n            <Button className=\"min-h-11 w-full sm:w-auto\" onClick={() => setScoreOpen(true)}>\n              {match.status === ''score_disputed'' ? ''Corregir y reenviar'' : ''Registrar marcador''}\n            </Button>\n          ) : null}\n          {canReject ? (\n            <Button className=\"min-h-11 w-full sm:w-auto\" variant=\"outline\" disabled={busy} onClick={() => setRejectOpen(true)}>\n              Refutar\n            </Button>\n          ) : null}\n        </MatchCardFooter>\n      )}\n\n      <ScoreSubmissionModal\n        open={scoreOpen}\n        onOpenChange={setScoreOpen}\n        match={match}\n        players={players}\n        viewerGroupPlayerId={myGroupPlayerId}\n        rules={rules}\n        submitting={busy}\n        submitLabel=\"Enviar marcador\"\n        onSubmit={async (scorePayload) => {\n          if (submitInFlightRef.current) return\n          submitInFlightRef.current = true\n          setBusy(true)\n          const perf = isPlayerSubmitPerfEnabled()\n          const t0 = perf ? performance.now() : 0\n          try {\n            const prepared = preparePlayerScoreSubmissionSync({ match, scorePayload, rules })\n            const tRpc = perf ? performance.now() : 0\n            const serverRow = await submitPlayerScore({ match, scorePayload, actorUserId: userId, rules })\n            if (perf) {\n              console.debug(`[perf] submitPlayerScore RPC ${Math.round(performance.now() - tRpc)}ms`)\n            }\n            const tMerge = perf ? performance.now() : 0\n            const merged = serverRow ?? mergeMatchAfterPlayerSubmit(match, prepared, userId)\n            qc.setQueryData<PlayerViewModel | null>([''playerViewModel'', userId, match.group_id], (old) =>\n              patchPlayerViewModelMatches(old, userId, match.id, merged),\n            )\n            if (perf) {\n              console.debug(`[perf] patchPlayerViewModelMatches ${Math.round(performance.now() - tMerge)}ms`)\n            }\n            toast.success(\n              match.status === ''score_disputed''\n                ? ''Marcador reenviado''\n                : ''Marcador registrado · ya cuenta como oficial en la tabla.'',\n            )\n            setScoreOpen(false)\n            onAfterMatchMutation({ match: merged })\n            if (perf) {\n              console.debug(`[perf] total ${Math.round(performance.now() - t0)}ms`)\n            }\n          } catch (error) {\n            toast.error(error instanceof Error ? error.message : ''No se pudo enviar el marcador'')\n          } finally {\n            submitInFlightRef.current = false\n            setBusy(false)\n          }\n        }}\n      />\n\n      <Dialog\n        open={rejectOpen}\n        onOpenChange={(open) => {\n          if (!open && busy) return\n          setRejectOpen(open)\n          if (!open) setRejectReason('''')\n        }}\n      >\n        <DialogContent\n          showCloseButton={!busy}\n          className=\"flex max-h-[min(100dvh-1rem,32rem)] w-[min(100vw-1rem,28rem)] flex-col gap-0 overflow-hidden p-0 sm:max-w-md\"\n        >\n          <DialogHeader className=\"shrink-0 space-y-2 px-4 pb-2 pt-5 pr-12\">\n            <DialogTitle className=\"text-base\">Refutar resultado</DialogTitle>\n            <DialogDescription className=\"text-xs leading-relaxed sm:text-sm\">\n              Explica el motivo; organización revisará y definirá el marcador oficial.\n            </DialogDescription>\n          </DialogHeader>\n          <div className=\"min-h-0 flex-1 overflow-y-auto px-4 pb-2\">\n            <Textarea\n              value={rejectReason}\n              onChange={(event) => setRejectReason(event.target.value)}\n              placeholder=\"Ej.: Los sets no coinciden con lo jugado…\"\n              maxLength={PLAYER_SCORE_DISPUTE_REASON_MAX_LENGTH}\n              className=\"min-h-28 text-base sm:text-sm\"\n              aria-label=\"Motivo de la refutación\"\n              aria-invalid={\n                rejectReason.trim().length > 0 && !validatePlayerScoreDisputeReason(rejectReason).ok\n              }\n            />\n          </div>\n          <DialogFooter className=\"shrink-0 flex-col-reverse gap-2 border-t bg-background/95 px-4 py-3 backdrop-blur-sm pb-[max(0.75rem,env(safe-area-inset-bottom))] sm:flex-row sm:justify-end\">\n            <Button variant=\"outline\" className=\"min-h-11 w-full sm:w-auto\" disabled={busy} onClick={() => setRejectOpen(false)}>\n              Cancelar\n            </Button>\n            <Button\n              variant=\"destructive\"\n              className=\"min-h-11 w-full sm:w-auto\"\n              disabled={\n                busy ||\n                rejectReason.trim().length < 3 ||\n                rejectReason.trim().length > PLAYER_SCORE_DISPUTE_REASON_MAX_LENGTH\n              }\n              onClick={() => void handleReject()}\n            >\n              Enviar refutación\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n    </MatchCardShell>\n  )\n}\n"}}]}}'
);

