invalidateQueries({ queryKey: [''admin-disputed-results''] })\n      void qc.invalidateQueries({ queryKey: [''admin-results''] })\n      void qc.invalidateQueries({ queryKey: [''admin-matches''] })\n      void qc.invalidateQueries({ queryKey: [''admin-overview''] })\n      toast.message(''Resultado refutado'', {\n        description: ''Organización revisará el marcador.'',\n      })\n      setRejectOpen(false)\n      setRejectReason('''')\n      onAfterMatchMutation({ match: merged })\n    } catch (error) {\n      toast.error(error instanceof Error ? error.message : ''No se pudo refutar el marcador'')\n    } finally {\n      rejectInFlightRef.current = false\n      setBusy(false)\n    }\n  }, [rejectReason, match, userId, qc, onAfterMatchMutation])\n\n  return (\n    <MatchCardShell accent={cardAccent(match, canSubmit)} className={className}>\n      <MatchCardHeader\n        eyebrow={groupName}\n        title={`Vs. ${rival?.display_name ?? ''Rival''}`}\n        badge={<StatusPill label={statusLabel} toneClass={statusTone} />}\n      />\n\n      <MatchCardBodyGrid>\n        <MatchCardMessage>{shortActionCopy(match, canReject, canSubmit, iSubmittedPending)}</MatchCardMessage>\n\n        {hasScore ? (\n          <MatchCardScoreBlock\n            label={match.status === ''score_disputed'' ? ''Marcador registrado'' : ''Marcador''}\n            score={match.status === ''score_disputed'' ? disputedScore : perspectiveScore}\n            hint={\n              match.status === ''score_disputed'' && winnerPlayer\n                ? `Ganador · ${winnerPlayer.display_name}`\n                : undefined\n            }\n          />\n        ) : null}\n      </MatchCardBodyGrid>\n\n      {match.status === ''score_disputed'' && match.dispute_reason ? (\n        <MatchCardCallout title=\"Motivo de refutación\">{match.dispute_reason}</MatchCardCallout>\n      ) : null}\n\n      {match.status === ''score_disputed'' || match.status === ''validated'' ? (\n        <MatchScoreTimeline matchId={match.id} collapsible defaultCollapsed className=\"mt-3\" />\n      ) : null}\n\n      {(canSubmit || canReject) && (\n        <MatchCardFooter>\n          {canSubmit ? (\n            <Button className=\"min-h-11 w-full sm:w-auto\" onClick={() => setScoreOpen(true)}>\n              {match.status === ''score_disputed'' ? ''Corregir y reenviar'' : ''Registrar marcador''}\n            </Button>\n          ) : null}\n          {canReject ? (\n            <Button className=\"min-h-11 w-full sm:w-auto\" variant=\"outline\" disabled={busy} onClick={() => setRejectOpen(true)}>\n              Refutar\n            </Button>\n          ) : null}\n        </MatchCardFooter>\n      )}\n\n      <ScoreSubmissionModal\n        open={scoreOpen}\n        onOpenChange={setScoreOpen}\n        match={match}\n        players={players}\n        viewerGroupPlayerId={myGroupPlayerId}\n        rules={rules}\n        submitting={busy}\n        submitLabel=\"Enviar marcador\"\n        onSubmit={async (scorePayload) => {\n          if (submitInFlightRef.current) return\n          submitInFlightRef.current = true\n          setBusy(true)\n          try {\n            const prepared = preparePlayerScoreSubmissionSync({ match, scorePayload, rules })\n            const serverRow = await submitPlayerScore({ match, scorePayload, actorUserId: userId, rules })\n            const merged = serverRow ?? mergeMatchAfterPlayerSubmit(match, prepared, userId)\n            qc.setQueryData<PlayerViewModel | null>([''playerViewModel'', userId, match.group_id], (old) =>\n              patchPlayerViewModelMatches(old, userId, match.id, merged),\n            )\n            toast.success(\n              match.status === ''score_disputed''\n                ? ''Marcador reenviado''\n                : ''Marcador registrado · ya cuenta como oficial en la tabla.'',\n            )\n            setScoreOpen(false)\n            onAfterMatchMutation({ match: merged })\n          } catch (error) {\n            toast.error(error instanceof Error ? error.message : ''No se pudo enviar el marcador'')\n          } finally {\n            submitInFlightRef.current = false\n            setBusy(false)\n          }\n        }}\n      />\n\n      <Dialog\n        open={rejectOpen}\n        onOpenChange={(open) => {\n          if (!open && busy) return\n          setRejectOpen(open)\n          if (!open) setRejectReason('''')\n        }}\n      >\n        <DialogContent\n          showCloseButton={!busy}\n          className=\"flex max-h-[min(100dvh-1rem,32rem)] w-[min(100vw-1rem,28rem)] flex-col gap-0 overflow-hidden p-0 sm:max-w-md\"\n        >\n          <DialogHeader className=\"shrink-0 space-y-2 px-4 pb-2 pt-5 pr-12\">\n            <DialogTitle className=\"text-base\">Refutar resultado</DialogTitle>\n            <DialogDescription className=\"text-xs leading-relaxed sm:text-sm\">\n              Explica el motivo; organización revisará y definirá el marcador oficial.\n            </DialogDescription>\n          </DialogHeader>\n          <div className=\"min-h-0 flex-1 overflow-y-auto px-4 pb-2\">\n            <Textarea\n              value={rejectReason}\n              onChange={(event) => setRejectReason(event.target.value)}\n              placeholder=\"Ej.: Los sets no coinciden con lo jugado…\"\n              maxLength={PLAYER_SCORE_DISPUTE_REASON_MAX_LENGTH}\n              className=\"min-h-28 text-base sm:text-sm\"\n              aria-label=\"Motivo de la refutación\"\n              aria-invalid={\n                rejectReason.trim().length > 0 && !validatePlayerScoreDisputeReason(rejectReason).ok\n              }\n            />\n          </div>\n          <DialogFooter className=\"shrink-0 flex-col-reverse gap-2 border-t bg-background/95 px-4 py-3 backdrop-blur-sm pb-[max(0.75rem,env(safe-area-inset-bottom))] sm:flex-row sm:justify-end\">\n            <Button variant=\"outline\" className=\"min-h-11 w-full sm:w-auto\" disabled={busy} onClick={() => setRejectOpen(false)}>\n              Cancelar\n            </Button>\n            <Button\n              variant=\"destructive\"\n              className=\"min-h-11 w-full sm:w-auto\"\n              disabled={\n                busy ||\n                rejectReason.trim().length < 3 ||\n                rejectReason.trim().length > PLAYER_SCORE_DISPUTE_REASON_MAX_LENGTH\n              }\n              onClick={() => void handleReject()}\n            >\n              Enviar refutación\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n    </MatchCardShell>\n  )\n}\n"}}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0192',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  192,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"contents": "import { CheckCircle2, ChevronDown, Pencil } from ''lucide-react''\nimport { useState } from ''react''\n\nimport {\n  MatchCardBodyGrid,\n  MatchCardCallout,\n  MatchCardFact,\n  MatchCardFacts,\n  MatchCardFooter,\n  MatchCardHeader,\n  MatchCardScoreBlock,\n  MatchCardShell,\n  StatusPill,\n} from ''@/components/shared/MatchCardLayout''\nimport { Button } from ''@/components/ui/button''\nimport { cn } from ''@/lib/utils''\nimport type { AdminMatchRecord } from ''@/services/admin''\nimport type { MatchStatus } from ''@/types/database''\n\nfunction formatScoreFromWinnerPerspective(match: AdminMatchRecord) {\n  if (!match.score_raw?.length) return ''—''\n  const winnerIsB = match.winner_id === match.player_b_id\n  return match.score_raw\n    .map((set) => (winnerIsB ? `${set.b}-${set.a}` : `${set.a}-${set.b}`))\n    .join('' · '')\n}\n\nfunction shortDate(iso: string | null | undefined) {\n  if (!iso) return ''—''\n  const d = new Date(iso)\n  if (Number.isNaN(d.getTime())) return ''—''\n  return new Intl.DateTimeFormat(''es'', { dateStyle: ''short'', timeStyle: ''short'' }).format(d)\n}\n\nfunction statusShortLabel(status: MatchStatus, refutedPending: boolean): string {\n  if (refutedPending) return ''Refutado · pendiente''\n  switch (status) {\n    case ''pending_score'':\n      return ''Sin marcador''\n    case ''score_submitted'':\n      return ''Confirmado''\n    case ''score_disputed'':\n      return ''En revisión''\n    case ''player_confirmed'':\n      return ''Pendiente validación''\n    case ''closed'':\n      return ''Oficial jugador''\n    case ''validated'':\n      return ''Validado admin''\n    case ''cancelled'':\n      return ''Cancelado''\n    default:\n      return status\n  }\n}\n\nfunction statusBadgeClass(status: MatchStatus, refutedPending: boolean): string {\n  if (refutedPending) return ''border-amber-300 bg-amber-50 text-amber-950''\n  switch (status) {\n    case ''score_disputed'':\n      return ''border-amber-300 bg-amber-50 text-amber-950''\n    case ''score_submitted'':\n      return ''border-blue-300 bg-blue-50 text-blue-900''\n    case ''closed'':\n      return ''border-green-300 bg-green-50 text-green-900''\n    case ''validated'':\n      return ''border-emerald-300 bg-emerald-50 text-emerald-900''\n    default:\n      return ''border-slate-300 bg-slate-50 text-slate-700''\n  }\n}\n\nfunction winnerLabel(match: AdminMatchRecord): string {\n  if (match.winner_id === match.player_a_id) return match.playerAName\n  if (match.winner_id === match.player_b_id) return match.playerBName\n  return ''—''\n}\n\nfunction DisputeActionButtons({\n  rowId,\n  match,\n  isDisputed,\n  canValidateLegacy,\n  onValidateAsIs,\n  onCorrect,\n  onConfirm,\n  validatePending = false,\n}: {\n  rowId: string\n  match: AdminMatchRecord\n  isDisputed: boolean\n  canValidateLegacy: boolean\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onConfirm: (match: AdminMatchRecord) => void\n  validatePending?: boolean\n}) {\n  if (isDisputed) {\n    return (\n      <div id={`${rowId}-actions`} data-name=\"dispute-row-actions\" className=\"flex flex-col gap-2 sm:flex-row sm:justify-end\">\n        <Button\n          id={`${rowId}-btn-validate`}\n          name={`validate-dispute-${match.id}`}\n          data-name=\"dispute-action-validate\"\n          size=\"sm\"\n          className=\"h-10 bg-emerald-600 text-white hover:bg-emerald-700 sm:h-9\"\n          onClick={() => onValidateAsIs?.(match)}\n          disabled={!onValidateAsIs || validatePending}\n        >\n          <CheckCircle2 className=\"size-3.5 opacity-90\" />\n          {validatePending ? ''Validando…'' : ''Validar marcador''}\n        </Button>\n        <Button\n          id={`${rowId}-btn-correct`}\n          name={`correct-dispute-${match.id}`}\n          data-name=\"dispute-action-correct\"\n          size=\"sm\"\n          variant=\"outline\"\n          className=\"h-10 sm:h-9\"\n          onClick={() => onCorrect(match)}\n          disabled={validatePending}\n        >\n          <Pencil className=\"size-3.5 opacity-80\" />\n          Corregir marcador\n        </Button>\n      </div>\n    )\n  }\n\n  return (\n    <div id={`${rowId}-actions`} data-name=\"dispute-row-actions\" className=\"flex flex-col gap-2 sm:flex-row sm:justify-end\">\n      <Button\n        id={`${rowId}-btn-validate-legacy`}\n        size=\"sm\"\n        disabled={!canValidateLegacy}\n        className=\"h-10 bg-emerald-600 text-white hover:bg-emerald-700 sm:h-9\"\n        onClick={() => onConfirm(match)}\n      >\n        <CheckCircle2 className=\"size-3.5 opacity-90\" />\n        Validar\n      </Button>\n      <Button id={`${rowId}-btn-correct-legacy`} size=\"sm\" variant=\"outline\" className=\"h-10 sm:h-9\" onClick={() => onCorrect(match)}>\n        <Pencil className=\"size-3.5 opacity-80\" />\n        Corregir\n      </Button>\n    </div>\n  )\n}\n\nexport function AdminResultReviewRow({\n  match,\n  quickReview,\n  onConfirm,\n  onCorrect,\n  onValidateAsIs,\n  validatePending = false,\n}: {\n  match: AdminMatchRecord\n  quickReview: boolean\n  onConfirm: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  validatePending?: boolean\n}) {\n  const [detailsOpen, setDetailsOpen] = useState(false)\n  const isRefutedPending = match.status === ''pending_score'' && Boolean(match.disputed_by)\n  const isDisputed = match.status === ''score_disputed''\n  const showRefutationContext = isDisputed || isRefutedPending\n  const canValidateLegacy = match.status === ''player_confirmed'' || match.status === ''score_submitted''\n  const rowId = `admin-notifications-dispute-${match.id}`\n  const winnerPerspectiveScore = formatScoreFromWinnerPerspective(match)\n  const winnerName = winnerLabel(match)\n  const disputerName = match.disputedByLabel ?? ''No identificado''\n\n  const playersTitle = (\n    <>\n      {match.playerAName}\n      <span className=\"font-normal text-slate-400\"> vs </span>\n      {match.playerBName}\n    </>\n  )\n\n  const shell = (\n    <MatchCardShell\n      id={rowId}\n      dataName=\"notifications-dispute-row\"\n      accent={showRefutationContext ? ''dispute'' : ''neutral''}\n    >\n      <MatchCardHeader\n        eyebrow={`${match.groupName} · ${match.tournamentName}`}\n        title={playersTitle}\n        meta={shortDate(match.disputed_at ?? match.score_submitted_at ?? match.updated_at)}\n        badge={\n          <StatusPill\n            label={statusShortLabel(match.status, isRefutedPending)}\n            toneClass={statusBadgeClass(match.status, isRefutedPending)}\n          />\n        }\n      />\n\n      <MatchCardBodyGrid>\n        <MatchCardFacts>\n          <MatchCardFact label=\"Ganador\" value={winnerName} />\n          <MatchCardFact label=\"Registró\" value={match.scoreSubmittedByLabel ?? ''—''} />\n          {showRefutationContext ? <MatchCardFact label=\"Refutó\" value={disputerName} /> : null}\n          {isRefutedPending ? (\n            <MatchCardFact label=\"Estado\" value=\"Volvió a pendiente / no jugado tras refutación\" />\n          ) : null}\n        </MatchCardFacts>\n\n        <MatchCardScoreBlock label=\"Marcador (ganador)\" score={winnerPerspectiveScore} />\n      </MatchCardBodyGrid>\n\n      {showRefutationContext && match.dispute_reason ? (\n        <MatchCardCallout title=\"Motivo de refutación\" className=\"mt-3\">\n          {match.dispute_reason}\n        </MatchCardCallout>\n      ) : null}\n\n      {!quickReview && showRefutationContext ? (\n        <div className=\"mt-3 border-t border-slate-200/80 pt-2\">\n          <button\n            id={`${rowId}-toggle`}\n            type=\"button\"\n            data-name=\"dispute-row-toggle\"\n            aria-expanded={detailsOpen}\n            className=\"flex w-full items-center gap-1.5 rounded-md py-1.5 text-left text-xs font-medium text-slate-600 hover:text-[#102A43] focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25\"\n            onClick={() => setDetailsOpen((v) => !v)}\n          >\n            <ChevronDown className={cn(''size-3.5 transition-transform'', detailsOpen && ''rotate-180'')} aria-hidden />\n            {detailsOpen ? ''Ocultar detalle'' : ''Ver detalle administrativo''}\n          </button>\n          {detailsOpen ? (\n            <div id={`${rowId}-details`} data-name=\"dispute-row-details\" className=\"mt-2 space-y-2 text-sm text-slate-600\">\n              {match.admin_notes ? (\n                <p>\n                  <span className=\"font-medium text-slate-700\">Nota admin:</span> {match.admin_notes}\n                </p>\n              ) : null}\n              <p className=\"text-xs text-slate-500\">ID partido · {match.id.slice(0, 8)}…</p>\n            </div>\n          ) : null}\n        </div>\n      ) : null}\n\n      {showRefutationContext || !quickReview ? (\n        <MatchCardFooter>\n          <DisputeActionButtons\n            rowId={rowId}\n            match={match}\n            isDisputed={isDisputed}\n            canValidateLegacy={canValidateLegacy}\n            onValidateAsIs={onValidateAsIs}\n            onCorrect={onCorrect}\n            onConfirm={onConfirm}\n            validatePending={validatePending}\n          />\n        </MatchCardFooter>\n      ) : null}\n    </MatchCardShell>\n  )\n\n  return shell\n}\n", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx"}}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
