INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0205',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  205,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Añadiendo un componente colapsable compartido y actualizando las tres cards para mostrar ganador, perdedor, marcador, refutador y motivo en el resumen.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import { ChevronDown } from ''lucide-react''\nimport { useState, type ReactNode } from ''react''\n\nimport { cn } from ''@/lib/utils''", "old_string": "import type { ReactNode } from ''react''\n\nimport { cn } from ''@/lib/utils''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchCardLayout.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export function StatusPill({ label, toneClass }: { label: string; toneClass: string }) {\n  return (\n    <span className={cn(''inline-flex rounded-full border px-2.5 py-0.5 text-[11px] font-semibold leading-tight'', toneClass)}>\n      {label}\n    </span>\n  )\n}\n\n/** Resumen compacto: ganador, perdedor, marcador, refutó, motivo. */\nexport function MatchOutcomeSummary({\n  winner,\n  loser,\n  score,\n  disputedBy,\n  disputeReason,\n  reasonClamp = true,\n  className,\n}: {\n  winner?: string | null\n  loser?: string | null\n  score?: string | null\n  disputedBy?: string | null\n  disputeReason?: string | null\n  reasonClamp?: boolean\n  className?: string\n}) {\n  const showDispute = Boolean(disputedBy || disputeReason)\n  const rows: { label: string; value: ReactNode }[] = []\n\n  if (winner) rows.push({ label: ''Ganador'', value: winner })\n  if (loser) rows.push({ label: ''Perdedor'', value: loser })\n  if (score && score !== ''—'') rows.push({ label: ''Marcador'', value: <span className=\"font-mono font-bold tabular-nums\">{score}</span> })\n  if (showDispute && disputedBy) rows.push({ label: ''Refutó'', value: disputedBy })\n  if (showDispute && disputeReason) {\n    rows.push({\n      label: ''Motivo'',\n      value: (\n        <span className={cn(reasonClamp && ''line-clamp-2'', ''text-pretty'')}>{disputeReason}</span>\n      ),\n    })\n  }\n\n  if (rows.length === 0) return null\n\n  return (\n    <dl\n      className={cn(\n        ''mt-3 grid gap-2 rounded-lg border border-slate-200/80 bg-slate-50/60 px-3 py-2.5 text-sm sm:grid-cols-2'',\n        className,\n      )}\n    >\n      {rows.map((row) => (\n        <div key={row.label} className={cn(''min-w-0'', row.label === ''Motivo'' && ''sm:col-span-2'')}>\n          <dt className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-400\">{row.label}</dt>\n          <dd className=\"mt-0.5 font-medium leading-snug text-slate-800\">{row.value}</dd>\n        </div>\n      ))}\n    </dl>\n  )\n}\n\nexport function MatchCardExpandable({\n  id,\n  summary,\n  details,\n  footer,\n  defaultExpanded = false,\n  expanded: expandedProp,\n  onExpandedChange,\n  toggleOpenLabel = ''Ver más detalle'',\n  toggleCloseLabel = ''Menos detalle'',\n}: {\n  id?: string\n  summary: ReactNode\n  details?: ReactNode\n  footer?: ReactNode\n  defaultExpanded?: boolean\n  expanded?: boolean\n  onExpandedChange?: (open: boolean) => void\n  toggleOpenLabel?: string\n  toggleCloseLabel?: string\n}) {\n  const [internalOpen, setInternalOpen] = useState(defaultExpanded)\n  const expanded = expandedProp ?? internalOpen\n  const setExpanded = (next: boolean) => {\n    if (expandedProp === undefined) setInternalOpen(next)\n    onExpandedChange?.(next)\n  }\n  const hasDetails = details != null\n\n  return (\n    <div id={id} className=\"min-w-0\">\n      {summary}\n\n      {hasDetails ? (\n        <>\n          <div className=\"mt-3 border-t border-slate-200/80 pt-2\">\n            <button\n              type=\"button\"\n              aria-expanded={expanded}\n              className=\"flex w-full items-center justify-center gap-1.5 rounded-lg py-2 text-xs font-semibold text-[#1F5A4C] transition-colors hover:bg-slate-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25\"\n              onClick={() => setExpanded(!expanded)}\n            >\n              <ChevronDown className={cn(''size-4 transition-transform'', expanded && ''rotate-180'')} aria-hidden />\n              {expanded ? toggleCloseLabel : toggleOpenLabel}\n            </button>\n          </div>\n          {expanded ? (\n            <div className=\"mt-3 space-y-3 border-t border-slate-200/60 pt-3\">{details}</div>\n          ) : null}\n        </>\n      ) : null}\n\n      {footer}\n    </div>\n  )\n}\n", "old_string": "export function StatusPill({ label, toneClass }: { label: string; toneClass: string }) {\n  return (\n    <span className={cn(''inline-flex rounded-full border px-2.5 py-0.5 text-[11px] font-semibold leading-tight'', toneClass)}>\n      {label}\n    </span>\n  )\n}\n", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchCardLayout.tsx"}}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0206',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  206,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\matchCardDisplay.ts", "contents": "import type { GroupPlayer, MatchRow } from ''@/types/database''\n\nexport function resolveMatchWinnerLoser(\n  match: MatchRow,\n  players: GroupPlayer[],\n): { winnerName: string | null; loserName: string | null } {\n  const playerA = players.find((p) => p.id === match.player_a_id)\n  const playerB = players.find((p) => p.id === match.player_b_id)\n  const winner = match.winner_id ? players.find((p) => p.id === match.winner_id) : null\n\n  if (!winner) return { winnerName: null, loserName: null }\n\n  const loser =\n    match.winner_id === match.player_a_id ? playerB : match.winner_id === match.player_b_id ? playerA : null\n\n  return {\n    winnerName: winner.display_name,\n    loserName: loser?.display_name ?? null,\n  }\n}\n\nexport function resolveDisputerLabel(\n  match: MatchRow,\n  players: GroupPlayer[],\n  viewerUserId?: string,\n): string | null {\n  if (!match.disputed_by) return null\n  if (viewerUserId && match.disputed_by === viewerUserId) return ''Tú''\n  const disputer = players.find((p) => p.user_id === match.disputed_by)\n  return disputer?.display_name ?? ''Jugador''\n}\n"}}, {"type": "tool_use", "name": "Read", "input": {"offset": 115, "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerMatchActionCard.tsx"}}]}}'
);

