INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0211',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  211,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"contents": "import { CheckCircle2, Pencil } from ''lucide-react''\n\nimport {\n  MatchCardExpandable,\n  MatchCardFact,\n  MatchCardFacts,\n  MatchCardFooter,\n  MatchCardHeader,\n  MatchCardShell,\n  MatchOutcomeSummary,\n  StatusPill,\n} from ''@/components/shared/MatchCardLayout''\nimport { Button } from ''@/components/ui/button''\nimport type { AdminMatchRecord } from ''@/services/admin''\nimport type { MatchStatus } from ''@/types/database''\n\nfunction formatScoreFromWinnerPerspective(match: AdminMatchRecord) {\n  if (!match.score_raw?.length) return ''—''\n  const winnerIsB = match.winner_id === match.player_b_id\n  return match.score_raw\n    .map((set) => (winnerIsB ? `${set.b}-${set.a}` : `${set.a}-${set.b}`))\n    .join('' · '')\n}\n\nfunction shortDate(iso: string | null | undefined) {\n  if (!iso) return ''—''\n  const d = new Date(iso)\n  if (Number.isNaN(d.getTime())) return ''—''\n  return new Intl.DateTimeFormat(''es'', { dateStyle: ''short'', timeStyle: ''short'' }).format(d)\n}\n\nfunction statusShortLabel(status: MatchStatus, refutedPending: boolean): string {\n  if (refutedPending) return ''Refutado · pendiente''\n  switch (status) {\n    case ''pending_score'':\n      return ''Sin marcador''\n    case ''score_submitted'':\n      return ''Confirmado''\n    case ''score_disputed'':\n      return ''En revisión''\n    case ''player_confirmed'':\n      return ''Pendiente validación''\n    case ''closed'':\n      return ''Oficial jugador''\n    case ''validated'':\n      return ''Validado admin''\n    case ''cancelled'':\n      return ''Cancelado''\n    default:\n      return status\n  }\n}\n\nfunction statusBadgeClass(status: MatchStatus, refutedPending: boolean): string {\n  if (refutedPending) return ''border-amber-300 bg-amber-50 text-amber-950''\n  switch (status) {\n    case ''score_disputed'':\n      return ''border-amber-300 bg-amber-50 text-amber-950''\n    case ''score_submitted'':\n      return ''border-blue-300 bg-blue-50 text-blue-900''\n    case ''closed'':\n      return ''border-green-300 bg-green-50 text-green-900''\n    case ''validated'':\n      return ''border-emerald-300 bg-emerald-50 text-emerald-900''\n    default:\n      return ''border-slate-300 bg-slate-50 text-slate-700''\n  }\n}\n\nfunction winnerLabel(match: AdminMatchRecord): string | null {\n  if (match.winner_id === match.player_a_id) return match.playerAName\n  if (match.winner_id === match.player_b_id) return match.playerBName\n  return null\n}\n\nfunction loserLabel(match: AdminMatchRecord): string | null {\n  if (match.winner_id === match.player_a_id) return match.playerBName\n  if (match.winner_id === match.player_b_id) return match.playerAName\n  return null\n}\n\nfunction DisputeActionButtons({\n  rowId,\n  match,\n  isDisputed,\n  canValidateLegacy,\n  onValidateAsIs,\n  onCorrect,\n  onConfirm,\n  validatePending = false,\n}: {\n  rowId: string\n  match: AdminMatchRecord\n  isDisputed: boolean\n  canValidateLegacy: boolean\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onConfirm: (match: AdminMatchRecord) => void\n  validatePending?: boolean\n}) {\n  if (isDisputed) {\n    return (\n      <div id={`${rowId}-actions`} data-name=\"dispute-row-actions\" className=\"flex flex-col gap-2 sm:flex-row sm:justify-end\">\n        <Button\n          id={`${rowId}-btn-validate`}\n          name={`validate-dispute-${match.id}`}\n          data-name=\"dispute-action-validate\"\n          size=\"sm\"\n          className=\"h-10 bg-emerald-600 text-white hover:bg-emerald-700 sm:h-9\"\n          onClick={() => onValidateAsIs?.(match)}\n          disabled={!onValidateAsIs || validatePending}\n        >\n          <CheckCircle2 className=\"size-3.5 opacity-90\" />\n          {validatePending ? ''Validando…'' : ''Validar marcador''}\n        </Button>\n        <Button\n          id={`${rowId}-btn-correct`}\n          name={`correct-dispute-${match.id}`}\n          data-name=\"dispute-action-correct\"\n          size=\"sm\"\n          variant=\"outline\"\n          className=\"h-10 sm:h-9\"\n          onClick={() => onCorrect(match)}\n          disabled={validatePending}\n        >\n          <Pencil className=\"size-3.5 opacity-80\" />\n          Corregir marcador\n        </Button>\n      </div>\n    )\n  }\n\n  return (\n    <div id={`${rowId}-actions`} data-name=\"dispute-row-actions\" className=\"flex flex-col gap-2 sm:flex-row sm:justify-end\">\n      <Button\n        id={`${rowId}-btn-validate-legacy`}\n        size=\"sm\"\n        disabled={!canValidateLegacy}\n        className=\"h-10 bg-emerald-600 text-white hover:bg-emerald-700 sm:h-9\"\n        onClick={() => onConfirm(match)}\n      >\n        <CheckCircle2 className=\"size-3.5 opacity-90\" />\n        Validar\n      </Button>\n      <Button id={`${rowId}-btn-correct-legacy`} size=\"sm\" variant=\"outline\" className=\"h-10 sm:h-9\" onClick={() => onCorrect(match)}>\n        <Pencil className=\"size-3.5 opacity-80\" />\n        Corregir\n      </Button>\n    </div>\n  )\n}\n\nexport function AdminResultReviewRow({\n  match,\n  quickReview,\n  onConfirm,\n  onCorrect,\n  onValidateAsIs,\n  validatePending = false,\n}: {\n  match: AdminMatchRecord\n  quickReview: boolean\n  onConfirm: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  validatePending?: boolean\n}) {\n  const isRefutedPending = match.status === ''pending_score'' && Boolean(match.disputed_by)\n  const isDisputed = match.status === ''score_disputed''\n  const showRefutationContext = isDisputed || isRefutedPending\n  const canValidateLegacy = match.status === ''player_confirmed'' || match.status === ''score_submitted''\n  const rowId = `admin-notifications-dispute-${match.id}`\n  const winnerPerspectiveScore = formatScoreFromWinnerPerspective(match)\n  const winnerName = winnerLabel(match)\n  const loserName = loserLabel(match)\n  const disputerName = match.disputedByLabel ?? ''No identificado''\n\n  const playersTitle = (\n    <>\n      {match.playerAName}\n      <span className=\"font-normal text-slate-400\"> vs </span>\n      {match.playerBName}\n    </>\n  )\n\n  return (\n    <MatchCardShell\n      id={rowId}\n      dataName=\"notifications-dispute-row\"\n      accent={showRefutationContext ? ''dispute'' : ''neutral''}\n    >\n      <MatchCardHeader\n        eyebrow={`${match.groupName} · ${match.tournamentName}`}\n        title={playersTitle}\n        meta={shortDate(match.disputed_at ?? match.score_submitted_at ?? match.updated_at)}\n        badge={\n          <StatusPill\n            label={statusShortLabel(match.status, isRefutedPending)}\n            toneClass={statusBadgeClass(match.status, isRefutedPending)}\n          />\n        }\n      />\n\n      <MatchCardExpandable\n        id={`${rowId}-expandable`}\n        summary={\n          <MatchOutcomeSummary\n            winner={winnerName}\n            loser={loserName}\n            score={winnerPerspectiveScore}\n            disputedBy={showRefutationContext ? disputerName : null}\n            disputeReason={showRefutationContext ? match.dispute_reason : null}\n          />\n        }\n        details={\n          quickReview ? null : (\n            <>\n              <MatchCardFacts>\n                <MatchCardFact label=\"Registró\" value={match.scoreSubmittedByLabel ?? ''—''} />\n                {isRefutedPending ? (\n                  <MatchCardFact label=\"Estado\" value=\"Volvió a pendiente / no jugado tras refutación\" />\n                ) : null}\n                {match.dispute_reason ? (\n                  <MatchCardFact label=\"Motivo completo\" value={match.dispute_reason} />\n                ) : null}\n              </MatchCardFacts>\n              {match.admin_notes ? (\n                <p className=\"text-sm leading-relaxed text-slate-600\">\n                  <span className=\"font-medium text-slate-700\">Nota admin:</span> {match.admin_notes}\n                </p>\n              ) : null}\n              <p className=\"text-xs text-slate-500\">ID partido · {match.id.slice(0, 8)}…</p>\n            </>\n          )\n        }\n        footer={\n          (isDisputed || canValidateLegacy) && !quickReview ? (\n            <MatchCardFooter>\n              <DisputeActionButtons\n                rowId={rowId}\n                match={match}\n                isDisputed={isDisputed}\n                canValidateLegacy={canValidateLegacy}\n                onValidateAsIs={onValidateAsIs}\n                onCorrect={onCorrect}\n                onConfirm={onConfirm}\n                validatePending={validatePending}\n              />\n            </MatchCardFooter>\n          ) : null\n        }\n      />\n    </MatchCardShell>\n  )\n}\n", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx"}}, {"type": "tool_use", "name": "Grep", "input": {"pattern": "PlayerRegisteredMatchCard", "glob": "**/*.{tsx,ts}"}}]}}'
);

