INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0222',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  222,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Creando componentes de feed deportivo compartidos y rediseñando la fila de admin según la especificación.\n\n[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchSportsFeed.tsx", "contents": "import {\n  AlertTriangle,\n  Ban,\n  Check,\n  CheckCircle2,\n  Clock,\n  Crown,\n  History,\n  Pencil,\n  XCircle,\n} from ''lucide-react''\nimport { useState, type ReactNode } from ''react''\n\nimport { Button } from ''@/components/ui/button''\nimport {\n  Dialog,\n  DialogContent,\n  DialogDescription,\n  DialogHeader,\n  DialogTitle,\n} from ''@/components/ui/dialog''\nimport { cn } from ''@/lib/utils''\nimport type { MatchStatus } from ''@/types/database''\nimport type { ScoreSet } from ''@/types/database''\n\nexport type MatchFeedVisualState =\n  | ''disputed''\n  | ''refuted_pending''\n  | ''pending_rival''\n  | ''official''\n  | ''validated''\n  | ''scheduled''\n  | ''cancelled''\n  | ''neutral''\n\nconst feedStateStyles: Record<\n  MatchFeedVisualState,\n  { bar: string; border: string; banner: string; icon: typeof AlertTriangle; title: string; subtitle: string }\n> = {\n  disputed: {\n    bar: ''bg-amber-500'',\n    border: ''border-amber-200/90'',\n    banner: ''border-amber-200 bg-amber-50 text-amber-950'',\n    icon: AlertTriangle,\n    title: ''Disputado'',\n    subtitle: ''Esperando revisión admin'',\n  },\n  refuted_pending: {\n    bar: ''bg-amber-500'',\n    border: ''border-amber-200/90'',\n    banner: ''border-amber-200 bg-amber-50 text-amber-950'',\n    icon: AlertTriangle,\n    title: ''Refutado'',\n    subtitle: ''Pendiente de nuevo marcador'',\n  },\n  pending_rival: {\n    bar: ''bg-sky-500'',\n    border: ''border-sky-200/90'',\n    banner: ''border-sky-200 bg-sky-50 text-sky-950'',\n    icon: Clock,\n    title: ''Pendiente'',\n    subtitle: ''Esperando confirmación del rival'',\n  },\n  official: {\n    bar: ''bg-emerald-500'',\n    border: ''border-emerald-200/90'',\n    banner: ''border-emerald-200 bg-emerald-50 text-emerald-950'',\n    icon: CheckCircle2,\n    title: ''Oficial'',\n    subtitle: ''Resultado confirmado por jugadores'',\n  },\n  validated: {\n    bar: ''bg-emerald-500'',\n    border: ''border-emerald-200/90'',\n    banner: ''border-emerald-200 bg-emerald-50 text-emerald-950'',\n    icon: CheckCircle2,\n    title: ''Validado'',\n    subtitle: ''Confirmado por administración'',\n  },\n  scheduled: {\n    bar: ''bg-slate-400'',\n    border: ''border-slate-200/90'',\n    banner: ''border-slate-200 bg-slate-50 text-slate-700'',\n    icon: Clock,\n    title: ''Programado'',\n    subtitle: ''Sin marcador registrado'',\n  },\n  cancelled: {\n    bar: ''bg-red-500'',\n    border: ''border-red-200/90'',\n    banner: ''border-red-200 bg-red-50 text-red-950'',\n    icon: Ban,\n    title: ''Cancelado'',\n    subtitle: ''Partido no disputado'',\n  },\n  neutral: {\n    bar: ''bg-slate-300'',\n    border: ''border-slate-200/90'',\n    banner: ''border-slate-200 bg-slate-50 text-slate-700'',\n    icon: Clock,\n    title: ''En seguimiento'',\n    subtitle: '''',\n  },\n}\n\nexport function resolveMatchFeedVisualState(\n  status: MatchStatus,\n  refutedPending: boolean,\n): MatchFeedVisualState {\n  if (refutedPending) return ''refuted_pending''\n  switch (status) {\n    case ''score_disputed'':\n      return ''disputed''\n    case ''score_submitted'':\n      return ''pending_rival''\n    case ''closed'':\n      return ''official''\n    case ''validated'':\n      return ''validated''\n    case ''pending_score'':\n      return ''scheduled''\n    case ''cancelled'':\n      return ''cancelled''\n    default:\n      return ''neutral''\n  }\n}\n\nexport function MatchFeedCard({\n  id,\n  dataName,\n  visualState,\n  className,\n  children,\n}: {\n  id?: string\n  dataName?: string\n  visualState: MatchFeedVisualState\n  className?: string\n  children: ReactNode\n}) {\n  const styles = feedStateStyles[visualState]\n  return (\n    <article\n      id={id}\n      data-name={dataName}\n      className={cn(\n        ''overflow-hidden rounded-xl border bg-white shadow-sm ring-1 ring-black/[0.03]'',\n        styles.border,\n        className,\n      )}\n    >\n      <div className={cn(''h-0.5 w-full'', styles.bar)} aria-hidden />\n      <div className=\"space-y-2.5 p-3\">{children}</div>\n    </article>\n  )\n}\n\nexport function MatchFeedStatusBanner({ visualState }: { visualState: MatchFeedVisualState }) {\n  const styles = feedStateStyles[visualState]\n  const Icon = styles.icon\n  return (\n    <div className={cn(''flex items-center gap-2 rounded-lg border px-2.5 py-1.5'', styles.banner)}>\n      <Icon className=\"size-3.5 shrink-0 opacity-90\" aria-hidden />\n      <div className=\"min-w-0 flex-1\">\n        <p className=\"text-[11px] font-bold uppercase leading-tight tracking-wide\">{styles.title}</p>\n        {styles.subtitle ? (\n          <p className=\"text-[10px] leading-snug opacity-85\">{styles.subtitle}</p>\n        ) : null}\n      </div>\n    </div>\n  )\n}\n\nexport function MatchFeedCompactHeader({\n  groupName,\n  tournamentName,\n  playerAName,\n  playerBName,\n  dateLabel,\n}: {\n  groupName: string\n  tournamentName: string\n  playerAName: string\n  playerBName: string\n  dateLabel?: string | null\n}) {\n  return (\n    <header className=\"space-y-0.5\">\n      <div className=\"flex items-start justify-between gap-2\">\n        <p className=\"text-sm font-semibold leading-tight text-[#102A43]\">{groupName}</p>\n        <span className=\"max-w-[45%] truncate text-[10px] leading-tight text-slate-400\" title={tournamentName}>\n          {tournamentName}\n        </span>\n      </div>\n      <h3 className=\"text-pretty text-[15px] font-bold leading-snug tracking-tight text-[#102A43]\">\n        {playerAName}\n        <span className=\"mx-1.5 font-normal text-slate-400\">vs</span>\n        {playerBName}\n      </h3>\n      {dateLabel ? <p className=\"text-[10px] text-slate-400\">{dateLabel}</p> : null}\n    </header>\n  )\n}\n\nexport function MatchFeedScoreboard({\n  playerAName,\n  playerBName,\n  sets,\n  winnerId,\n  playerAId,\n  playerBId,\n  className,\n}: {\n  playerAName: string\n  playerBName: string\n  sets: ScoreSet[] | null | undefined\n  winnerId: string | null\n  playerAId: string\n  playerBId: string\n  className?: string\n}) {\n  const winnerIsA = winnerId === playerAId\n  const winnerIsB = winnerId === playerBId\n  const scoreSets = sets ?? []\n\n  if (scoreSets.length === 0) {\n    return (\n      <div\n        className={cn(\n          ''rounded-lg border border-dashed border-slate-200 bg-slate-50/80 px-3 py-2 text-center text-xs text-slate-500'',\n          className,\n        )}\n      >\n        Sin marcador registrado\n      </div>\n    )\n  }\n\n  const renderRow = (name: string, games: number[], isWinner: boolean) => (\n    <div\n      className={cn(\n        ''grid grid-cols-[minmax(0,1fr)_auto] items-center gap-3 rounded-md px-2 py-1.5'',\n        isWinner && ''border border-emerald-200/90 bg-emerald-50/70'',\n      )}\n    >\n      <div className=\"flex min-w-0 items-center gap-1.5\">\n        {isWinner ? <Crown className=\"size-3.5 shrink-0 text-emerald-600\" aria-hidden /> : null}\n        <span\n          className={cn(\n            ''truncate text-sm leading-tight'',\n            isWinner ? ''font-bold text-emerald-900'' : ''font-medium text-slate-700'',\n          )}\n        >\n          {name}\n        </span>\n      </div>\n      <div className=\"flex items-center gap-1 font-mono text-sm font-bold tabular-nums leading-none text-[#102A43]\">\n        {games.map((g, i) => (\n          <span key={i} className=\"inline-flex items-center\">\n            {i > 0 ? <span className=\"mx-0.5 text-slate-300\">·</span> : null}\n            {g}\n          </span>\n        ))}\n      </div>\n    </div>\n  )\n\n  return (\n    <div className={cn(''space-y-1 rounded-lg border border-slate-200/80 bg-slate-50/50 p-1.5'', className)}>\n      {renderRow(\n        playerAName,\n        scoreSets.map((s) => s.a),\n        winnerIsA,\n      )}\n      {renderRow(\n        playerBName,\n        scoreSets.map((s) => s.b),\n        winnerIsB,\n      )}\n    </div>\n  )\n}\n\nexport type MatchFeedTimelineStep = {\n  kind: ''success'' | ''warning'' | ''pending'' | ''info'' | ''error''\n  text: string\n}\n\nconst timelineIcon: Record<MatchFeedTimelineStep[''kind''], typeof Check> = {\n  success: Check,\n  warning: AlertTriangle,\n  pending: Clock,\n  info: CheckCircle2,\n  error: XCircle,\n}\n\nconst timelineTone: Record<MatchFeedTimelineStep[''kind''], string> = {\n  success: ''text-emerald-600'',\n  warning: ''text-amber-600'',\n  pending: ''text-sky-600'',\n  info: ''text-slate-500'',\n  error: ''text-red-600'',\n}\n\nexport function MatchFeedWorkflowTimeline({ steps, className }: { steps: MatchFeedTimelineStep[]; className?: string }) {\n  if (steps.length === 0) return null\n\n  return (\n    <ul className={cn(''space-y-1'', className)}>\n      {steps.map((step, i) => {\n        const Icon = timelineIcon[step.kind]\n        return (\n          <li key={i} className=\"flex items-start gap-2 text-xs leading-snug text-slate-700\">\n            <Icon className={cn(''mt-0.5 size-3.5 shrink-0'', timelineTone[step.kind])} aria-hidden />\n            <span className=\"min-w-0 text-pretty\">{step.text}</span>\n          </li>\n        )\n      })}\n    </ul>\n  )\n}\n\nexport function MatchFeedActionBar({\n  children,\n  className,\n}: {\n  children: ReactNode\n  className?: string\n}) {\n  return (\n    <footer className={cn(''flex flex-col gap-2 border-t border-slate-100 pt-2.5 sm:flex-row sm:items-center sm:justify-between'', className)}>\n      {children}\n    </footer>\n  )\n}\n\nexport function MatchFeedLogDialog({\n  open,\n  onOpenChange,\n  title = ''Registro administrativo'',\n  entries,\n}: {\n  open: boolean\n  onOpenChange: (open: boolean) => void\n  title?: string\n  entries: { label: string; value: ReactNode }[]\n}) {\n  return (\n    <Dialog open={open} onOpenChange={onOpenChange}>\n      <DialogContent className=\"max-w-md\">\n        <DialogHeader>\n          <DialogTitle>{title}</DialogTitle>\n          <DialogDescription>Historial y datos de auditoría del partido.</DialogDescription>\n        </DialogHeader>\n        <dl className=\"space-y-2.5 text-sm\">\n          {entries.map((entry) => (\n            <div key={entry.label} className=\"grid gap-0.5\">\n              <dt className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-400\">{entry.label}</dt>\n              <dd className=\"font-medium leading-relaxed text-slate-800\">{entry.value}</dd>\n            </div>\n          ))}\n        </dl>\n      </DialogContent>\n    </Dialog>\n  )\n}\n\nexport function MatchFeedLogButton({ onClick, className }: { onClick: () => void; className?: string }) {\n  return (\n    <Button\n      type=\"button\"\n      variant=\"ghost\"\n      size=\"sm\"\n      className={cn(''h-8 px-2 text-xs text-slate-500 hover:text-slate-800'', className)}\n      onClick={onClick}\n    >\n      <History className=\"size-3.5 opacity-70\" />\n      Ver log\n    </Button>\n  )\n}\n\nexport function MatchFeedValidateButton({\n  id,\n  name,\n  pending,\n  disabled,\n  onClick,\n}: {\n  id?: string\n  name?: string\n  pending?: boolean\n  disabled?: boolean\n  onClick: () => void\n}) {\n  return (\n    <Button\n      id={id}\n      name={name}\n      size=\"sm\"\n      className=\"h-9 bg-emerald-600 text-white hover:bg-emerald-700\"\n      onClick={onClick}\n      disabled={disabled || pending}\n    >\n      <CheckCircle2 className=\"size-3.5 opacity-90\" />\n      {pending ? ''Validando…'' : ''Validar resultado''}\n    </Button>\n  )\n}\n\nexport function MatchFeedEditButton({\n  id,\n  name,\n  disabled,\n  onClick,\n}: {\n  id?: string\n  name?: string\n  disabled?: boolean\n  onClick: () => void\n}) {\n  return (\n    <Button id={id} name={name} size=\"sm\" variant=\"outline\" className=\"h-9\" onClick={onClick} disabled={disabled}>\n      <Pencil className=\"size-3.5 opacity-80\" />\n      Editar\n    </Button>\n  )\n}\n\nexport function MatchFeedWaitingLabel({ children }: { children: ReactNode }) {\n  return (\n    <p className=\"flex items-center gap-1.5 text-xs text-slate-500\">\n      <Clock className=\"size-3.5 shrink-0 opacity-70\" aria-hidden />\n      {children}\n    </p>\n  )\n}\n\nexport function useMatchFeedLogDialog() {\n  const [open, setOpen] = useState(false)\n  return { logOpen: open, setLogOpen: setOpen }\n}\n\nexport function shortFeedDate(iso: string | null | undefined) {\n  if (!iso) return null\n  const d = new Date(iso)\n  if (Number.isNaN(d.getTime())) return null\n  return new Intl.DateTimeFormat(''es'', { dateStyle: ''short'', timeStyle: ''short'' }).format(d)\n}\n"}}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "contents": "import {\n  MatchFeedActionBar,\n  MatchFeedCard,\n  MatchFeedCompactHeader,\n  MatchFeedEditButton,\n  MatchFeedLogButton,\n  MatchFeedLogDialog,\n  MatchFeedScoreboard,\n  MatchFeedStatusBanner,\n  MatchFeedValidateButton,\n  MatchFeedWaitingLabel,\n  MatchFeedWorkflowTimeline,\n  resolveMatchFeedVisualState,\n  shortFeedDate,\n  useMatchFeedLogDialog,\n  type MatchFeedTimelineStep,\n} from ''@/components/shared/MatchSportsFeed''\nimport type { AdminMatchRecord } from ''@/services/admin''\n\nfunction buildWorkflowSteps(match: AdminMatchRecord, isDisputed: boolean, isRefutedPending: boolean): MatchFeedTimelineStep[] {\n  const steps: MatchFeedTimelineStep[] = []\n\n  if (match.scoreSubmittedByLabel) {\n    steps.push({\n      kind: ''success'',\n      text: `Marcador enviado por ${match.scoreSubmittedByLabel}`,\n    })\n  }\n\n  const disputer = match.disputedByLabel\n  if (disputer && (isDisputed || isRefutedPending || match.dispute_reason)) {\n    steps.push({\n      kind: ''warning'',\n      text: `${disputer} refutó el resultado`,\n    })\n  }\n\n  if (match.dispute_reason && (isDisputed || isRefutedPending)) {\n    steps.push({\n      kind: ''info'',\n      text: `Motivo: ${match.dispute_reason}`,\n    })\n  }\n\n  if (isDisputed) {\n    steps.push({ kind: ''pending'', text: ''Esperando validación administrativa'' })\n  } else if (isRefutedPending) {\n    steps.push({ kind: ''pending'', text: ''Volvió a pendiente tras refutación'' })\n  } else if (match.status === ''score_submitted'') {\n    steps.push({ kind: ''pending'', text: ''Esperando confirmación del rival'' })\n  } else if (match.status === ''validated'') {\n    steps.push({ kind: ''success'', text: ''Validado por administración'' })\n  } else if (match.status === ''closed'') {\n    steps.push({ kind: ''success'', text: ''Resultado oficial entre jugadores'' })\n  }\n\n  return steps\n}\n\nfunction buildLogEntries(match: AdminMatchRecord, isRefutedPending: boolean) {\n  return [\n    { label: ''Registró'', value: match.scoreSubmittedByLabel ?? ''—'' },\n    { label: ''Refutó'', value: match.disputedByLabel ?? ''—'' },\n    { label: ''Motivo'', value: match.dispute_reason ?? ''—'' },\n    { label: ''Nota admin'', value: match.admin_notes ?? ''—'' },\n    {\n      label: ''Estado'',\n      value: isRefutedPending ? ''Refutado · pendiente de marcador'' : match.status,\n    },\n    { label: ''Enviado'', value: shortFeedDate(match.score_submitted_at) ?? ''—'' },\n    { label: ''Refutado'', value: shortFeedDate(match.disputed_at) ?? ''—'' },\n    { label: ''ID partido'', value: match.id },\n  ]\n}\n\nexport function AdminResultReviewRow({\n  match,\n  quickReview,\n  onConfirm,\n  onCorrect,\n  onValidateAsIs,\n  validatePending = false,\n}: {\n  match: AdminMatchRecord\n  quickReview: boolean\n  onConfirm: (match: AdminMatchRecord) => void\n  onCorrect: (match: AdminMatchRecord) => void\n  onValidateAsIs?: (match: AdminMatchRecord) => void\n  validatePending?: boolean\n}) {\n  const { logOpen, setLogOpen } = useMatchFeedLogDialog()\n  const isRefutedPending = match.status === ''pending_score'' && Boolean(match.disputed_by)\n  const isDisputed = match.status === ''score_disputed''\n  const isOfficial = match.status === ''closed'' || match.status === ''validated''\n  const isPendingRival = match.status === ''score_submitted''\n  const canValidateLegacy = match.status === ''player_confirmed'' || match.status === ''score_submitted''\n  const showDisputeActions = isDisputed && !quickReview\n  const showLegacyActions = canValidateLegacy && !quickReview && !isDisputed\n  const visualState = resolveMatchFeedVisualState(match.status, isRefutedPending)\n  const rowId = `admin-notifications-dispute-${match.id}`\n  const workflowSteps = buildWorkflowSteps(match, isDisputed, isRefutedPending)\n  const dateLabel = shortFeedDate(match.disputed_at ?? match.score_submitted_at ?? match.updated_at)\n\n  return (\n    <>\n      <MatchFeedCard id={rowId} dataName=\"notifications-dispute-row\" visualState={visualState}>\n        <MatchFeedStatusBanner visualState={visualState} />\n\n        <MatchFeedCompactHeader\n          groupName={match.groupName}\n          tournamentName={match.tournamentName}\n          playerAName={match.playerAName}\n          playerBName={match.playerBName}\n          dateLabel={dateLabel}\n        />\n\n        <MatchFeedScoreboard\n          playerAName={match.playerAName}\n          playerBName={match.playerBName}\n          sets={match.score_raw}\n          winnerId={match.winner_id}\n          playerAId={match.player_a_id}\n          playerBId={match.player_b_id}\n        />\n\n        <MatchFeedWorkflowTimeline steps={workflowSteps} />\n\n        {!quickReview ? (\n          <MatchFeedActionBar>\n            <MatchFeedLogButton onClick={() => setLogOpen(true)} />\n\n            <div className=\"flex flex-col gap-2 sm:flex-row sm:justify-end\">\n              {showDisputeActions ? (\n                <>\n                  <MatchFeedValidateButton\n                    id={`${rowId}-btn-validate`}\n                    name={`validate-dispute-${match.id}`}\n                    pending={validatePending}\n                    disabled={!onValidateAsIs}\n                    onClick={() => onValidateAsIs?.(match)}\n                  />\n                  <MatchFeedEditButton\n                    id={`${rowId}-btn-correct`}\n                    name={`correct-dispute-${match.id}`}\n                    disabled={validatePending}\n                    onClick={() => onCorrect(match)}\n                  />\n                </>\n              ) : null}\n\n              {showLegacyActions ? (\n                <>\n                  <MatchFeedValidateButton\n                    id={`${rowId}-btn-validate-legacy`}\n                    pending={validatePending}\n                    disabled={!canValidateLegacy}\n                    onClick={() => onConfirm(match)}\n                  />\n                  <MatchFeedEditButton\n                    id={`${rowId}-btn-correct-legacy`}\n                    onClick={() => onCorrect(match)}\n                  />\n                </>\n              ) : null}\n\n              {isPendingRival && !isDisputed ? (\n                <MatchFeedWaitingLabel>Esperando rival</MatchFeedWaitingLabel>\n              ) : null}\n\n              {isOfficial ? null : null}\n            </div>\n          </MatchFeedActionBar>\n        ) : null}\n      </MatchFeedCard>\n\n      <MatchFeedLogDialog\n        open={logOpen}\n        onOpenChange={setLogOpen}\n        entries={buildLogEntries(match, isRefutedPending)}\n      />\n    </>\n  )\n}\n"}}]}}'
);

