INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0227',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  227,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Integrando jugadores, marcador y ganador en el header y colapsando el timeline (`space-y-1`); eliminando el scoreboard duplicado.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchSportsFeed.tsx", "old_string": "import {\n  AlertTriangle,\n  Ban,\n  Check,\n  CheckCircle2,\n  Clock,\n  Crown,\n  History,\n  Pencil,\n  XCircle,\n} from ''lucide-react''", "new_string": "import {\n  AlertTriangle,\n  Ban,\n  Check,\n  CheckCircle2,\n  ChevronDown,\n  Clock,\n  Crown,\n  History,\n  Pencil,\n  XCircle,\n} from ''lucide-react''"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchSportsFeed.tsx", "old_string": "export function MatchFeedCompactHeader({\n  groupName,\n  tournamentName,\n  playerAName,\n  playerBName,\n  dateLabel,\n}: {\n  groupName: string\n  tournamentName: string\n  playerAName: string\n  playerBName: string\n  dateLabel?: string | null\n}) {\n  return (\n    <header className=\"space-y-0.5\">\n      <div className=\"flex items-start justify-between gap-2\">\n        <p className=\"text-sm font-semibold leading-tight text-[#102A43]\">{groupName}</p>\n        <span className=\"max-w-[45%] truncate text-[10px] leading-tight text-slate-400\" title={tournamentName}>\n          {tournamentName}\n        </span>\n      </div>\n      <h3 className=\"text-pretty text-[15px] font-bold leading-snug tracking-tight text-[#102A43]\">\n        {playerAName}\n        <span className=\"mx-1.5 font-normal text-slate-400\">vs</span>\n        {playerBName}\n      </h3>\n      {dateLabel ? <p className=\"text-[10px] text-slate-400\">{dateLabel}</p> : null}\n    </header>\n  )\n}", "new_string": "export function formatCompactMatchScore(sets: ScoreSet[] | null | undefined): string | null {\n  if (!sets?.length) return null\n  return sets.map((s) => `${s.a}-${s.b}`).join('' · '')\n}\n\nexport function resolveFeedWinnerName(\n  winnerId: string | null,\n  playerAId: string,\n  playerBId: string,\n  playerAName: string,\n  playerBName: string,\n): string | null {\n  if (winnerId === playerAId) return playerAName\n  if (winnerId === playerBId) return playerBName\n  return null\n}\n\nexport function MatchFeedCompactHeader({\n  groupName,\n  tournamentName,\n  playerAName,\n  playerBName,\n  dateLabel,\n  scoreLabel,\n  winnerName,\n}: {\n  groupName: string\n  tournamentName: string\n  playerAName: string\n  playerBName: string\n  dateLabel?: string | null\n  scoreLabel?: string | null\n  winnerName?: string | null\n}) {\n  return (\n    <header className=\"space-y-0.5\">\n      <div className=\"flex items-start justify-between gap-2\">\n        <p className=\"text-sm font-semibold leading-tight text-[#102A43]\">{groupName}</p>\n        <span className=\"max-w-[45%] truncate text-[10px] leading-tight text-slate-400\" title={tournamentName}>\n          {tournamentName}\n        </span>\n      </div>\n      <h3 className=\"text-pretty text-[15px] font-bold leading-snug tracking-tight text-[#102A43]\">\n        {playerAName}\n        <span className=\"mx-1.5 font-normal text-slate-400\">vs</span>\n        {playerBName}\n      </h3>\n      {scoreLabel || winnerName ? (\n        <p className=\"flex flex-wrap items-center gap-x-1.5 gap-y-0.5 text-xs leading-snug text-slate-600\">\n          {scoreLabel ? (\n            <span className=\"font-mono text-sm font-bold tabular-nums text-[#102A43]\">{scoreLabel}</span>\n          ) : (\n            <span className=\"text-slate-400\">Sin marcador</span>\n          )}\n          {winnerName ? (\n            <>\n              <span className=\"text-slate-300\" aria-hidden>\n                ·\n              </span>\n              <span className=\"inline-flex items-center gap-1\">\n                <Crown className=\"size-3 shrink-0 text-emerald-600\" aria-hidden />\n                <span>\n                  Ganó <span className=\"font-semibold text-emerald-800\">{winnerName}</span>\n                </span>\n              </span>\n            </>\n          ) : null}\n        </p>\n      ) : null}\n      {dateLabel ? <p className=\"text-[10px] text-slate-400\">{dateLabel}</p> : null}\n    </header>\n  )\n}"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchSportsFeed.tsx", "old_string": "export function MatchFeedWorkflowTimeline({ steps, className }: { steps: MatchFeedTimelineStep[]; className?: string }) {\n  if (steps.length === 0) return null\n\n  return (\n    <ul className={cn(''space-y-1'', className)}>\n      {steps.map((step, i) => {\n        const Icon = timelineIcon[step.kind]\n        return (\n          <li key={i} className=\"flex items-start gap-2 text-xs leading-snug text-slate-700\">\n            <Icon className={cn(''mt-0.5 size-3.5 shrink-0'', timelineTone[step.kind])} aria-hidden />\n            <span className=\"min-w-0 text-pretty\">{step.text}</span>\n          </li>\n        )\n      })}\n    </ul>\n  )\n}", "new_string": "export function MatchFeedWorkflowTimeline({\n  steps,\n  className,\n  collapsible = true,\n  defaultCollapsed = true,\n}: {\n  steps: MatchFeedTimelineStep[]\n  className?: string\n  collapsible?: boolean\n  defaultCollapsed?: boolean\n}) {\n  const [open, setOpen] = useState(!defaultCollapsed)\n\n  if (steps.length === 0) return null\n\n  const list = (\n    <ul className=\"space-y-1\">\n      {steps.map((step, i) => {\n        const Icon = timelineIcon[step.kind]\n        return (\n          <li key={i} className=\"flex items-start gap-2 text-xs leading-snug text-slate-700\">\n            <Icon className={cn(''mt-0.5 size-3.5 shrink-0'', timelineTone[step.kind])} aria-hidden />\n            <span className=\"min-w-0 text-pretty\">{step.text}</span>\n          </li>\n        )\n      })}\n    </ul>\n  )\n\n  if (!collapsible) {\n    return <div className={className}>{list}</div>\n  }\n\n  return (\n    <div className={className}>\n      <button\n        type=\"button\"\n        aria-expanded={open}\n        className=\"flex w-full items-center gap-1 rounded-md py-1 text-left text-[11px] font-medium text-slate-500 hover:text-slate-800 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25\"\n        onClick={() => setOpen((v) => !v)}\n      >\n        <ChevronDown className={cn(''size-3.5 transition-transform'', open && ''rotate-180'')} aria-hidden />\n        {open ? ''Ocultar historial'' : ''Ver historial''}\n      </button>\n      {open ? <div className=\"mt-1\">{list}</div> : null}\n    </div>\n  )\n}"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "old_string": "import {\n  MatchFeedActionBar,\n  MatchFeedCard,\n  MatchFeedCompactHeader,\n  MatchFeedEditButton,\n  MatchFeedLogButton,\n  MatchFeedLogDialog,\n  MatchFeedScoreboard,\n  MatchFeedStatusBanner,\n  MatchFeedValidateButton,\n  MatchFeedWaitingLabel,\n  MatchFeedWorkflowTimeline,\n  resolveMatchFeedVisualState,\n  shortFeedDate,\n  useMatchFeedLogDialog,\n  type MatchFeedTimelineStep,\n} from ''@/components/shared/MatchSportsFeed''", "new_string": "import {\n  MatchFeedActionBar,\n  MatchFeedCard,\n  MatchFeedCompactHeader,\n  MatchFeedEditButton,\n  MatchFeedLogButton,\n  MatchFeedLogDialog,\n  MatchFeedStatusBanner,\n  MatchFeedValidateButton,\n  MatchFeedWaitingLabel,\n  MatchFeedWorkflowTimeline,\n  formatCompactMatchScore,\n  resolveFeedWinnerName,\n  resolveMatchFeedVisualState,\n  shortFeedDate,\n  useMatchFeedLogDialog,\n  type MatchFeedTimelineStep,\n} from ''@/components/shared/MatchSportsFeed''"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx", "old_string": "  const dateLabel = shortFeedDate(match.disputed_at ?? match.score_submitted_at ?? match.updated_at)\n\n  return (\n    <>\n      <MatchFeedCard id={rowId} dataName=\"notifications-dispute-row\" visualState={visualState}>\n        <MatchFeedStatusBanner visualState={visualState} />\n\n        <MatchFeedCompactHeader\n          groupName={match.groupName}\n          tournamentName={match.tournamentName}\n          playerAName={match.playerAName}\n          playerBName={match.playerBName}\n          dateLabel={dateLabel}\n        />\n\n        <MatchFeedScoreboard\n          playerAName={match.playerAName}\n          playerBName={match.playerBName}\n          sets={match.score_raw}\n          winnerId={match.winner_id}\n          playerAId={match.player_a_id}\n          playerBId={match.player_b_id}\n        />\n\n        <MatchFeedWorkflowTimeline steps={workflowSteps} />", "new_string": "  const dateLabel = shortFeedDate(match.disputed_at ?? match.score_submitted_at ?? match.updated_at)\n  const scoreLabel = formatCompactMatchScore(match.score_raw)\n  const winnerName = resolveFeedWinnerName(\n    match.winner_id,\n    match.player_a_id,\n    match.player_b_id,\n    match.playerAName,\n    match.playerBName,\n  )\n\n  return (\n    <>\n      <MatchFeedCard id={rowId} dataName=\"notifications-dispute-row\" visualState={visualState}>\n        <MatchFeedStatusBanner visualState={visualState} />\n\n        <MatchFeedCompactHeader\n          groupName={match.groupName}\n          tournamentName={match.tournamentName}\n          playerAName={match.playerAName}\n          playerBName={match.playerBName}\n          dateLabel={dateLabel}\n          scoreLabel={scoreLabel}\n          winnerName={winnerName}\n        />\n\n        <MatchFeedWorkflowTimeline steps={workflowSteps} defaultCollapsed />"}}]}}'
);

