INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0235',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  235,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Creando un layout compartido para el feed del jugador y refactorizando ambas cards.\n\n[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\playerMatchFeed.ts", "contents": "import type { MatchFeedTimelineStep } from ''@/components/shared/MatchSportsFeed''\nimport { resolveDisputerLabel } from ''@/lib/matchCardDisplay''\nimport { isPendingScoreStatus } from ''@/lib/matchStatus''\nimport type { GroupPlayer, MatchGameType, MatchRow } from ''@/types/database''\n\nexport function gameTypeLabel(gt: MatchGameType | null | undefined): string {\n  if (gt === ''long_set'') return ''Set largo''\n  if (gt === ''sudden_death'') return ''Muerte súbita''\n  if (gt === ''best_of_3_short_tiebreak'') return ''2 de 3 (tie-break corto)''\n  return ''Al mejor de 3''\n}\n\nexport function resolveMatchPlayerNames(\n  match: MatchRow,\n  players: GroupPlayer[],\n): { playerAName: string; playerBName: string } {\n  const playerA = players.find((p) => p.id === match.player_a_id)\n  const playerB = players.find((p) => p.id === match.player_b_id)\n  return {\n    playerAName: playerA?.display_name ?? ''Jugador'',\n    playerBName: playerB?.display_name ?? ''Jugador'',\n  }\n}\n\nexport function resolveScoreSubmitterLabel(\n  match: MatchRow,\n  players: GroupPlayer[],\n  viewerUserId: string,\n): string | null {\n  const hasScore = Boolean(match.score_raw?.length || match.game_type === ''sudden_death'')\n  if (!hasScore) return null\n\n  if (match.score_submitted_by === viewerUserId) return ''Tú''\n  const submitter = players.find((p) => p.user_id === match.score_submitted_by)\n  if (submitter) return submitter.display_name\n\n  if (match.score_submitted_by == null) {\n    const playerA = players.find((p) => p.id === match.player_a_id)\n    return playerA?.display_name ?? null\n  }\n\n  return ''Rival''\n}\n\nexport function buildPlayerWorkflowSteps(\n  match: MatchRow,\n  players: GroupPlayer[],\n  viewerUserId: string,\n  opts?: { iSubmittedPending?: boolean },\n): MatchFeedTimelineStep[] {\n  const steps: MatchFeedTimelineStep[] = []\n  const isRefutedPending = match.status === ''pending_score'' && Boolean(match.disputed_by)\n\n  const submitter = resolveScoreSubmitterLabel(match, players, viewerUserId)\n  if (submitter) {\n    steps.push({ kind: ''success'', text: `Marcador enviado por ${submitter}` })\n  }\n\n  const disputer = resolveDisputerLabel(match, players, viewerUserId)\n  if (disputer && (match.status === ''score_disputed'' || isRefutedPending || match.disputed_by)) {\n    steps.push({ kind: ''warning'', text: `${disputer} refutó el resultado` })\n  }\n\n  if (match.status === ''score_disputed'') {\n    steps.push({ kind: ''pending'', text: ''Esperando validación administrativa'' })\n  } else if (isRefutedPending) {\n    steps.push({ kind: ''pending'', text: ''Pendiente de nuevo marcador'' })\n  } else if (match.status === ''score_submitted'') {\n    steps.push({\n      kind: ''pending'',\n      text: opts?.iSubmittedPending\n        ? ''Esperando confirmación del rival''\n        : ''Puedes refutar si no coincide con lo jugado'',\n    })\n  } else if (match.status === ''validated'') {\n    steps.push({ kind: ''success'', text: ''Validado por organización'' })\n  } else if (match.status === ''closed'') {\n    steps.push({ kind: ''success'', text: ''Resultado oficial'' })\n  } else if (match.status === ''cancelled'') {\n    steps.push({ kind: ''error'', text: ''Partido cancelado'' })\n  } else if (isPendingScoreStatus(match.status)) {\n    steps.push({ kind: ''pending'', text: ''Pendiente de marcador'' })\n  } else if (match.status === ''player_confirmed'') {\n    steps.push({ kind: ''pending'', text: ''Pendiente de cierre por organización'' })\n  }\n\n  return steps\n}\n\nexport function buildPlayerLogEntries(\n  match: MatchRow,\n  players: GroupPlayer[],\n  viewerUserId: string,\n  extras?: { outcome?: string | null; impact?: string | null },\n) {\n  const submitter = resolveScoreSubmitterLabel(match, players, viewerUserId)\n  const disputer = resolveDisputerLabel(match, players, viewerUserId)\n  return [\n    { label: ''Registró'', value: submitter ?? ''—'' },\n    { label: ''Refutó'', value: disputer ?? ''—'' },\n    { label: ''Motivo'', value: match.dispute_reason ?? ''—'' },\n    { label: ''Estado'', value: match.status },\n    ...(extras?.outcome ? [{ label: ''Resultado'', value: extras.outcome }] : []),\n    ...(extras?.impact ? [{ label: ''Impacto'', value: extras.impact }] : []),\n    { label: ''ID partido'', value: match.id },\n  ]\n}\n"}}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerMatchFeedLayout.tsx", "contents": "import type { ReactNode } from ''react''\n\nimport { MatchScoreTimeline } from ''@/components/player/MatchScoreTimeline''\nimport {\n  MatchFeedActionBar,\n  MatchFeedCard,\n  MatchFeedCompactHeader,\n  MatchFeedLogButton,\n  MatchFeedLogDialog,\n  MatchFeedStatusBanner,\n  MatchFeedWorkflowTimeline,\n  formatCompactMatchScore,\n  resolveFeedWinnerName,\n  resolveMatchFeedVisualState,\n  shortFeedDate,\n  useMatchFeedLogDialog,\n  type MatchFeedTimelineStep,\n} from ''@/components/shared/MatchSportsFeed''\nimport { buildPlayerLogEntries, buildPlayerWorkflowSteps, resolveMatchPlayerNames } from ''@/lib/playerMatchFeed''\nimport { cn } from ''@/lib/utils''\nimport type { GroupPlayer, MatchRow } from ''@/types/database''\n\nexport function PlayerMatchFeedLayout({\n  match,\n  players,\n  userId,\n  groupName,\n  metaLabel,\n  footer,\n  workflowSteps: workflowStepsProp,\n  logEntries: logEntriesProp,\n  showLog = true,\n  showScoreTimelineInLog = true,\n  iSubmittedPending,\n  className,\n  id,\n}: {\n  match: MatchRow\n  players: GroupPlayer[]\n  userId: string\n  groupName: string\n  metaLabel: string\n  footer?: ReactNode\n  workflowSteps?: MatchFeedTimelineStep[]\n  logEntries?: { label: string; value: ReactNode }[]\n  showLog?: boolean\n  showScoreTimelineInLog?: boolean\n  iSubmittedPending?: boolean\n  className?: string\n  id?: string\n}) {\n  const { logOpen, setLogOpen } = useMatchFeedLogDialog()\n  const isRefutedPending = match.status === ''pending_score'' && Boolean(match.disputed_by)\n  const visualState = resolveMatchFeedVisualState(match.status, isRefutedPending)\n  const { playerAName, playerBName } = resolveMatchPlayerNames(match, players)\n  const scoreLabel = formatCompactMatchScore(match.score_raw)\n  const winnerName = resolveFeedWinnerName(\n    match.winner_id,\n    match.player_a_id,\n    match.player_b_id,\n    playerAName,\n    playerBName,\n  )\n  const dateLabel = shortFeedDate(match.disputed_at ?? match.score_submitted_at ?? match.updated_at)\n  const workflowSteps =\n    workflowStepsProp ?? buildPlayerWorkflowSteps(match, players, userId, { iSubmittedPending })\n  const logEntries = logEntriesProp ?? buildPlayerLogEntries(match, players, userId)\n\n  return (\n    <>\n      <MatchFeedCard id={id} visualState={visualState} className={cn(className)}>\n        <MatchFeedStatusBanner visualState={visualState} />\n\n        <MatchFeedCompactHeader\n          groupName={groupName}\n          tournamentName={metaLabel}\n          playerAName={playerAName}\n          playerBName={playerBName}\n          dateLabel={dateLabel}\n          scoreLabel={scoreLabel}\n          winnerName={winnerName}\n        />\n\n        {workflowSteps.length > 0 ? (\n          <MatchFeedWorkflowTimeline steps={workflowSteps} defaultCollapsed />\n        ) : null}\n\n        {footer || showLog ? (\n          <MatchFeedActionBar>\n            {showLog ? <MatchFeedLogButton onClick={() => setLogOpen(true)} /> : <span />}\n            {footer ? <div className=\"flex flex-col gap-2 sm:flex-row sm:justify-end\">{footer}</div> : null}\n          </MatchFeedActionBar>\n        ) : null}\n      </MatchFeedCard>\n\n      {showLog ? (\n        <MatchFeedLogDialog open={logOpen} onOpenChange={setLogOpen} entries={logEntries}>\n          {showScoreTimelineInLog ? (\n            <div className=\"mt-4 border-t border-slate-100 pt-3\">\n              <p className=\"mb-2 text-[10px] font-semibold uppercase tracking-wide text-slate-400\">\n                Historial de cambios\n              </p>\n              <MatchScoreTimeline matchId={match.id} />\n            </div>\n          ) : null}\n        </MatchFeedLogDialog>\n      ) : null}\n    </>\n  )\n}\n"}}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0236',
