  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export function MatchFeedLogDialog({\n  open,\n  onOpenChange,\n  title = ''Registro administrativo'',\n  entries,\n  children,\n}: {\n  open: boolean\n  onOpenChange: (open: boolean) => void\n  title?: string\n  entries: { label: string; value: ReactNode }[]\n  children?: ReactNode\n}) {\n  return (\n    <Dialog open={open} onOpenChange={onOpenChange}>\n      <DialogContent className=\"max-w-md\">\n        <DialogHeader>\n          <DialogTitle>{title}</DialogTitle>\n          <DialogDescription>Historial y datos de auditoría del partido.</DialogDescription>\n        </DialogHeader>\n        <dl className=\"space-y-2.5 text-sm\">\n          {entries.map((entry) => (\n            <div key={entry.label} className=\"grid gap-0.5\">\n              <dt className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-400\">{entry.label}</dt>\n              <dd className=\"font-medium leading-relaxed text-slate-800\">{entry.value}</dd>\n            </div>\n          ))}\n        </dl>\n        {children}\n      </DialogContent>\n    </Dialog>\n  )\n}", "old_string": "export function MatchFeedLogDialog({\n  open,\n  onOpenChange,\n  title = ''Registro administrativo'',\n  entries,\n}: {\n  open: boolean\n  onOpenChange: (open: boolean) => void\n  title?: string\n  entries: { label: string; value: ReactNode }[]\n}) {\n  return (\n    <Dialog open={open} onOpenChange={onOpenChange}>\n      <DialogContent className=\"max-w-md\">\n        <DialogHeader>\n          <DialogTitle>{title}</DialogTitle>\n          <DialogDescription>Historial y datos de auditoría del partido.</DialogDescription>\n        </DialogHeader>\n        <dl className=\"space-y-2.5 text-sm\">\n          {entries.map((entry) => (\n            <div key={entry.label} className=\"grid gap-0.5\">\n              <dt className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-400\">{entry.label}</dt>\n              <dd className=\"font-medium leading-relaxed text-slate-800\">{entry.value}</dd>\n            </div>\n          ))}\n        </dl>\n      </DialogContent>\n    </Dialog>\n  )\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchSportsFeed.tsx"}}, {"type": "tool_use", "name": "Write", "input": {"contents": "import { useCallback, useRef, useState } from ''react''\nimport { useQueryClient } from ''@tanstack/react-query''\nimport { toast } from ''sonner''\n\nimport { ScoreSubmissionModal } from ''@/components/matches/ScoreSubmissionModal''\nimport { PlayerMatchFeedLayout } from ''@/components/player/PlayerMatchFeedLayout''\nimport { Button } from ''@/components/ui/button''\nimport {\n  Dialog,\n  DialogContent,\n  DialogDescription,\n  DialogFooter,\n  DialogHeader,\n  DialogTitle,\n} from ''@/components/ui/dialog''\nimport { Textarea } from ''@/components/ui/textarea''\nimport { gameTypeLabel } from ''@/lib/playerMatchFeed''\nimport {\n  canRejectScore,\n  canSubmitScore,\n  isMatchPlayerA,\n} from ''@/lib/matchStatus''\nimport {\n  mergeMatchAfterPlayerSubmit,\n  patchPlayerViewModelAfterOpponentReject,\n  patchPlayerViewModelMatches,\n} from ''@/lib/playerDashboardMatchCache''\nimport {\n  PLAYER_SCORE_DISPUTE_REASON_MAX_LENGTH,\n  validatePlayerScoreDisputeReason,\n} from ''@/lib/playerScoreDispute''\nimport {\n  preparePlayerScoreSubmissionSync,\n  rejectPlayerScore,\n  submitPlayerScore,\n} from ''@/services/matches''\nimport type { PlayerViewModel } from ''@/services/playerViewModel''\nimport type { GroupPlayer, MatchRow, TournamentRules } from ''@/types/database''\n\nexport function PlayerMatchActionCard({\n  match,\n  players,\n  rules,\n  myGroupPlayerId,\n  userId,\n  groupName,\n  onAfterMatchMutation,\n  className,\n}: {\n  match: MatchRow\n  players: GroupPlayer[]\n  rules: TournamentRules\n  myGroupPlayerId: string\n  userId: string\n  groupName: string\n  onAfterMatchMutation: (payload: { match: MatchRow }) => void\n  className?: string\n}) {\n  const qc = useQueryClient()\n  const [scoreOpen, setScoreOpen] = useState(false)\n  const [rejectOpen, setRejectOpen] = useState(false)\n  const [rejectReason, setRejectReason] = useState('''')\n  const [busy, setBusy] = useState(false)\n  const submitInFlightRef = useRef(false)\n  const rejectInFlightRef = useRef(false)\n\n  const canSubmit = rules.allow_player_score_entry && canSubmitScore(match, userId)\n  const canReject = rules.allow_player_score_entry && canRejectScore(match, userId)\n\n  const iSubmittedPending =\n    match.status === ''score_submitted'' &&\n    (match.score_submitted_by === userId ||\n      (match.score_submitted_by == null && isMatchPlayerA(match, userId)))\n\n  const handleReject = useCallback(async () => {\n    if (rejectInFlightRef.current) return\n    const parsed = validatePlayerScoreDisputeReason(rejectReason)\n    if (!parsed.ok) {\n      toast.error(parsed.message)\n      return\n    }\n    rejectInFlightRef.current = true\n    setBusy(true)\n    try {\n      const serverMatch = await rejectPlayerScore({ matchId: match.id, disputeReason: parsed.reason })\n      const merged = patchPlayerViewModelAfterOpponentReject(qc, userId, serverMatch ?? match, parsed.reason)\n      void qc.invalidateQueries({ queryKey: [''admin-disputed-results''] })\n      void qc.invalidateQueries({ queryKey: [''admin-results''] })\n      void qc.invalidateQueries({ queryKey: [''admin-matches''] })\n      void qc.invalidateQueries({ queryKey: [''admin-overview''] })\n      toast.message(''Resultado refutado'', {\n        description: ''Organización revisará el marcador.'',\n      })\n      setRejectOpen(false)\n      setRejectReason('''')\n      onAfterMatchMutation({ match: merged })\n    } catch (error) {\n      toast.error(error instanceof Error ? error.message : ''No se pudo refutar el marcador'')\n    } finally {\n      rejectInFlightRef.current = false\n      setBusy(false)\n    }\n  }, [rejectReason, match, userId, qc, onAfterMatchMutation])\n\n  const actionFooter =\n    canSubmit || canReject ? (\n      <>\n        {canSubmit ? (\n          <Button className=\"h-9 w-full sm:w-auto\" onClick={() => setScoreOpen(true)}>\n            {match.status === ''score_disputed'' ? ''Corregir y reenviar'' : ''Registrar marcador''}\n          </Button>\n        ) : null}\n        {canReject ? (\n          <Button className=\"h-9 w-full sm:w-auto\" variant=\"outline\" disabled={busy} onClick={() => setRejectOpen(true)}>\n            Refutar\n          </Button>\n        ) : null}\n      </>\n    ) : undefined\n\n  return (\n    <>\n      <PlayerMatchFeedLayout\n        match={match}\n        players={players}\n        userId={userId}\n        groupName={groupName}\n        metaLabel={gameTypeLabel(match.game_type)}\n        iSubmittedPending={iSubmittedPending}\n        footer={actionFooter}\n        className={className}\n        id={`player-match-action-${match.id}`}\n      />\n\n      <ScoreSubmissionModal\n        open={scoreOpen}\n        onOpenChange={setScoreOpen}\n        match={match}\n        players={players}\n        viewerGroupPlayerId={myGroupPlayerId}\n        rules={rules}\n        submitting={busy}\n        submitLabel=\"Enviar marcador\"\n        onSubmit={async (scorePayload) => {\n          if (submitInFlightRef.current) return\n          submitInFlightRef.current = true\n          setBusy(true)\n          try {\n            const prepared = preparePlayerScoreSubmissionSync({ match, scorePayload, rules })\n            const serverRow = await submitPlayerScore({ match, scorePayload, actorUserId: userId, rules })\n            const merged = serverRow ?? mergeMatchAfterPlayerSubmit(match, prepared, userId)\n            qc.setQueryData<PlayerViewModel | null>([''playerViewModel'', userId, match.group_id], (old) =>\n              patchPlayerViewModelMatches(old, userId, match.id, merged),\n            )\n            toast.success(\n              match.status === ''score_disputed''\n                ? ''Marcador reenviado''\n                : ''Marcador registrado · ya cuenta como oficial en la tabla.'',\n            )\n            setScoreOpen(false)\n            onAfterMatchMutation({ match: merged })\n          } catch (error) {\n            toast.error(error instanceof Error ? error.message : ''No se pudo enviar el marcador'')\n          } finally {\n            submitInFlightRef.current = false\n            setBusy(false)\n          }\n        }}\n      />\n\n      <Dialog\n        open={rejectOpen}\n        onOpenChange={(open) => {\n          if (!open && busy) return\n          setRejectOpen(open)\n          if (!open) setRejectReason('''')\n        }}\n      >\n        <DialogContent\n          showCloseButton={!busy}\n          className=\"flex max-h-[min(100dvh-1rem,32rem)] w-[min(100vw-1rem,28rem)] flex-col gap-0 overflow-hidden p-0 sm:max-w-md\"\n        >\n          <DialogHeader className=\"shrink-0 space-y-2 px-4 pb-2 pt-5 pr-12\">\n            <DialogTitle className=\"text-base\">Refutar resultado</DialogTitle>\n            <DialogDescription className=\"text-xs leading-relaxed sm:text-sm\">\n              Explica el motivo; organización revisará y definirá el marcador oficial.\n            </DialogDescription>\n          </DialogHeader>\n          <div className=\"min-h-0 flex-1 overflow-y-auto px-4 pb-2\">\n            <Textarea\n              value={rejectReason}\n              onChange={(event) => setRejectReason(event.target.value)}\n              placeholder=\"Ej.: Los sets no coinciden con lo jugado…\"\n              maxLength={PLAYER_SCORE_DISPUTE_REASON_MAX_LENGTH}\n              className=\"min-h-28 text-base sm:text-sm\"\n              aria-label=\"Motivo de la refutación\"\n              aria-invalid={\n                rejectReason.trim().length > 0 && !validatePlayerScoreDisputeReason(rejectReason).ok\n              }\n            />\n          </div>\n          <DialogFooter className=\"shrink-0 flex-col-reverse gap-2 border-t bg-background/95 px-4 py-3 backdrop-blur-sm pb-[max(0.75rem,env(safe-area-inset-bottom))] sm:flex-row sm:justify-end\">\n            <Button variant=\"outline\" className=\"min-h-11 w-full sm:w-auto\" disabled={busy} onClick={() => setRejectOpen(false)}>\n              Cancelar\n            </Button>\n            <Button\n              variant=\"destructive\"\n              className=\"min-h-11 w-full sm:w-auto\"\n              disabled={\n                busy ||\n                rejectReason.trim().length < 3 ||\n                rejectReason.trim().length > PLAYER_SCORE_DISPUTE_REASON_MAX_LENGTH\n              }\n              onClick={() => void handleReject()}\n            >\n              Enviar refutación\n            </Button>\n          </DialogFooter>\n        </DialogContent>\n      </Dialog>\n    </>\n  )\n}\n", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerMatchActionCard.tsx"}}, {"type": "tool_use", "name": "Write", "input": {"contents": "import { Button } from ''@/components/ui/button''\nimport { PlayerMatchFeedLayout } from ''@/components/player/PlayerMatchFeedLayout''\nimport {\n  calculateMatchGamesDifference,\n  getMatchOutcome,\n  getPointsForPlayerInMatch,\n} from ''@/lib/playerDashboard''\nimport { buildPlayerLogEntries, gameTypeLabel } from ''@/lib/playerMatchFeed''\nimport {\n  importResultTypeBothPenalized,\n  importResultTypeUsesDefaultPoints,\n} from ''@/lib/matchResultSemantics''\nimport type { GroupPlayer, MatchResultType, MatchRow, TournamentRules } from ''@/types/database''\n\nfunction outcomeLine(match: MatchRow, myGroupPlayerId: string, resultType: MatchResultType | null): string {\n  if (importResultTypeBothPenalized(match.result_type)) return ''No reportado · penalización''\n  if (match.winner_id == null) return ''—''\n  const walkoverLike = importResultTypeUsesDefaultPoints(resultType)\n  const w = getMatchOutcome(match, myGroupPlayerId)\n  if (walkoverLike) {\n    if (w === ''win'') return ''Ganaste (W.O./DEF)''\n    if (w === ''loss'') return ''Perdiste (W.O./DEF)''\n  }\n  if (resultType === ''retired'') {\n    if (w === ''win'') return ''Ganaste (retiro)''\n    if (w === ''loss'') return ''Perdiste (retiro)''\n  }\n  if (w === ''win'') return ''Ganaste''\n  if (w === ''loss'') return ''Perdiste''\n  return ''—''\n}\n\nfunction signed(n: number) {\n  if (n > 0) return `+${n}`\n  return String(n)\n}\n\nfunction pointsPhrase(points: number) {\n  const sign = points >= 0 ? ''+'' : ''''\n  return `${sign}${points} ${Math.abs(points) === 1 ? ''pt'' : ''pts''}`\n}\n\nexport function PlayerRegisteredMatchCard({\n  match,\n  groupName,\n  myGroupPlayerId,\n  players,\n  rules,\n  viewerUserId,\n  onRefute,\n}: {\n  match: MatchRow\n  groupName: string\n  myGroupPlayerId: string\n  players: GroupPlayer[]\n  rules: TournamentRules\n  viewerUserId: string\n  onRefute?: () => void\n}) {\n  const officialCounted =\n    (match.status === ''closed'' || match.status === ''validated'') && match.winner_id != null\n  const pts = officialCounted ? getPointsForPlayerInMatch(match, myGroupPlayerId, rules) : null\n  const gamesDiff = officialCounted ? calculateMatchGamesDifference(myGroupPlayerId, match) : null\n  const outcome = officialCounted ? outcomeLine(match, myGroupPlayerId, match.result_type) : null\n  const impact =\n    pts != null && gamesDiff != null ? `${pointsPhrase(pts)} · Juegos ${signed(gamesDiff)}` : null\n\n  const logEntries = buildPlayerLogEntries(match, players, viewerUserId, {\n    outcome,\n    impact,\n  })\n\n  const refuteFooter = onRefute ? (\n    <Button type=\"button\" variant=\"outline\" className=\"h-9 w-full sm:w-auto\" onClick={onRefute}>\n      Refutar resultado\n    </Button>\n  ) : undefined\n\n  return (\n    <PlayerMatchFeedLayout\n      match={match}\n      players={players}\n      userId={viewerUserId}\n      groupName={groupName}\n      metaLabel={gameTypeLabel(match.game_type)}\n      logEntries={logEntries}\n      footer={refuteFooter}\n      id={`player-match-registered-${match.id}`}\n    />\n  )\n}\n", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerRegisteredMatchCard.tsx"}}]}}'
);

