INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0269',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  269,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Rediseñé el modal **Editar marcador** en `/admin/notifications`. Cambios principales:\n\n### Diseño optimizado\n\n1. **Contexto de disputa** — Banner ámbar arriba con marcador actual (vista ganador), motivo de refutación, quién envió y quién refutó.\n\n2. **Scoreboard compacto** — Tabla tipo app deportiva:\n   - Cabecera con nombres de jugadores\n   - Una fila por set (`S1`, `S2`, `STB`…)\n   - Inputs grandes centrados con separador `-`\n   - Botón `-` para quitar set\n\n3. **Menos altura** — Eliminadas las cards pesadas por set y textos repetitivos.\n\n4. **Nota admin colapsable** — Oculta por defecto; se expande solo si hace falta.\n\n5. **Footer fijo** — Acciones siempre visibles abajo:\n   - `Cancelar`\n   - `Validar resultado` (verde, con icono) en disputas\n   - Sin botón “Guardar borrador” en disputas (solo validar)\n\n6. **Scroll interno** — El cuerpo hace scroll; header y footer quedan estables en pantallas pequeñas.\n\nEl modal sigue funcionando en otras rutas admin (Partidos/Resultados) con el layout mejorado; en notificaciones el título y descripción están adaptados al flujo de disputas.\n\n[REDACTED]"}]}}'
);

