INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0279',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  279,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "La RPC en producción no acepta `p_status: ''validated''` (migración 042 no aplicada). Usaremos `''closed''`, que es compatible y en 042+ se mapea a `validated`.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "/**\n * Destino de estado al guardar como admin.\n * Desde disputa: `explicit === ''score_disputed''` guarda borrador (sigue en revisión); cerrar valida.\n * Enviamos `closed` al RPC: migración 042+ lo convierte en `validated`; en DB anteriores queda `closed` (oficial).\n */\nexport function inferAdminSaveTargetStatus(match: MatchRow, explicit?: MatchStatus): MatchStatus {\n  if (explicit === ''cancelled'') return ''cancelled''\n  if (match.status === ''score_disputed'') {\n    if (explicit === ''score_disputed'') return ''score_disputed''\n    return ''closed''\n  }", "old_string": "/**\n * Destino de estado al guardar como admin.\n * Desde disputa: `explicit === ''score_disputed''` guarda borrador (sigue en revisión); cerrar valida (`validated`).\n */\nexport function inferAdminSaveTargetStatus(match: MatchRow, explicit?: MatchStatus): MatchStatus {\n  if (explicit === ''cancelled'') return ''cancelled''\n  if (match.status === ''score_disputed'') {\n    if (explicit === ''score_disputed'') return ''score_disputed''\n    return ''validated''\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\matches.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  const { error } = await supabase.rpc(''admin_set_match_result'', {\n    p_match_id: fresh.id,\n    p_score: (fresh.score_raw ?? []) as unknown as Json,\n    p_winner_id: fresh.winner_id,\n    p_status: ''closed'',\n    p_result_type: fresh.result_type ?? ''normal'',\n    p_game_type: fresh.game_type ?? ''best_of_3'',\n  })", "old_string": "  const { error } = await supabase.rpc(''admin_set_match_result'', {\n    p_match_id: fresh.id,\n    p_score: (fresh.score_raw ?? []) as unknown as Json,\n    p_winner_id: fresh.winner_id,\n    p_status: ''validated'',\n    p_result_type: fresh.result_type ?? ''normal'',\n    p_game_type: fresh.game_type ?? ''best_of_3'',\n  })", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\matches.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  const { error } = await supabase.rpc(''admin_set_match_result'', {\n    p_match_id: fresh.id,\n    p_score: pScoreJson,\n    p_winner_id: winnerId,\n    p_status: ''closed'',\n    p_result_type: fresh.result_type ?? ''normal'',\n    p_game_type: payload.game_type ?? fresh.game_type ?? ''best_of_3'',\n  })", "old_string": "  const { error } = await supabase.rpc(''admin_set_match_result'', {\n    p_match_id: fresh.id,\n    p_score: pScoreJson,\n    p_winner_id: winnerId,\n    p_status: ''validated'',\n    p_result_type: fresh.result_type ?? ''normal'',\n    p_game_type: payload.game_type ?? fresh.game_type ?? ''best_of_3'',\n  })", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\matches.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  it(''valida disputa vía admin_set_match_result → closed (RPC 042+ lo mapea a validated)'', async () => {\n    const match = disputedMatch()\n    await adminValidateDisputedWithoutChanges(match)\n\n    expect(singleMock).toHaveBeenCalledOnce()\n    expect(rpcMock).toHaveBeenCalledOnce()\n    expect(rpcMock).toHaveBeenCalledWith(''admin_set_match_result'', {\n      p_match_id: ''match-1'',\n      p_score: [{ a: 6, b: 4 }],\n      p_winner_id: ''player-a-gp'',\n      p_status: ''closed'',\n      p_result_type: ''normal'',\n      p_game_type: ''best_of_3'',\n    })\n  })", "old_string": "  it(''valida disputa vía admin_set_match_result → validated'', async () => {\n    const match = disputedMatch()\n    await adminValidateDisputedWithoutChanges(match)\n\n    expect(singleMock).toHaveBeenCalledOnce()\n    expect(rpcMock).toHaveBeenCalledOnce()\n    expect(rpcMock).toHaveBeenCalledWith(''admin_set_match_result'', {\n      p_match_id: ''match-1'',\n      p_score: [{ a: 6, b: 4 }],\n      p_winner_id: ''player-a-gp'',\n      p_status: ''validated'',\n      p_result_type: ''normal'',\n      p_game_type: ''best_of_3'',\n    })\n  })", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\matches.adminValidate.test.ts"}}]}}'
);

