INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0281',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  281,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "**Causa:** El cliente enviaba `p_status: ''validated''` a `admin_set_match_result`, pero en tu Supabase remoto la función RPC aún no incluye `''validated''` en los estados permitidos (eso llega con la migración **042**). La base respondía con `Estado inválido` (400).\n\n**Fix:** Al validar o corregir una disputa, ahora se envía `p_status: ''closed''`, que:\n\n- En DB **sin** migración 042 → queda `closed` (oficial, cuenta para ranking)\n- En DB **con** migración 042 → el RPC lo convierte automáticamente a `validated`\n\nCambios en `src/services/matches.ts` (`adminValidateDisputedWithoutChanges`, `adminCorrectDisputedMatch`, `inferAdminSaveTargetStatus`).\n\nPrueba de nuevo **Validar resultado** en `/admin/notifications`. Si quieres el estado `validated` explícito en producción, aplica las migraciones pendientes (`042` en adelante) con `supabase db push` o tu flujo habitual.\n\n[REDACTED]"}]}}'
);

