INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0288',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  288,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export type MatchFeedLogEntry = {\n  label: string\n  value: ReactNode\n  multiline?: boolean\n}\n\nexport function MatchFeedLogDialog({\n  open,\n  onOpenChange,\n  title = ''Registro administrativo'',\n  entries,\n  children,\n}: {\n  open: boolean\n  onOpenChange: (open: boolean) => void\n  title?: string\n  entries: MatchFeedLogEntry[]\n  children?: ReactNode\n}) {\n  return (\n    <Dialog open={open} onOpenChange={onOpenChange}>\n      <DialogContent className=\"max-w-md\">\n        <DialogHeader>\n          <DialogTitle>{title}</DialogTitle>\n          <DialogDescription>Historial y datos de auditoría del partido.</DialogDescription>\n        </DialogHeader>\n        <dl className=\"space-y-2.5 text-sm\">\n          {entries.map((entry) => (\n            <div key={entry.label} className=\"grid gap-0.5\">\n              <dt className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-400\">{entry.label}</dt>\n              <dd\n                className={cn(\n                  ''font-medium leading-relaxed text-slate-800'',\n                  entry.multiline && ''whitespace-pre-wrap text-pretty'',\n                )}\n              >\n                {entry.value}\n              </dd>\n            </div>\n          ))}\n        </dl>\n        {children}\n      </DialogContent>\n    </Dialog>\n  )\n}", "old_string": "export function MatchFeedLogDialog({\n  open,\n  onOpenChange,\n  title = ''Registro administrativo'',\n  entries,\n  children,\n}: {\n  open: boolean\n  onOpenChange: (open: boolean) => void\n  title?: string\n  entries: { label: string; value: ReactNode }[]\n  children?: ReactNode\n}) {\n  return (\n    <Dialog open={open} onOpenChange={onOpenChange}>\n      <DialogContent className=\"max-w-md\">\n        <DialogHeader>\n          <DialogTitle>{title}</DialogTitle>\n          <DialogDescription>Historial y datos de auditoría del partido.</DialogDescription>\n        </DialogHeader>\n        <dl className=\"space-y-2.5 text-sm\">\n          {entries.map((entry) => (\n            <div key={entry.label} className=\"grid gap-0.5\">\n              <dt className=\"text-[10px] font-semibold uppercase tracking-wide text-slate-400\">{entry.label}</dt>\n              <dd className=\"font-medium leading-relaxed text-slate-800\">{entry.value}</dd>\n            </div>\n          ))}\n        </dl>\n        {children}\n      </DialogContent>\n    </Dialog>\n  )\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\shared\\MatchSportsFeed.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import type { MatchFeedLogEntry, MatchFeedTimelineStep } from ''@/components/shared/MatchSportsFeed''", "old_string": "import type { MatchFeedTimelineStep } from ''@/components/shared/MatchSportsFeed''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\playerMatchFeed.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export function adminNotesLogEntry(adminNotes: string | null | undefined): MatchFeedLogEntry {\n  const text = adminNotes?.trim()\n  return {\n    label: ''Notas de admin'',\n    value: text || ''—'',\n    multiline: Boolean(text),\n  }\n}\n\nexport function buildPlayerLogEntries(\n  match: MatchRow,\n  players: GroupPlayer[],\n  viewerUserId: string,\n  extras?: { outcome?: string | null; impact?: string | null },\n): MatchFeedLogEntry[] {\n  const submitter = resolveScoreSubmitterLabel(match, players, viewerUserId)\n  const disputer = resolveDisputerLabel(match, players, viewerUserId)\n  return [\n    { label: ''Registró'', value: submitter ?? ''—'' },\n    { label: ''Refutó'', value: disputer ?? ''—'' },\n    { label: ''Motivo refutación'', value: match.dispute_reason?.trim() || ''—'', multiline: Boolean(match.dispute_reason?.trim()) },\n    adminNotesLogEntry(match.admin_notes),\n    { label: ''Estado'', value: match.status },\n    ...(extras?.outcome ? [{ label: ''Resultado'', value: extras.outcome }] : []),\n    ...(extras?.impact ? [{ label: ''Impacto'', value: extras.impact }] : []),\n    { label: ''ID partido'', value: match.id },\n  ]\n}", "old_string": "export function buildPlayerLogEntries(\n  match: MatchRow,\n  players: GroupPlayer[],\n  viewerUserId: string,\n  extras?: { outcome?: string | null; impact?: string | null },\n) {\n  const submitter = resolveScoreSubmitterLabel(match, players, viewerUserId)\n  const disputer = resolveDisputerLabel(match, players, viewerUserId)\n  return [\n    { label: ''Registró'', value: submitter ?? ''—'' },\n    { label: ''Refutó'', value: disputer ?? ''—'' },\n    { label: ''Motivo'', value: match.dispute_reason ?? ''—'' },\n    { label: ''Estado'', value: match.status },\n    ...(extras?.outcome ? [{ label: ''Resultado'', value: extras.outcome }] : []),\n    ...(extras?.impact ? [{ label: ''Impacto'', value: extras.impact }] : []),\n    { label: ''ID partido'', value: match.id },\n  ]\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\playerMatchFeed.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  type MatchFeedTimelineStep,\n  type MatchFeedLogEntry,\n} from ''@/components/shared/MatchSportsFeed''\nimport { adminNotesLogEntry } from ''@/lib/playerMatchFeed''", "old_string": "  type MatchFeedTimelineStep,\n} from ''@/components/shared/MatchSportsFeed''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "function buildLogEntries(match: AdminMatchRecord, isRefutedPending: boolean): MatchFeedLogEntry[] {\n  return [\n    { label: ''Registró'', value: match.scoreSubmittedByLabel ?? ''—'' },\n    { label: ''Refutó'', value: match.disputedByLabel ?? ''—'' },\n    {\n      label: ''Motivo refutación'',\n      value: match.dispute_reason?.trim() || ''—'',\n      multiline: Boolean(match.dispute_reason?.trim()),\n    },\n    adminNotesLogEntry(match.admin_notes),\n    {\n      label: ''Estado'',\n      value: isRefutedPending ? ''Refutado · pendiente de marcador'' : match.status,\n    },\n    { label: ''Enviado'', value: shortFeedDate(match.score_submitted_at) ?? ''—'' },\n    { label: ''Refutado'', value: shortFeedDate(match.disputed_at) ?? ''—'' },\n    { label: ''ID partido'', value: match.id },\n  ]\n}", "old_string": "function buildLogEntries(match: AdminMatchRecord, isRefutedPending: boolean) {\n  return [\n    { label: ''Registró'', value: match.scoreSubmittedByLabel ?? ''—'' },\n    { label: ''Refutó'', value: match.disputedByLabel ?? ''—'' },\n    { label: ''Motivo'', value: match.dispute_reason ?? ''—'' },\n    { label: ''Nota admin'', value: match.admin_notes ?? ''—'' },\n    {\n      label: ''Estado'',\n      value: isRefutedPending ? ''Refutado · pendiente de marcador'' : match.status,\n    },\n    { label: ''Enviado'', value: shortFeedDate(match.score_submitted_at) ?? ''—'' },\n    { label: ''Refutado'', value: shortFeedDate(match.disputed_at) ?? ''—'' },\n    { label: ''ID partido'', value: match.id },\n  ]\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\results\\AdminResultReviewRow.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  type MatchFeedTimelineStep,\n  type MatchFeedLogEntry,\n} from ''@/components/shared/MatchSportsFeed''", "old_string": "  type MatchFeedTimelineStep,\n} from ''@/components/shared/MatchSportsFeed''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerMatchFeedLayout.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  logEntries?: MatchFeedLogEntry[]", "old_string": "  logEntries?: { label: string; value: ReactNode }[]", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerMatchFeedLayout.tsx"}}]}}'
