  295,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Moviendo las descripciones del tipo de juego a iconos de info con tooltip en hover y popover al tocar, y compactando las tarjetas de selección.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import { useEffect, useMemo, useRef, useState, type ReactNode } from ''react''\nimport type { LucideIcon } from ''lucide-react''\nimport { AlertCircle, Check, CheckCircle2, Flame, Info, Layers, Timer } from ''lucide-react''", "old_string": "import { useEffect, useMemo, useState } from ''react''\nimport type { LucideIcon } from ''lucide-react''\nimport { AlertCircle, Check, CheckCircle2, Flame, Layers, Timer } from ''lucide-react''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\matches\\ScoreSubmissionModal.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "function InfoHint({\n  label,\n  children,\n  align = ''end'',\n}: {\n  label: string\n  children: ReactNode\n  align?: ''start'' | ''end''\n}) {\n  const [open, setOpen] = useState(false)\n  const rootRef = useRef<HTMLSpanElement>(null)\n\n  useEffect(() => {\n    if (!open) return\n    const onDocClick = (event: MouseEvent) => {\n      if (rootRef.current?.contains(event.target as Node)) return\n      setOpen(false)\n    }\n    document.addEventListener(''click'', onDocClick)\n    return () => document.removeEventListener(''click'', onDocClick)\n  }, [open])\n\n  return (\n    <span ref={rootRef} className=\"relative inline-flex shrink-0\">\n      <button\n        type=\"button\"\n        aria-label={label}\n        aria-expanded={open}\n        className=\"flex size-6 touch-manipulation items-center justify-center rounded-full text-muted-foreground transition-colors hover:bg-muted/80 hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[#1F5A4C]/25\"\n        onPointerDown={(event) => event.stopPropagation()}\n        onClick={(event) => {\n          event.stopPropagation()\n          setOpen((value) => !value)\n        }}\n        onMouseEnter={() => {\n          if (window.matchMedia(''(hover: hover) and (pointer: fine)'').matches) setOpen(true)\n        }}\n        onMouseLeave={() => {\n          if (window.matchMedia(''(hover: hover) and (pointer: fine)'').matches) setOpen(false)\n        }}\n      >\n        <Info className=\"size-3.5\" aria-hidden />\n      </button>\n      {open ? (\n        <div\n          role=\"tooltip\"\n          className={cn(\n            ''absolute bottom-[calc(100%+0.35rem)] z-30 w-[min(15rem,calc(100vw-2.5rem))] rounded-lg border border-border/80 bg-popover px-2.5 py-2 text-[11px] leading-snug text-popover-foreground shadow-md'',\n            align === ''end'' ? ''right-0'' : ''left-0'',\n          )}\n          onPointerDown={(event) => event.stopPropagation()}\n        >\n          {children}\n        </div>\n      ) : null}\n    </span>\n  )\n}\n\nfunction GameTypeSelector({\n  value,\n  onChange,\n}: {\n  value: MatchGameType\n  onChange: (value: MatchGameType) => void\n}) {\n  return (\n    <section className=\"space-y-2.5\">\n      <div className=\"flex items-center gap-1.5\">\n        <p className=\"text-sm font-semibold text-foreground\">Tipo de juego</p>\n        <InfoHint label=\"Información sobre el tipo de juego\">\n          Elige el formato del partido; debe coincidir con lo acordado en pista.\n        </InfoHint>\n      </div>\n      <div\n        className=\"grid grid-cols-1 gap-2 sm:grid-cols-3\"\n        role=\"radiogroup\"\n        aria-label=\"Tipo de juego del partido\"\n      >\n        {gameTypeOptions.map((option) => {\n          const selected = value === option.value\n          const Icon = option.icon\n          return (\n            <button\n              key={option.value}\n              type=\"button\"\n              role=\"radio\"\n              aria-checked={selected}\n              className={cn(\n                ''group relative min-h-[3.25rem] touch-manipulation rounded-xl border-2 px-2.5 py-2 text-left transition active:scale-[0.99] sm:min-h-[3.5rem] sm:px-3'',\n                selected\n                  ? ''border-[#1F5A4C] bg-[#1F5A4C]/[0.09] shadow-sm ring-2 ring-[#1F5A4C]/15''\n                  : ''border-border/60 bg-gradient-to-b from-white to-muted/30 hover:border-[#1F5A4C]/45 hover:bg-muted/40'',\n              )}\n              onClick={() => onChange(option.value)}\n            >\n              <span className=\"flex items-center gap-2\">\n                <span\n                  className={cn(\n                    ''flex size-9 shrink-0 items-center justify-center rounded-lg border shadow-sm transition-colors sm:size-10'',\n                    selected\n                      ? ''border-[#1F5A4C]/40 bg-[#1F5A4C] text-white''\n                      : ''border-border/50 bg-white text-[#1F5A4C]/80 group-hover:border-[#1F5A4C]/35'',\n                  )}\n                >\n                  <Icon className=\"size-4 sm:size-[1.1rem]\" aria-hidden />\n                </span>\n                <span className=\"min-w-0 flex-1 text-sm font-bold leading-tight text-foreground sm:text-[0.9375rem]\">\n                  {option.label}\n                </span>\n                <InfoHint label={`Información: ${option.label}`} align=\"end\">\n                  {option.description}\n                </InfoHint>\n                <span\n                  className={cn(\n                    ''flex size-5 shrink-0 items-center justify-center rounded-full border-2 transition-colors'',\n                    selected\n                      ? ''border-[#1F5A4C] bg-[#1F5A4C] text-white''\n                      : ''border-muted-foreground/35 bg-white'',\n                  )}\n                  aria-hidden\n                >\n                  {selected ? <Check className=\"size-3\" strokeWidth={2.8} /> : null}\n                </span>\n              </span>\n            </button>\n          )\n        })}\n      </div>\n    </section>\n  )\n}", "old_string": "function GameTypeSelector({\n  value,\n  onChange,\n}: {\n  value: MatchGameType\n  onChange: (value: MatchGameType) => void\n}) {\n  return (\n    <section className=\"space-y-3\">\n      <div>\n        <p className=\"text-sm font-semibold text-foreground\">Tipo de juego</p>\n        <p className=\"mt-0.5 text-[11px] leading-snug text-muted-foreground sm:text-xs\">\n          Elige el formato del partido; debe coincidir con lo acordado en pista.\n        </p>\n      </div>\n      <div\n        className=\"grid grid-cols-1 gap-2.5 sm:grid-cols-3 sm:gap-2\"\n        role=\"radiogroup\"\n        aria-label=\"Tipo de juego del partido\"\n      >\n        {gameTypeOptions.map((option) => {\n          const selected = value === option.value\n          const Icon = option.icon\n          return (\n            <button\n              key={option.value}\n              type=\"button\"\n              role=\"radio\"\n              aria-checked={selected}\n              className={cn(\n                ''group relative min-h-[4.5rem] touch-manipulation rounded-2xl border-2 p-3 text-left transition active:scale-[0.99] sm:min-h-[5.25rem] sm:p-3.5'',\n                selected\n                  ? ''border-[#1F5A4C] bg-[#1F5A4C]/[0.09] shadow-md ring-2 ring-[#1F5A4C]/15''\n                  : ''border-border/60 bg-gradient-to-b from-white to-muted/30 hover:border-[#1F5A4C]/45 hover:bg-muted/40'',\n              )}\n              onClick={() => onChange(option.value)}\n            >\n              <span className=\"flex items-start gap-2.5\">\n                <span\n                  className={cn(\n                    ''flex size-10 shrink-0 items-center justify-center rounded-xl border shadow-sm transition-colors sm:size-11'',\n                    selected\n                      ? ''border-[#1F5A4C]/40 bg-[#1F5A4C] text-white''\n                      : ''border-border/50 bg-white text-[#1F5A4C]/80 group-hover:border-[#1F5A4C]/35'',\n                  )}\n                >\n                  <Icon className=\"size-[1.15rem] sm:size-5\" aria-hidden />\n                </span>\n                <span className=\"min-w-0 flex-1 pt-0.5\">\n                  <span className=\"flex items-start justify-between gap-2\">\n                    <span className=\"text-sm font-bold leading-tight text-foreground sm:text-[0.9375rem]\">{option.label}</span>\n                    <span\n                      className={cn(\n                        ''flex size-5 shrink-0 items-center justify-center rounded-full border-2 transition-colors'',\n                        selected\n                          ? ''border-[#1F5A4C] bg-[#1F5A4C] text-white''\n                          : ''border-muted-foreground/35 bg-white'',\n                      )}\n                      aria-hidden\n                    >\n                      {selected ? <Check className=\"size-3\" strokeWidth={2.8} /> : null}\n                    </span>\n                  </span>\n                  <span className=\"mt-1 block text-pretty text-[11px] leading-relaxed text-muted-foreground sm:text-xs\">\n                    {option.description}\n                  </span>\n                </span>\n              </span>\n            </button>\n          )\n        })}\n      </div>\n    </section>\n  )\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\matches\\ScoreSubmissionModal.tsx"}}]}}'
);

