INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0402',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  402,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Corrigiendo la Edge Function (email de recuperación no debe tocar Auth), mejorando validación en cliente y evitando que la UI quede bloqueada.\n\n[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\supabase\\functions\\update-user-account\\index.ts", "contents": "import { createClient } from ''https://esm.sh/@supabase/supabase-js@2.49.1''\n\nimport { formatAuthPasswordError, isPasswordLongEnough, passwordMinLengthError } from ''../_shared/passwordPolicy.ts''\n\nconst corsHeaders = {\n  ''Access-Control-Allow-Origin'': ''*'',\n  ''Access-Control-Allow-Headers'': ''authorization, x-client-info, apikey, content-type'',\n  ''Access-Control-Allow-Methods'': ''POST, OPTIONS'',\n} as const\n\nfunction err(message: string, status: number) {\n  return new Response(JSON.stringify({ error: message }), {\n    status,\n    headers: { ...corsHeaders, ''Content-Type'': ''application/json'' },\n  })\n}\n\nfunction ok(body: Record<string, unknown>) {\n  return new Response(JSON.stringify(body), {\n    status: 200,\n    headers: { ...corsHeaders, ''Content-Type'': ''application/json'' },\n  })\n}\n\nfunction normalizePhone(raw: string): { ok: true; digits: string } | { ok: false; error: string } {\n  let s = String(raw ?? '''').trim()\n  s = s.replace(/[\\s\\-().]/g, '''')\n  if (s.startsWith(''+52'')) s = s.slice(3)\n  let digits = s.replace(/\\D/g, '''')\n  while (digits.startsWith(''52'') && digits.length > 10) digits = digits.slice(2)\n  if (digits.length < 10) return { ok: false, error: ''El numero debe tener al menos 10 digitos.'' }\n  if (digits.length > 13) return { ok: false, error: ''El numero no puede tener mas de 13 digitos.'' }\n  return { ok: true, digits }\n}\n\nfunction technicalAuthEmailFromDigits(digits: string): string {\n  return `${digits}@mega-varonil.local`\n}\n\nfunction isValidEmail(s: string): boolean {\n  return /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/.test(s)\n}\n\nDeno.serve(async (req) => {\n  if (req.method === ''OPTIONS'') {\n    return new Response(''ok'', { status: 200, headers: corsHeaders })\n  }\n  if (req.method !== ''POST'') return err(''Metodo no permitido'', 405)\n\n  const authHeader = req.headers.get(''Authorization'')\n  if (!authHeader?.startsWith(''Bearer '')) return err(''No autorizado'', 401)\n\n  let body: {\n    fullName?: string\n    phone?: string\n    recoveryEmail?: string | null\n    newPassword?: string\n  }\n  try {\n    body = await req.json()\n  } catch {\n    return err(''JSON invalido'', 400)\n  }\n\n  const supabaseUrl = Deno.env.get(''SUPABASE_URL'')!\n  const serviceKey = Deno.env.get(''SUPABASE_SERVICE_ROLE_KEY'')!\n  const anonKey = Deno.env.get(''SUPABASE_ANON_KEY'')!\n\n  const userClient = createClient(supabaseUrl, anonKey, {\n    global: { headers: { Authorization: authHeader } },\n  })\n  const { data: userData, error: userErr } = await userClient.auth.getUser()\n  if (userErr || !userData.user) return err(''No autorizado'', 401)\n  const uid = userData.user.id\n\n  const admin = createClient(supabaseUrl, serviceKey, {\n    auth: { autoRefreshToken: false, persistSession: false },\n  })\n\n  const { data: currentProfile, error: currentErr } = await admin\n    .from(''profiles'')\n    .select(''id, phone, email'')\n    .eq(''id'', uid)\n    .maybeSingle()\n  if (currentErr) return err(currentErr.message, 500)\n  if (!currentProfile) return err(''Perfil no encontrado'', 404)\n\n  const patch: Record<string, unknown> = {}\n  let changed = false\n\n  if (Object.prototype.hasOwnProperty.call(body, ''fullName'')) {\n    const fullName = String(body.fullName ?? '''').trim()\n    if (fullName.length < 2) return err(''El nombre debe tener al menos 2 caracteres.'', 400)\n    const prev = String((currentProfile as { full_name?: string | null }).full_name ?? '''').trim()\n    if (fullName !== prev) {\n      patch.full_name = fullName\n      changed = true\n    }\n  }\n\n  if (Object.prototype.hasOwnProperty.call(body, ''phone'')) {\n    const parsed = normalizePhone(String(body.phone ?? ''''))\n    if (!parsed.ok) return err(parsed.error, 400)\n    const prev = String((currentProfile as { phone?: string | null }).phone ?? '''').trim()\n    if (parsed.digits !== prev) {\n      const { data: dupPhone, error: dupPhoneErr } = await admin\n        .from(''profiles'')\n        .select(''id'')\n        .eq(''phone'', parsed.digits)\n        .neq(''id'', uid)\n        .maybeSingle()\n      if (dupPhoneErr) return err(dupPhoneErr.message, 500)\n      if (dupPhone) return err(''Ese celular ya esta registrado en otra cuenta.'', 409)\n\n      const tech = technicalAuthEmailFromDigits(parsed.digits)\n      const { error: authUpErr } = await admin.auth.admin.updateUserById(uid, {\n        email: tech,\n        email_confirm: true,\n      })\n      if (authUpErr) return err(authUpErr.message, 400)\n\n      patch.phone = parsed.digits\n      changed = true\n    }\n  }\n\n  if (Object.prototype.hasOwnProperty.call(body, ''recoveryEmail'')) {\n    const raw = body.recoveryEmail\n    const nextEmail = raw == null || String(raw).trim() === '''' ? null : String(raw).trim().toLowerCase()\n    if (nextEmail && !isValidEmail(nextEmail)) return err(''Correo no valido'', 400)\n\n    const prev = String((currentProfile as { email?: string | null }).email ?? '''').trim().toLowerCase() || null\n    if (nextEmail !== prev) {\n      if (nextEmail) {\n        const { data: dupEmail, error: dupEmailErr } = await admin\n          .from(''profiles'')\n          .select(''id'')\n          .eq(''email'', nextEmail)\n          .neq(''id'', uid)\n          .maybeSingle()\n        if (dupEmailErr) return err(dupEmailErr.message, 500)\n        if (dupEmail) return err(''Ese correo ya esta registrado en otra cuenta.'', 409)\n      }\n      patch.email = nextEmail\n      patch.email_verified = false\n      patch.must_complete_email = nextEmail == null\n      changed = true\n    }\n  }\n\n  const newPassword = String(body.newPassword ?? '''').trim()\n  if (newPassword) {\n    if (!isPasswordLongEnough(newPassword)) {\n      return err(`${passwordMinLengthError(''La contrasena'')}.`, 400)\n    }\n    const { error: pwErr } = await admin.auth.admin.updateUserById(uid, { password: newPassword })\n    if (pwErr) return err(formatAuthPasswordError(pwErr.message), 400)\n    const { error: credErr } = await admin.from(''admin_user_credentials'').upsert({\n      user_id: uid,\n      password_plain: newPassword,\n      updated_by: uid,\n      updated_at: new Date().toISOString(),\n    })\n    if (credErr) return err(credErr.message, 500)\n    changed = true\n  }\n\n  if (Object.keys(patch).length > 0) {\n    const { error: profErr } = await admin.from(''profiles'').update(patch).eq(''id'', uid)\n    if (profErr) return err(profErr.message, 500)\n  }\n\n  if (!changed) {\n    return ok({ success: true, unchanged: true })\n  }\n\n  return ok({ success: true })\n})\n"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "async function readFunctionsErrorBody(error: unknown): Promise<{ error?: string; code?: string } | null> {\n  if (!(error instanceof FunctionsHttpError)) return null\n  const res = error.context as Response\n  try {\n    const ct = res.headers.get(''Content-Type'') ?? ''''\n    if (!ct.includes(''application/json'')) return null\n    return (await res.clone().json()) as { error?: string; code?: string }\n  } catch {\n    return null\n  }\n}\n\nconst EDGE_FUNCTION_TIMEOUT_MS = 30_000\n\nasync function invokeAuthedEdgeFunction<T>(\n  name: string,\n  body: Record<string, unknown>,\n): Promise<T | null> {\n  const anonKey = requireAnonKey()\n  const { data: sessionData } = await supabase.auth.getSession()\n  const token = sessionData.session?.access_token\n  if (!token) throw new Error(''Inicia sesión para continuar.'')\n\n  const ac = new AbortController()\n  const timeout = window.setTimeout(() => ac.abort(), EDGE_FUNCTION_TIMEOUT_MS)\n\n  try {\n    const { data, error } = await supabase.functions.invoke<T>(name, {\n      body,\n      headers: { Authorization: `Bearer ${token}`, apikey: anonKey },\n      signal: ac.signal,\n    })\n\n    if (error) {\n      if (error.name === ''AbortError'') {\n        throw new Error(''La solicitud tardó demasiado. Intenta de nuevo.'')\n      }\n      const parsed = await readFunctionsErrorBody(error)\n      throw new Error(parsed?.error ?? error.message)\n    }\n\n    if (data && typeof data === ''object'' && ''error'' in data && (data as { error?: string }).error) {\n      throw new Error(String((data as { error?: string }).error))\n    }\n\n    return data ?? null\n  } finally {\n    window.clearTimeout(timeout)\n  }\n}", "old_string": "async function readFunctionsErrorBody(error: unknown): Promise<{ error?: string; code?: string } | null> {\n  if (!(error instanceof FunctionsHttpError)) return null\n  const res = error.context as Response\n  try {\n    const ct = res.headers.get(''Content-Type'') ?? ''''\n    if (!ct.includes(''application/json'')) return null\n    return (await res.clone().json()) as { error?: string; code?: string }\n  } catch {\n    return null\n  }\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\authEdge.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export async function invokeUpdateUserAccount(input: {\n  fullName?: string\n  phone?: string\n  recoveryEmail?: string | null\n  newPassword?: string\n}): Promise<void> {\n  await invokeAuthedEdgeFunction(''update-user-account'', input)\n}", "old_string": "export async function invokeUpdateUserAccount(input: {\n  fullName?: string\n  phone?: string\n  recoveryEmail?: string | null\n  newPassword?: string\n}): Promise<void> {\n  const anonKey = requireAnonKey()\n  const { data: sessionData } = await supabase.auth.getSession()\n  const token = sessionData.session?.access_token\n  if (!token) throw new Error(''Inicia sesiÃ³n para actualizar tu cuenta.'')\n  const { data, error } = await supabase.functions.invoke<{ error?: string }>(''update-user-account'', {\n    body: input,\n    headers: { Authorization: `Bearer ${token}`, apikey: anonKey },\n  })\n  if (error) {\n    const parsed = await readFunctionsErrorBody(error)\n    throw new Error(parsed?.error ?? error.message)\n  }\n  if (data && typeof data === ''object'' && ''error'' in data && data.error) {\n    throw new Error(String(data.error))\n  }\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\authEdge.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import { formatRecoveryEmailDisplay, recoveryEmailComplete } from ''@/lib/profileEmail''\nimport { normalizePhone } from ''@/lib/phone''\nimport { invokeUpdateUserAccount } from ''@/services/authEdge''", "old_string": "import { formatRecoveryEmailDisplay, recoveryEmailComplete } from ''@/lib/profileEmail''\nimport { invokeUpdateUserAccount } from ''@/services/authEdge''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerAccountSection.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  const saveProfile = async (event: React.FormEvent) => {\n    event.preventDefault()\n    const nextName = fullName.trim()\n    const nextConfirm = confirmEmail.trim().toLowerCase()\n    const nextEmail = email.trim().toLowerCase()\n    const parsedPhone = normalizePhone(phone)\n\n    if (nextName.length < 2) {\n      toast.error(''Escribe tu nombre completo.'')\n      return\n    }\n    if (!parsedPhone.ok) {\n      toast.error(parsedPhone.error)\n      return\n    }\n    if (nextEmail && !EMAIL_RE.test(nextEmail)) {\n      toast.error(''Introduce un correo de recuperacion valido.'')\n      return\n    }\n    if (nextEmail !== nextConfirm) {\n      toast.error(''Los correos de recuperacion no coinciden.'')\n      return\n    }\n\n    setBusyProfile(true)\n    try {\n      await invokeUpdateUserAccount({\n        fullName: nextName,\n        phone: parsedPhone.digits,\n        recoveryEmail: nextEmail || null,\n      })\n      toast.success(''Datos actualizados'')\n      setPhone(parsedPhone.digits)\n      setEmail(nextEmail)\n      setConfirmEmail(nextEmail)\n    } catch (e) {\n      toast.error(e instanceof Error ? e.message : ''No se pudieron guardar tus datos'')\n    } finally {\n      setBusyProfile(false)\n    }\n    void refreshProfile()\n  }", "old_string": "  const saveProfile = async (event: React.FormEvent) => {\n    event.preventDefault()\n    const nextName = fullName.trim()\n    const nextPhone = phone.trim()\n    const nextEmail = email.trim().toLowerCase()\n    const nextConfirm = confirmEmail.trim().toLowerCase()\n\n    if (nextName.length < 2) {\n      toast.error(''Escribe tu nombre completo.'')\n      return\n    }\n    if (!nextPhone) {\n      toast.error(''Escribe tu celular.'')\n      return\n    }\n    if (nextEmail && !EMAIL_RE.test(nextEmail)) {\n      toast.error(''Introduce un correo de recuperacion valido.'')\n      return\n    }\n    if (nextEmail !== nextConfirm) {\n      toast.error(''Los correos de recuperacion no coinciden.'')\n      return\n    }\n\n    setBusyProfile(true)\n    try {\n      await invokeUpdateUserAccount({\n        fullName: nextName,\n        phone: nextPhone,\n        recoveryEmail: nextEmail || null,\n      })\n      toast.success(''Datos actualizados'')\n      await refreshProfile()\n    } catch (e) {\n      toast.error(e instanceof Error ? e.message : ''No se pudieron guardar tus datos'')\n    } finally {\n      setBusyProfile(false)\n    }\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerAccountSection.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "    setBusyPwd(true)\n    try {\n      await invokeUpdateUserAccount({ newPassword: pwd })\n      toast.success(''Contrasena actualizada'')\n      setPwd('''')\n      setPwd2('''')\n    } catch (e) {\n      toast.error(e instanceof Error ? e.message : ''No se pudo cambiar la contrasena'')\n    } finally {\n      setBusyPwd(false)\n    }\n    void refreshProfile()\n  }", "old_string": "    setBusyPwd(true)\n    try {\n      await invokeUpdateUserAccount({ newPassword: pwd })\n      toast.success(''Contrasena actualizada'')\n      setPwd('''')\n      setPwd2('''')\n      await refreshProfile()\n    } catch (e) {\n      toast.error(e instanceof Error ? e.message : ''No se pudo cambiar la contrasena'')\n    } finally {\n      setBusyPwd(false)\n    }\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\player\\PlayerAccountSection.tsx"}}]}}'
