INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0404',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  404,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Corregí el guardado en `/player/cuenta`. Había varios problemas:\n\n**Causas principales**\n1. **Edge Function `update-user-account`**: al guardar el correo de recuperación intentaba cambiar el email de **Auth** (login), lo que podía bloquear o fallar. Ahora el correo de recuperación solo se guarda en `profiles.email`, como en el panel admin.\n2. **Cambio de celular**: no actualizaba el email técnico de login (`5512345678@mega-varonil.local`); ya queda sincronizado.\n3. **UI bloqueada**: el botón esperaba también a `refreshProfile()` antes de dejar de cargar; ahora el spinner se quita en cuanto responde el servidor.\n4. **Timeout**: si la función no responde en 30 s, muestra error en lugar de quedarse cargando indefinidamente.\n5. **Validación de celular**: se normaliza en cliente (10 dígitos) antes de enviar.\n\n**Desplegado** `update-user-account` en Supabase.\n\nRecarga la página (`Ctrl+Shift+R`) y prueba **Guardar datos** de nuevo. Si falla, deberías ver un mensaje concreto en español en lugar del spinner infinito.\n\n[REDACTED]"}]}}'
);

