INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0478',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  478,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Implementando la escalera en cascada con Grupo MB siempre al final y añadiendo validación al crear el torneo.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import type { TournamentMovementReason, TournamentMovementType } from ''@/types/database''\nimport { compareRankingRowsForLeaderboard, type RankingRow } from ''@/utils/ranking''\n\n/** Intento legado antes de límites; mantener solo si otros módulos lo referencian. */\nexport type PromotionIntent = ''promote'' | ''stay'' | ''demote''\n\nexport type GroupTierInput = {\n  order_index: number\n  name: string\n  players: readonly unknown[]\n}\n\nfunction localeEsNumericNameCompare(a: string, b: string): number {\n  return a.localeCompare(b, ''es'', { numeric: true, sensitivity: ''base'' })\n}\n\n/** Grupo MB siempre es el último escalón (no puede subir desde abajo ni actuar como grupo 1). */\nexport function isMbBottomTierGroupName(name: string): boolean {\n  const normalized = name.trim().toLowerCase().replace(/\\s+/g, '' '')\n  return normalized === ''grupo mb'' || normalized === ''mb''\n}\n\nexport function compareGroupsForPromotionTier(a: GroupTierInput, b: GroupTierInput): number {\n  const aMb = isMbBottomTierGroupName(a.name)\n  const bMb = isMbBottomTierGroupName(b.name)\n  if (aMb !== bMb) return aMb ? 1 : -1\n  if (a.order_index !== b.order_index) return a.order_index - b.order_index\n  return localeEsNumericNameCompare(a.name, b.name)\n}\n\n/**\n * Escalera de niveles para ascenso/descenso en cascada (1 = mejor grupo).\n * Devuelve `order_index` distintos ordenados de arriba hacia abajo; Grupo MB siempre al final.\n */\nexport function buildPromotionTierLadder(groups: GroupTierInput[]): number[] {\n  const byOrderIndex = new Map<number, GroupTierInput>()\n  for (const g of groups) {\n    if (g.players.length === 0) continue\n    const prev = byOrderIndex.get(g.order_index)\n    if (!prev || isMbBottomTierGroupName(g.name)) {\n      byOrderIndex.set(g.order_index, g)\n    }\n  }\n  return [...byOrderIndex.entries()]\n    .sort(([, a], [, b]) => compareGroupsForPromotionTier(a, b))\n    .map(([orderIndex]) => orderIndex)\n}\n\n/**\n * Orden para ascenso/descenso: puntos → games a favor → diferencia de games → nombre (estable).\n */\nexport function sortGroupStandingsForMovement(standings: RankingRow[]): RankingRow[] {\n  const sorted = [...standings].sort(compareRankingRowsForLeaderboard)\n  return sorted.map((r, i) => ({ ...r, position: i + 1 }))\n}\n\n/** @deprecated Usar {@link sortGroupStandingsForMovement}. */\nexport function sortPlayersForPromotion(rows: RankingRow[]): RankingRow[] {\n  return sortGroupStandingsForMovement(rows)\n}\n\n/**\n * Escalera de grupos por **rango de nivel** (1 = mejor grupo).\n * Cascada: posiciones 1–2 suben un nivel, 3 se queda, 4–5 bajan un nivel (con topes arriba/abajo).\n */\nexport function getTargetGroupOrder(", "old_string": "import type { TournamentMovementReason, TournamentMovementType } from ''@/types/database''\nimport { compareRankingRowsForLeaderboard, type RankingRow } from ''@/utils/ranking''\n\n/** Intento legado antes de límites; mantener solo si otros módulos lo referencian. */\nexport type PromotionIntent = ''promote'' | ''stay'' | ''demote''\n\n/**\n * Orden para ascenso/descenso: puntos → games a favor → diferencia de games → nombre (estable).\n */\nexport function sortGroupStandingsForMovement(standings: RankingRow[]): RankingRow[] {\n  const sorted = [...standings].sort(compareRankingRowsForLeaderboard)\n  return sorted.map((r, i) => ({ ...r, position: i + 1 }))\n}\n\n/** @deprecated Usar {@link sortGroupStandingsForMovement}. */\nexport function sortPlayersForPromotion(rows: RankingRow[]): RankingRow[] {\n  return sortGroupStandingsForMovement(rows)\n}\n\n/**\n * Escalera de grupos por **rango de nivel** (1 = mejor grupo).\n * `currentGroupOrder`, `minGroupOrder`, `maxGroupOrder` son posiciones 1…N en la escalera,\n * no los valores arbitrarios de `groups.order_index` en base de datos.\n */\nexport function getTargetGroupOrder(", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export function comparePromotionPreviewPlayers(\n  a: { points: number; gamesFor: number; gamesDifference: number; displayName: string },\n  b: { points: number; gamesFor: number; gamesDifference: number; displayName: string },\n): number {\n  if (b.points !== a.points) return b.points - a.points\n  if (b.gamesFor !== a.gamesFor) return b.gamesFor - a.gamesFor\n  if (b.gamesDifference !== a.gamesDifference) return b.gamesDifference - a.gamesDifference\n  return a.displayName.localeCompare(b.displayName)\n}\n\ntype PromotionPreviewCascadeRow = {\n  displayName: string\n  fromGroupOrderIndex: number\n  fromPosition: number\n  targetOrderIndex: number\n  movementType: TournamentMovementType\n}\n\n/** Valida que cada movimiento respete la cascada 1–2↑ / 3= / 4–5↓ sobre la escalera dada. */\nexport function validatePromotionPreviewCascade(\n  previewRows: PromotionPreviewCascadeRow[],\n  tierLadder: number[],\n): string[] {\n  if (tierLadder.length === 0) return [''No hay niveles de grupo para validar movimientos.'']\n  const errors: string[] = []\n  const minTier = 1\n  const maxTier = tierLadder.length\n\n  for (const row of previewRows) {\n    const fromTier = tierLadder.indexOf(row.fromGroupOrderIndex) + 1\n    if (fromTier < 1) {\n      errors.push(`«${row.displayName}»: grupo origen no está en la escalera de promoción.`)\n      continue\n    }\n    const expected = getTargetGroupOrder(fromTier, row.fromPosition, minTier, maxTier)\n    const expectedOrderIndex = tierLadder[expected.targetGroupOrder - 1]\n    if (row.targetOrderIndex !== expectedOrderIndex) {\n      errors.push(\n        `«${row.displayName}» (pos ${row.fromPosition} en nivel ${fromTier}): destino incorrecto; esperado nivel ${expected.targetGroupOrder}, obtuvo order_index ${row.targetOrderIndex}.`,\n      )\n    }\n    if (row.movementType !== expected.movementType) {\n      errors.push(\n        `«${row.displayName}»: tipo de movimiento «${row.movementType}» no coincide con «${expected.movementType}».`,\n      )\n    }\n  }\n  return errors\n}", "old_string": "export function comparePromotionPreviewPlayers(\n  a: { points: number; gamesFor: number; gamesDifference: number; displayName: string },\n  b: { points: number; gamesFor: number; gamesDifference: number; displayName: string },\n): number {\n  if (b.points !== a.points) return b.points - a.points\n  if (b.gamesFor !== a.gamesFor) return b.gamesFor - a.gamesFor\n  if (b.gamesDifference !== a.gamesDifference) return b.gamesDifference - a.gamesDifference\n  return a.displayName.localeCompare(b.displayName)\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import {\n  buildPromotionTierLadder,\n  chunkPlayersIntoGroups,\n  comparePromotionPreviewPlayers,\n  generateTierGroupName,\n  getTargetGroupOrder,\n  sortGroupStandingsForMovement,\n  validatePromotionPreviewCascade,\n} from ''@/utils/nextTournamentPromotion''", "old_string": "import {\n  chunkPlayersIntoGroups,\n  comparePromotionPreviewPlayers,\n  generateTierGroupName,\n  getTargetGroupOrder,\n  sortGroupStandingsForMovement,\n} from ''@/utils/nextTournamentPromotion''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "function groupLabelForTierRank(sortedDistinct: number[], targetOrderIndex: number): string {", "old_string": "function distinctSortedGroupOrderIndices(groups: AdminGroupRecord[]): number[] {\n  const set = new Set<number>()\n  for (const g of groups) {\n    if (g.players.length > 0) set.add(g.order_index)\n  }\n  return [...set].sort((a, b) => a - b)\n}\n\nfunction groupLabelForTierRank(sortedDistinct: number[], targetOrderIndex: number): string {", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  const sortedDistinct = buildPromotionTierLadder(groups)", "old_string": "  const sortedDistinct = distinctSortedGroupOrderIndices(groups)", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "    const groups = await getAdminGroups(payload.baseTournamentId)\n    if (nonClosedMatchCount(groups) > 0) {\n      errors.push(''Todos los partidos del torneo base deben estar cerrados o cancelados.'')\n    }\n    const tierLadder = buildPromotionTierLadder(groups)\n    errors.push(...validatePromotionPreviewCascade(previewRows, tierLadder))\n  }", "old_string": "    const groups = await getAdminGroups(payload.baseTournamentId)\n    if (nonClosedMatchCount(groups) > 0) {\n      errors.push(''Todos los partidos del torneo base deben estar cerrados o cancelados.'')\n    }\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "            <CardDescription>\n              Cascada por nivel: posiciones 1–2 suben un grupo, 3 se queda, 4–5 bajan (con topes). Grupo MB\n              cuenta como último nivel. Mostrando {filteredPreview.length} de {previewRows.length} jugador(es)\n              {baseTournament ? ` · ${baseTournament.name}` : ''''}.\n            </CardDescription>", "old_string": "            <CardDescription>\n              Posiciones 1–2 suben un nivel, 3 se queda, 4–5 bajan (con topes). Mostrando {filteredPreview.length} de{'' ''}\n              {previewRows.length} jugador(es)\n              {baseTournament ? ` · ${baseTournament.name}` : ''''}.\n            </CardDescription>", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\next-tournament\\NextTournamentWizard.tsx"}}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.test.ts", "contents": "import { describe, expect, it } from ''vitest''\n\nimport {\n  buildPromotionTierLadder,\n  getTargetGroupOrder,\n  isMbBottomTierGroupName,\n  validatePromotionPreviewCascade,\n} from ''@/utils/nextTournamentPromotion''\n\ndescribe(''isMbBottomTierGroupName'', () => {\n  it(''detecta Grupo MB'', () => {\n    expect(isMbBottomTierGroupName(''Grupo MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''grupo mb'')).toBe(true)\n    expect(isMbBottomTierGroupName(''MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''Grupo 1'')).toBe(false)\n  })\n})\n\ndescribe(''buildPromotionTierLadder'', () => {\n  it(''ordena por order_index con Grupo MB siempre al final'', () => {\n    const ladder = buildPromotionTierLadder([\n      { order_index: 1, name: ''Grupo MB'', players: [1] },\n      { order_index: 100, name: ''Grupo 1'', players: [1] },\n      { order_index: 200, name: ''Grupo 2'', players: [1] },\n      { order_index: 300, name: ''Grupo 3'', players: [1] },\n    ])\n    expect(ladder).toEqual([100, 200, 300, 1])\n  })\n\n  it(''ignora grupos vacíos'', () => {\n    const ladder = buildPromotionTierLadder([\n      { order_index: 100, name: ''Grupo 1'', players: [1] },\n      { order_index: 200, name: ''Grupo 2'', players: [] },\n    ])\n    expect(ladder).toEqual([100])\n  })\n})\n\ndescribe(''getTargetGroupOrder cascada'', () => {\n  const min = 1\n  const max = 4\n\n  it(''grupo 1: pos 1–2 no suben (tope), pos 3 se queda, pos 4–5 bajan a grupo 2'', () => {\n    expect(getTargetGroupOrder(1, 1, min, max)).toMatchObject({ targetGroupOrder: 1, movementType: ''capped_top'' })\n    expect(getTargetGroupOrder(1, 2, min, max)).toMatchObject({ targetGroupOrder: 1, movementType: ''capped_top'' })\n    expect(getTargetGroupOrder(1, 3, min, max)).toMatchObject({ targetGroupOrder: 1, movementType: ''stay'' })\n    expect(getTargetGroupOrder(1, 4, min, max)).toMatchObject({ targetGroupOrder: 2, movementType: ''demote'' })\n    expect(getTargetGroupOrder(1, 5, min, max)).toMatchObject({ targetGroupOrder: 2, movementType: ''demote'' })\n  })\n\n  it(''grupo intermedio 2: pos 1–2 suben a 1, pos 3 se queda, pos 4–5 bajan a 3'', () => {\n    expect(getTargetGroupOrder(2, 1, min, max)).toMatchObject({ targetGroupOrder: 1, movementType: ''promote'' })\n    expect(getTargetGroupOrder(2, 2, min, max)).toMatchObject({ targetGroupOrder: 1, movementType: ''promote'' })\n    expect(getTargetGroupOrder(2, 3, min, max)).toMatchObject({ targetGroupOrder: 2, movementType: ''stay'' })\n    expect(getTargetGroupOrder(2, 4, min, max)).toMatchObject({ targetGroupOrder: 3, movementType: ''demote'' })\n    expect(getTargetGroupOrder(2, 5, min, max)).toMatchObject({ targetGroupOrder: 3, movementType: ''demote'' })\n  })\n\n  it(''último grupo (MB): pos 1–2 suben, pos 3 se queda, pos 4–5 no bajan (tope inferior)'', () => {\n    expect(getTargetGroupOrder(4, 1, min, max)).toMatchObject({ targetGroupOrder: 3, movementType: ''promote'' })\n    expect(getTargetGroupOrder(4, 2, min, max)).toMatchObject({ targetGroupOrder: 3, movementType: ''promote'' })\n    expect(getTargetGroupOrder(4, 3, min, max)).toMatchObject({ targetGroupOrder: 4, movementType: ''stay'' })\n    expect(getTargetGroupOrder(4, 4, min, max)).toMatchObject({ targetGroupOrder: 4, movementType: ''capped_bottom'' })\n    expect(getTargetGroupOrder(4, 5, min, max)).toMatchObject({ targetGroupOrder: 4, movementType: ''capped_bottom'' })\n  })\n})\n\ndescribe(''validatePromotionPreviewCascade'', () => {\n  const ladder = [100, 200, 300, 1]\n\n  it(''acepta movimientos coherentes con la escalera'', () => {\n    const errors = validatePromotionPreviewCascade(\n      [\n        {\n          displayName: ''A'',\n          fromGroupOrderIndex: 100,\n          fromPosition: 4,\n          targetOrderIndex: 200,\n          movementType: ''demote'',\n        },\n        {\n          displayName: ''B'',\n          fromGroupOrderIndex: 200,\n          fromPosition: 1,\n          targetOrderIndex: 100,\n          movementType: ''promote'',\n        },\n        {\n          displayName: ''C'',\n          fromGroupOrderIndex: 1,\n          fromPosition: 5,\n          targetOrderIndex: 1,\n          movementType: ''capped_bottom'',\n        },\n      ],\n      ladder,\n    )\n    expect(errors).toEqual([])\n  })\n\n  it(''rechaza destino incorrecto'', () => {\n    const errors = validatePromotionPreviewCascade(\n      [\n        {\n          displayName: ''Mal'',\n          fromGroupOrderIndex: 100,\n          fromPosition: 4,\n          targetOrderIndex: 300,\n          movementType: ''demote'',\n        },\n      ],\n      ladder,\n    )\n    expect(errors.length).toBeGreaterThan(0)\n    expect(errors[0]).toContain(''Mal'')\n  })\n})\n"}}]}}'
);

