  487,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.ts", "old_string": "export type GroupTierInput = {\n  order_index: number\n  name: string\n  players: readonly unknown[]\n}", "new_string": "export type GroupTierInput = {\n  id?: string\n  order_index: number\n  name: string\n  players: readonly unknown[]\n}\n\nexport type BuildPromotionTierLadderOptions = {\n  /** Solo grupos con clasificación / jugadores en el reparto (excluye grupos vacíos u huérfanos en BD). */\n  participatingGroupIds?: ReadonlySet<string>\n}"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.ts", "old_string": "/**\n * Escalera de niveles para ascenso/descenso en cascada (1 = mejor grupo).\n * Devuelve `order_index` distintos ordenados de arriba hacia abajo; Grupo MB siempre al final.\n */\nexport function buildPromotionTierLadder(groups: GroupTierInput[]): number[] {\n  const byOrderIndex = new Map<number, GroupTierInput>()\n  for (const g of groups) {\n    if (g.players.length === 0) continue\n    const prev = byOrderIndex.get(g.order_index)\n    if (!prev || isMbBottomTierGroupName(g.name)) {\n      byOrderIndex.set(g.order_index, g)\n    }\n  }\n  return [...byOrderIndex.entries()]\n    .sort(([, a], [, b]) => compareGroupsForPromotionTier(a, b))\n    .map(([orderIndex]) => orderIndex)\n}", "new_string": "/**\n * Escalera de niveles para ascenso/descenso en cascada (1 = mejor grupo).\n * Devuelve `order_index` distintos ordenados de arriba hacia abajo; Grupo MB siempre al final.\n * Solo cuenta grupos con jugadores y, si se indica, los que participaron en la clasificación final.\n */\nexport function buildPromotionTierLadder(\n  groups: GroupTierInput[],\n  opts?: BuildPromotionTierLadderOptions,\n): number[] {\n  const participating = opts?.participatingGroupIds\n  const byOrderIndex = new Map<number, GroupTierInput>()\n  for (const g of groups) {\n    if (g.players.length === 0) continue\n    if (participating && g.id && !participating.has(g.id)) continue\n    const prev = byOrderIndex.get(g.order_index)\n    if (!prev || isMbBottomTierGroupName(g.name)) {\n      byOrderIndex.set(g.order_index, g)\n    }\n  }\n  return [...byOrderIndex.entries()]\n    .sort(([, a], [, b]) => compareGroupsForPromotionTier(a, b))\n    .map(([orderIndex]) => orderIndex)\n}\n\n/** Rango 1…N consecutivo del grupo dentro de la escalera (no usa el valor crudo de `order_index`). */\nexport function getPromotionTierRank(tierLadder: number[], orderIndex: number): number {\n  const i = tierLadder.indexOf(orderIndex)\n  return i >= 0 ? i + 1 : 0\n}\n\n/** Etiqueta de nivel para UI (evita confundir «Nivel 3» con el nombre «GRUPO 18»). */\nexport function promotionTierLabel(tierRankOneBased: number, groupName?: string): string {\n  if (tierRankOneBased < 1) return ''Nivel ?''\n  if (groupName && isMbBottomTierGroupName(groupName)) {\n    return `Nivel ${tierRankOneBased} (MB)`\n  }\n  return `Nivel ${tierRankOneBased}`\n}"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.ts", "old_string": "/** Nombre visible para sub-grupos cuando el mismo nivel tiene más de un grupo físico. */\nexport function generateTierGroupName(tierRankOneBased: number, indexWithinTierZeroBased: number, chunksInTier?: number): string {\n  const n = chunksInTier ?? 1\n  if (n <= 1) return `Grupo ${tierRankOneBased}`\n  return `Grupo ${tierRankOneBased} · Sub ${indexWithinTierZeroBased + 1}`\n}", "new_string": "/** Nombre visible para sub-grupos cuando el mismo nivel tiene más de un grupo físico. */\nexport function generateTierGroupName(tierRankOneBased: number, indexWithinTierZeroBased: number, chunksInTier?: number): string {\n  const n = chunksInTier ?? 1\n  if (n <= 1) return promotionTierLabel(tierRankOneBased)\n  return `${promotionTierLabel(tierRankOneBased)} · Sub ${indexWithinTierZeroBased + 1}`\n}"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts", "old_string": "import {\n  buildPromotionTierLadder,\n  chunkPlayersIntoGroups,\n  comparePromotionPreviewPlayers,\n  generateTierGroupName,\n  getTargetGroupOrder,\n  sortGroupStandingsForMovement,\n  validatePromotionPreviewCascade,\n} from ''@/utils/nextTournamentPromotion''", "new_string": "import {\n  buildPromotionTierLadder,\n  chunkPlayersIntoGroups,\n  comparePromotionPreviewPlayers,\n  generateTierGroupName,\n  getPromotionTierRank,\n  getTargetGroupOrder,\n  promotionTierLabel,\n  sortGroupStandingsForMovement,\n  validatePromotionPreviewCascade,\n  type GroupTierInput,\n} from ''@/utils/nextTournamentPromotion''"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts", "old_string": "function groupLabelForTierRank(sortedDistinct: number[], targetOrderIndex: number): string {\n  const i = sortedDistinct.indexOf(targetOrderIndex)\n  const tr = i >= 0 ? i + 1 : 1\n  return `Grupo ${tr}`\n}", "new_string": "function groupLabelForTierRank(sortedDistinct: number[], targetOrderIndex: number): string {\n  const tr = getPromotionTierRank(sortedDistinct, targetOrderIndex)\n  return tr > 0 ? promotionTierLabel(tr) : promotionTierLabel(1)\n}\n\nfunction toGroupTierInputs(groups: AdminGroupRecord[]): GroupTierInput[] {\n  return groups.map((g) => ({\n    id: g.id,\n    order_index: g.order_index,\n    name: g.name,\n    players: g.players,\n  }))\n}"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts", "old_string": "  const sortedDistinct = buildPromotionTierLadder(groups)\n  if (sortedDistinct.length === 0) {\n    throw new Error(''No hay grupos con jugadores en el torneo base.'')\n  }\n\n  const snapRows = snapRes.data ?? []\n  const usedSnapshot = snapRows.length > 0\n  const minTier = 1\n  const maxTier = sortedDistinct.length", "new_string": "  const snapRows = snapRes.data ?? []\n  const usedSnapshot = snapRows.length > 0\n  const tierInputs = toGroupTierInputs(groups)\n  const participatingGroupIds = usedSnapshot\n    ? new Set(snapRows.map((r) => r.group_id))\n    : new Set(groups.filter((g) => g.players.length > 0).map((g) => g.id))\n\n  const sortedDistinct = buildPromotionTierLadder(tierInputs, { participatingGroupIds })\n  if (sortedDistinct.length === 0) {\n    throw new Error(''No hay grupos con jugadores en el torneo base.'')\n  }\n\n  const minTier = 1\n  const maxTier = sortedDistinct.length"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts", "old_string": "      const tierRank = sortedDistinct.indexOf(g.order_index) + 1\n      if (tierRank < 1) continue\n\n      for (const row of ordered) {", "new_string": "      const tierRank = getPromotionTierRank(sortedDistinct, g.order_index)\n      if (tierRank < 1) continue\n\n      for (const row of ordered) {"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts", "old_string": "      const tierRank = sortedDistinct.indexOf(g.order_index) + 1\n      if (tierRank < 1) continue\n\n      for (const r of ranking) {", "new_string": "      const tierRank = getPromotionTierRank(sortedDistinct, g.order_index)\n      if (tierRank < 1) continue\n\n      for (const r of ranking) {"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts", "old_string": "    const tierLadder = buildPromotionTierLadder(groups)\n    errors.push(...validatePromotionPreviewCascade(previewRows, tierLadder))", "new_string": "    const participatingGroupIds = new Set(previewRows.map((r) => r.fromGroupId))\n    const tierLadder = buildPromotionTierLadder(toGroupTierInputs(groups), { participatingGroupIds })\n    errors.push(...validatePromotionPreviewCascade(previewRows, tierLadder))"}}]}}'
);

