andingsByGroup = useMemo(() => {\n    const m = new Map<string, { name: string; orderIndex: number; rows: PromotionPreviewRow[] }>()\n    for (const r of previewRows) {\n      const cur = m.get(r.fromGroupId) ?? {\n        name: r.fromGroupName,\n        orderIndex: r.fromGroupOrderIndex,\n        rows: [],\n      }\n      cur.rows.push(r)\n      m.set(r.fromGroupId, cur)\n    }\n    for (const v of m.values()) {\n      v.rows.sort(\n        (a, b) => a.fromPosition - b.fromPosition || a.displayName.localeCompare(b.displayName, ''es''),\n      )\n    }\n    return [...m.entries()]\n      .map(([id, v]) => ({ id, ...v }))\n      .sort((a, b) => a.orderIndex - b.orderIndex || a.name.localeCompare(b.name, ''es''))\n  }, [previewRows])", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\next-tournament\\NextTournamentWizard.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "              Solo se listan torneos en estado <span className=\"font-medium\">finished</span>. La cascada usa niveles\n              consecutivos (1 = más alto) según la clasificación final; Grupo MB siempre es el último nivel.", "old_string": "              Solo se listan torneos en estado <span className=\"font-medium\">finished</span>. La jerarquía usa{'' ''}\n              <span className=\"font-medium\">order_index</span> del grupo (menor índice = grupo más alto).", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\next-tournament\\NextTournamentWizard.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "                  <span className=\"font-normal text-slate-500\">\n                    {previewQ.data?.sortedDistinctGroupOrderIndices ? (\n                      (() => {\n                        const tierRank = getPromotionTierRank(\n                          previewQ.data.sortedDistinctGroupOrderIndices,\n                          g.orderIndex,\n                        )\n                        r