\n                    const fromLabel = fromTier > 0 ? promotionTierLabel(fromTier, r.fromGroupName) : r.fromGroupName", "old_string": "                    const distinct = previewQ.data?.sortedDistinctGroupOrderIndices ?? []\n                    const fromIx = distinct.indexOf(r.fromGroupOrderIndex)\n                    const fromLabel =\n                      fromIx >= 0 ? `Grupo ${fromIx + 1}` : `Ord.${r.fromGroupOrderIndex}`", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\next-tournament\\NextTournamentWizard.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import {\n  buildPromotionTierLadder,\n  chunkPlayersIntoGroups,\n  comparePromotionPreviewPlayers,\n  generateTierGroupName,\n  getPromotionTierRank,\n  getTargetGroupOrder,\n  promotionTierLabel,\n  sortGroupStandingsForMovement,\n  validatePromotionPreviewCascade,\n  type GroupTierInput,\n} from ''@/utils/nextTournamentPromotion''", "old_string": "import {\n  buildPromotionTierLadder,\n  chunkPlayersIntoGroups,\n  comparePromotionPreviewPlayers,\n  generateTierGroupName,\n  getPromotionTierRank,\n  getTargetGroupOrder,\n  promotionTierLabel,\n  sortGroupStandingsForMovement,\n  validatePromotionPreviewCascade,\n  type GroupTierInput,\n} from ''@/utils/nextTournamentPromotion''\n\nfunction groupLabelForTierRank(sortedDistinct: number[], targetOrderIndex: number): string {\n  const tr = getPromotionTierRank(sortedDistinct, targetOrderIndex)\n  return tr > 0 ? promotionTierLabel(tr) : promotionTierLabel(1)\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}]}}'
