  491,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  const tierRank = (orderIdx: number) => getPromotionTierRank(sortedDistinctGroupOrderIndices, orderIdx) || 1\n\n  const byTier = new Map<number, PromotionPreviewRow[]>()\n  for (const row of rows) {\n    const list = byTier.get(row.targetOrderIndex) ?? []\n    list.push(row)\n    byTier.set(row.targetOrderIndex, list)\n  }\n\n  const out: NextTournamentGroupPreview[] = []\n  const tierKeys = [...byTier.keys()].sort(\n    (a, b) =>\n      getPromotionTierRank(sortedDistinctGroupOrderIndices, a) -\n      getPromotionTierRank(sortedDistinctGroupOrderIndices, b),\n  )\n\n  for (const targetOrderIndex of tierKeys) {\n    const bucket = byTier.get(targetOrderIndex)!\n    const sorted = [...bucket].sort((a, b) => comparePromotionPreviewPlayers(a, b))\n    const tr = tierRank(targetOrderIndex)\n    const tierDisplayName = promotionTierLabel(tr)", "old_string": "  const tierRank = (orderIdx: number) => {\n    const i = sortedDistinctGroupOrderIndices.indexOf(orderIdx)\n    return i >= 0 ? i + 1 : 1\n  }\n\n  const byTier = new Map<number, PromotionPreviewRow[]>()\n  for (const row of rows) {\n    const list = byTier.get(row.targetOrderIndex) ?? []\n    list.push(row)\n    byTier.set(row.targetOrderIndex, list)\n  }\n\n  const out: NextTournamentGroupPreview[] = []\n  const tierKeys = [...byTier.keys()].sort((a, b) => a - b)\n\n  for (const targetOrderIndex of tierKeys) {\n    const bucket = byTier.get(targetOrderIndex)!\n    const sorted = [...bucket].sort((a, b) => comparePromotionPreviewPlayers(a, b))\n    const tr = tierRank(targetOrderIndex)\n    const tierDisplayName = `Grupo ${tr}`", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import { describe, expect, it } from ''vitest''\n\nimport {\n  buildPromotionTierLadder,\n  getPromotionTierRank,\n  getTargetGroupOrder,\n  isMbBottomTierGroupName,\n  promotionTierLabel,\n  validatePromotionPreviewCascade,\n} from ''@/utils/nextTournamentPromotion''\n\ndescribe(''isMbBottomTierGroupName'', () => {\n  it(''detecta Grupo MB'', () => {\n    expect(isMbBottomTierGroupName(''Grupo MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''grupo mb'')).toBe(true)\n    expect(isMbBottomTierGroupName(''MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''GRUPO MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''Grupo 1'')).toBe(false)\n  })\n})\n\ndescribe(''buildPromotionTierLadder'', () => {\n  it(''ordena por order_index con Grupo MB siempre al final'', () => {\n    const ladder = buildPromotionTierLadder([\n      { order_index: 1, name: ''Grupo MB'', players: [1] },\n      { order_index: 100, name: ''Grupo 1'', players: [1] },\n      { order_index: 200, name: ''Grupo 2'', players: [1] },\n      { order_index: 300, name: ''Grupo 3'', players: [1] },\n    ])\n    expect(ladder).toEqual([100, 200, 300, 1])\n  })\n\n  it(''solo incluye grupos participantes en la clasificación final'', () => {\n    const groups = [\n      { id: ''g15'', order_index: 0, name: ''GRUPO 15'', players: [1] },\n      { id: ''g16'', order_index: 1, name: ''GRUPO 16'', players: [1] },\n      { id: ''g17'', order_index: 2, name: ''GRUPO 17'', players: [1] },\n      { id: ''g18'', order_index: 3, name: ''GRUPO 18'', players: [1] },\n      { id: ''gmb'', order_index: 5, name: ''GRUPO MB'', players: [1] },\n      { id: ''g19'', order_index: 19, name: ''GRUPO 19'', players: [1] },\n    ]\n    const participating = new Set([''g15'', ''g16'', ''g18'', ''gmb''])\n    const ladder = buildPromotionTierLadder(groups, { participatingGroupIds: participating })\n    expect(ladder).toEqual([0, 1, 3, 5])\n    expect(getPromotionTierRank(ladder, 0)).toBe(1)\n    expect(getPromotionTierRank(ladder, 1)).toBe(2)\n    expect(getPromotionTierRank(ladder, 3)).toBe(3)\n    expect(getPromotionTierRank(ladder, 5)).toBe(4)\n    expect(promotionTierLabel(4, ''GRUPO MB'')).toBe(''Nivel 4 (MB)'')\n  })\n\n  it(''ignora grupos vacíos'', () => {\n    const ladder = buildPromotionTierLadder([\n      { order_index: 100, name: ''Grupo 1'', players: [1] },\n      { order_index: 200, name: ''Grupo 2'', players: [] },\n    ])\n    expect(ladder).toEqual([100])\n  })\n})", "old_string": "import { describe, expect, it } from ''vitest''\n\nimport {\n  buildPromotionTierLadder,\n  getTargetGroupOrder,\n  isMbBottomTierGroupName,\n  validatePromotionPreviewCascade,\n} from ''@/utils/nextTournamentPromotion''\n\ndescribe(''isMbBottomTierGroupName'', () => {\n  it(''detecta Grupo MB'', () => {\n    expect(isMbBottomTierGroupName(''Grupo MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''grupo mb'')).toBe(true)\n    expect(isMbBottomTierGroupName(''MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''Grupo 1'')).toBe(false)\n  })\n})\n\ndescribe(''buildPromotionTierLadder'', () => {\n  it(''ordena por order_index con Grupo MB siempre al final'', () => {\n    const ladder = buildPromotionTierLadder([\n      { order_index: 1, name: ''Grupo MB'', players: [1] },\n      { order_index: 100, name: ''Grupo 1'', players: [1] },\n      { order_index: 200, name: ''Grupo 2'', players: [1] },\n      { order_index: 300, name: ''Grupo 3'', players: [1] },\n    ])\n    expect(ladder).toEqual([100, 200, 300, 1])\n  })\n\n  it(''ignora grupos vacíos'', () => {\n    const ladder = buildPromotionTierLadder([\n      { order_index: 100, name: ''Grupo 1'', players: [1] },\n      { order_index: 200, name: ''Grupo 2'', players: [] },\n    ])\n    expect(ladder).toEqual([100])\n  })\n})", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.test.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import { getPromotionTierRank, isMbBottomTierGroupName, promotionTierLabel } from ''@/utils/nextTournamentPromotion''", "old_string": "import { getPromotionTierRank, isMbBottomTierGroupName, promotionTierLabel } from ''@/utils/nextTournamentPromotion''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\next-tournament\\NextTournamentWizard.tsx"}}]}}'
);

