INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0498',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  498,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export type BuildPromotionTierLadderOptions = {\n  /** Solo grupos con clasificación / jugadores en el reparto (excluye grupos vacíos u huérfanos en BD). */\n  participatingGroupIds?: ReadonlySet<string>\n}\n\n/** Un escalón de la cascada: un grupo físico = un nivel (p. ej. 20 grupos → 20 niveles). */\nexport type PromotionTierEntry = {\n  groupId: string\n  orderIndex: number\n  name: string\n}", "old_string": "export type BuildPromotionTierLadderOptions = {\n  /** Solo grupos con clasificación / jugadores en el reparto (excluye grupos vacíos u huérfanos en BD). */\n  participatingGroupIds?: ReadonlySet<string>\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "/**\n * Escalera completa: un nivel por grupo con jugadores (20 grupos → niveles 1…20).\n * Orden: `order_index` ascendente; Grupo MB siempre al final.\n */\nexport function buildPromotionTierLadderEntries(\n  groups: GroupTierInput[],\n  opts?: BuildPromotionTierLadderOptions,\n): PromotionTierEntry[] {\n  const participating = opts?.participatingGroupIds\n  const filtered = groups.filter(\n    (g) => g.players.length > 0 && g.id && (!participating || participating.has(g.id)),\n  )\n  return [...filtered]\n    .sort(compareGroupsForPromotionTier)\n    .map((g) => ({\n      groupId: g.id!,\n      orderIndex: g.order_index,\n      name: g.name,\n    }))\n}\n\n/**\n * `order_index` por nivel (persistencia del torneo destino).\n * @deprecated Preferir {@link buildPromotionTierLadderEntries} + {@link orderIndexForTierRank}.\n */\nexport function buildPromotionTierLadder(\n  groups: GroupTierInput[],\n  opts?: BuildPromotionTierLadderOptions,\n): number[] {\n  return buildPromotionTierLadderEntries(groups, opts).map((e) => e.orderIndex)\n}\n\nexport function orderIndexForTierRank(entries: PromotionTierEntry[], tierRank: number): number {\n  return entries[tierRank - 1]?.orderIndex ?? entries[0]?.orderIndex ?? 0\n}\n\n/** Nivel 1…N del grupo dentro de la escalera (por id de grupo, no por `order_index`). */\nexport function getPromotionTierRankForGroup(entries: PromotionTierEntry[], groupId: string): number {\n  const i = entries.findIndex((e) => e.groupId === groupId)\n  return i >= 0 ? i + 1 : 0\n}\n\n/** @deprecated Usar {@link getPromotionTierRankForGroup}; ambiguo si varios grupos comparten `order_index`. */\nexport function getPromotionTierRank(tierLadder: number[], orderIndex: number): number {\n  const i = tierLadder.indexOf(orderIndex)\n  return i >= 0 ? i + 1 : 0\n}\n\n/** Etiqueta de nivel para UI (evita confundir «Nivel 3» con el nombre «GRUPO 18»). */\nexport function promotionTierLabel(\n  tierRankOneBased: number,\n  groupName?: string,\n  totalTiers?: number,\n): string {\n  if (tierRankOneBased < 1) return ''Nivel ?''\n  const suffix = totalTiers != null && totalTiers > 0 ? ` de ${totalTiers}` : ''''\n  if (groupName && isMbBottomTierGroupName(groupName)) {\n    return `Nivel ${tierRankOneBased}${suffix} (MB)`\n  }\n  return `Nivel ${tierRankOneBased}${suffix}`\n}", "old_string": "/**\n * Escalera de niveles para ascenso/descenso en cascada (1 = mejor grupo).\n * Devuelve `order_index` distintos ordenados de arriba hacia abajo; Grupo MB siempre al final.\n * Solo cuenta grupos con jugadores y, si se indica, los que participaron en la clasificación final.\n */\nexport function buildPromotionTierLadder(\n  groups: GroupTierInput[],\n  opts?: BuildPromotionTierLadderOptions,\n): number[] {\n  const participating = opts?.participatingGroupIds\n  const byOrderIndex = new Map<number, GroupTierInput>()\n  for (const g of groups) {\n    if (g.players.length === 0) continue\n    if (participating && g.id && !participating.has(g.id)) continue\n    const prev = byOrderIndex.get(g.order_index)\n    if (!prev || isMbBottomTierGroupName(g.name)) {\n      byOrderIndex.set(g.order_index, g)\n    }\n  }\n  return [...byOrderIndex.entries()]\n    .sort(([, a], [, b]) => compareGroupsForPromotionTier(a, b))\n    .map(([orderIndex]) => orderIndex)\n}\n\n/** Rango 1…N consecutivo del grupo dentro de la escalera (no usa el valor crudo de `order_index`). */\nexport function getPromotionTierRank(tierLadder: number[], orderIndex: number): number {\n  const i = tierLadder.indexOf(orderIndex)\n  return i >= 0 ? i + 1 : 0\n}\n\n/** Etiqueta de nivel para UI (evita confundir «Nivel 3» con el nombre «GRUPO 18»). */\nexport function promotionTierLabel(tierRankOneBased: number, groupName?: string): string {\n  if (tierRankOneBased < 1) return ''Nivel ?''\n  if (groupName && isMbBottomTierGroupName(groupName)) {\n    return `Nivel ${tierRankOneBased} (MB)`\n  }\n  return `Nivel ${tierRankOneBased}`\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "type PromotionPreviewCascadeRow = {\n  displayName: string\n  fromGroupId: string\n  fromGroupOrderIndex: number\n  fromPosition: number\n  targetOrderIndex: number\n  movementType: TournamentMovementType\n}\n\n/** Valida que cada movimiento respete la cascada 1–2↑ / 3= / 4–5↓ sobre la escalera dada. */\nexport function validatePromotionPreviewCascade(\n  previewRows: PromotionPreviewCascadeRow[],\n  tierEntries: PromotionTierEntry[],\n): string[] {\n  if (tierEntries.length === 0) return [''No hay niveles de grupo para validar movimientos.'']\n  const errors: string[] = []\n  const minTier = 1\n  const maxTier = tierEntries.length\n\n  for (const row of previewRows) {\n    const fromTier = getPromotionTierRankForGroup(tierEntries, row.fromGroupId)\n    if (fromTier < 1) {\n      errors.push(`«${row.displayName}»: grupo origen no está en la escalera de promoción.`)\n      continue\n    }\n    const expected = getTargetGroupOrder