  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.test.ts", "contents": "import { describe, expect, it } from ''vitest''\n\nimport {\n  buildPromotionTierLadder,\n  buildPromotionTierLadderEntries,\n  getPromotionTierRankForGroup,\n  getTargetGroupOrder,\n  isMbBottomTierGroupName,\n  orderIndexForTierRank,\n  promotionTierLabel,\n  validatePromotionPreviewCascade,\n} from ''@/utils/nextTournamentPromotion''\n\ndescribe(''isMbBottomTierGroupName'', () => {\n  it(''detecta Grupo MB'', () => {\n    expect(isMbBottomTierGroupName(''Grupo MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''grupo mb'')).toBe(true)\n    expect(isMbBottomTierGroupName(''MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''GRUPO MB'')).toBe(true)\n    expect(isMbBottomTierGroupName(''Grupo 1'')).toBe(false)\n  })\n})\n\ndescribe(''buildPromotionTierLadderEntries'', () => {\n  it(''ordena por order_index con Grupo MB siempre al final'', () => {\n    const entries = buildPromotionTierLadderEntries([\n      { id: ''mb'', order_index: 1, name: ''Grupo MB'', players: [1] },\n      { id: ''g1'', order_index: 100, name: ''Grupo 1'', players: [1] },\n      { id: ''g2'', order_index: 200, name: ''Grupo 2'', players: [1] },\n      { id: ''g3'', order_index: 300, name: ''Grupo 3'', players: [1] },\n    ])\n    expect(entries.map((e) => e.orderIndex)).toEqual([100, 200, 300, 1])\n    expect(getPromotionTierRankForGroup(entries, ''mb'')).toBe(4)\n  })\n\n  it(''20 grupos físicos → 20 niveles consecutivos; MB es nivel 20'', () => {\n    const groups = Array.from({ length: 19 }, (_, i) => ({\n      id: `g${i + 1}`,\n      order_index: i,\n      name: `GRUPO ${i + 1}`,\n      players: [1],\n    }))\n    groups.push({ id: ''gmb'', order_index: 5, name: ''GRUPO MB'', players: [1] })\n\n    const entries = buildPromotionTierLadderEntries(groups)\n    expect(entries).toHaveLength(20)\n    expect(getPromotionTierRankForGroup(entries, ''g1'')).toBe(1)\n    expect(getPromotionTierRankForGroup(entries, ''g19'')).toBe(19)\n    expect(getPromotionTierRankForGroup(entries, ''gmb'')).toBe(20)\n    expect(promotionTierLabel(20, ''GRUPO MB'', 20)).toBe(''Nivel 20 de 20 (MB)'')\n  })\n\n  it(''un grupo físico por nivel aunque compartan order_index'', () => {\n    const entries = buildPromotionTierLadderEntries([\n      { id: ''ga'', order_index: 10, name: ''GRUPO A'', players: [1] },\n      { id: ''gb'', order_index: 10, name: ''GRUPO B'', players: [1] },\n    ])\n    expect(entries).toHaveLength(2)\n    expect(getPromotionTierRankForGroup(entries, ''ga'')).toBe(1)\n    expect(getPromotionTierRankForGroup(entries, ''gb'')).toBe(2)\n  })\n\n  it(''solo incluye grupos participantes en la clasificación final'', () => {\n    const groups = [\n      { id: ''g15'', order_index: 0, name: ''GRUPO 15'', players: [1] },\n      { id: ''g16'', order_index: 1, name: ''GRUPO 16'', players: [1] },\n      { id: ''g17'', order_index: 2, name: ''GRUPO 17'', players: [1] },\n      { id: ''g18'', order_index: 3, name: ''GRUPO 18'', players: [1] },\n      { id: ''gmb'', order_index: 5, name: ''GRUPO MB'', players: [1] },\n      { id: ''g19'', order_index: 19, name: ''GRUPO 19'', players: [1] },\n    ]\n    const participating = new Set([''g15'', ''g16'', ''g18'', ''gmb''])\n    const entries = buildPromotionTierLadderEntries(groups, { participatingGroupIds: participating })\n    expect(entries).toHaveLength(4)\n    expect(buildPromotionTierLadder(groups, { participatingGroupIds: participating })).toEqual([0, 1, 3, 5])\n  })\n\n  it(''ignora grupos vacíos'', () => {\n    const entries = buildPromotionTierLadderEntries([\n      { id: ''g1'', order_index: 100, name: ''Grupo 1'', players: [1] },\n      { id: ''g2'', order_index: 200, name: ''Grupo 2'', players: [] },\n    ])\n    expect(entries).toHaveLength(1)\n  })\n})\n\ndescribe(''getTargetGroupOrder cascada'', () => {\n  const min = 1\n  const max = 4\n\n  it(''grupo 1: pos 1–2 no suben (tope), pos 3 se queda, pos 4–5 bajan a grupo 2'', () => {\n    expect(getTargetGroupOrder(1, 1, min, max)).toMatchObject({ targetGroupOrder: 1, movementType: ''capped_top'' })\n    expect(getTargetGroupOrder(1, 4, min, max)).toMatchObject({ targetGroupOrder: 2, movementType: ''demote'' })\n  })\n\n  it(''nivel 20 de 20: pos 4–5 no bajan más'', () => {\n    expect(getTargetGroupOrder(20, 5, 1, 20)).toMatchObject({\n      targetGroupOrder: 20,\n      movementType: ''capped_bottom'',\n    })\n  })\n})\n\ndescribe(''validatePromotionPreviewCascade'', () => {\n  const entries = buildPromotionTierLadderEntries([\n    { id: ''g1'', order_index: 100, name: ''G1'', players: [1] },\n    { id: ''g2'', order_index: 200, name: ''G2'', players: [1] },\n    { id: ''g3'', order_index: 300, name: ''G3'', players: [1] },\n    { id: ''mb'', order_index: 1, name: ''Grupo MB'', players: [1] },\n  ])\n\n  it(''acepta movimientos coherentes con la escalera'', () => {\n    const errors = validatePromotionPreviewCascade(\n      [\n        {\n          displayName: ''A'',\n          fromGroupId: ''g1'',\n          fromGroupOrderIndex: 100,\n          fromPosition: 4,\n          targetOrderIndex: orderIndexForTierRank(entries, 2),\n          movementType: ''demote'',\n        },\n        {\n          displayName: ''B'',\n          fromGroupId: ''mb'',\n          fromGroupOrderIndex: 1,\n          fromPosition: 5,\n          targetOrderIndex: 1,\n          movementType: ''capped_bottom'',\n        },\n      ],\n      entries,\n    )\n    expect(errors).toEqual([])\n  })\n\n  it(''rechaza destino incorrecto'', () => {\n    const errors = validatePromotionPreviewCascade(\n      [\n        {\n          displayName: ''Mal'',\n          fromGroupId: ''g1'',\n          fromGroupOrderIndex: 100,\n          fromPosition: 4,\n          targetOrderIndex: 300,\n          movementType: ''demote'',\n        },\n      ],\n      entries,\n    )\n    expect(errors.length).toBeGreaterThan(0)\n    expect(errors[0]).toContain(''Mal'')\n  })\n})\n"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "            <CardDescription className=\"text-pretty\">\n              Orden: puntos, games a favor, diferencia de games (desempate estable por nombre).{'' ''}\n              {tierCount > 0 ? `${tierCount} nivel(es) en cascada (1 = más alto).` : ''''}\n            </CardDescription>", "old_string": "            <CardDescription className=\"text-pretty\">\n              Orden: puntos, games a favor, diferencia de games (desempate estable por nombre). Sin usar categorías de\n              división.\n            </CardDescription>", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\next-tournament\\NextTournamentWizard.tsx"}}, {"type": "tool_use", "name": "Shell", "input": {"block_until_ms": 90000, "command": "cd \"c:\\Users\\alpev\\tennis-tournament-app\"; npm test -- --run src/utils/nextTournamentPromotion.test.ts 2>&1", "description": "Run updated promotion tests"}}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0504',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  504,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Con **20 grupos**, el comportamiento correcto es:\n\n## Cómo funciona con 20 grupos\n\n- **20 grupos con jugadores en la clasificación final → 20 niveles en cascada**\n- **Nivel 1** = el de menor `order_index` (tu GRUPO 15 con `order_index 0`)\n- **Nivel 19** = penúltimo en la escalera\n- **Nivel 20 de 20 (MB)** = GRUPO MB, siempre al final aunque tenga `order_index 5`\n\nLa cascada es entre **niveles consecutivos 1↔2↔3↔…↔20**, no entre el número del nombre del grupo:\n\n| Ejemplo | Nivel en cascada |\n|---------|------------------|\n| GRUPO 15 (`order_index 0`) | Nivel **1** de 20 |\n| GRUPO 16 (`order_index 1`) | Nivel **2** de 20 |\n| GRUPO 18 (`order_index 3`) | Nivel **4** de 20 *(hay un grupo en `order_index 2`)* |\n| GRUPO MB (`order_index 5`) | Nivel **20** de 20 *(MB)* |\n\n> **Importante:** «GRUPO 18» no implica nivel 18. El nivel lo define la **posición en la escalera** (`order_index` + MB al final), no el número del nombre.\n\n## Cambio técnico aplicado\n\nAntes se **colapsaban** grupos que compartían `order_index`. Ahora **cada grupo físico = un nivel** (20 grupos → exactamente 20 escalones).\n\nEn la UI verás etiquetas como **`Nivel 4 de 20`** y **`Nivel 20 de 20 (MB)`**.\n\nRecarga el wizard del siguiente torneo para ver los 20 niveles. Si algún grupo no aparece, revisa que esté en el snapshot al cerrar el torneo (`tournament_final_standings`).\n\n[REDACTED]"}]}}'
);

