INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0516',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  516,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export function comparePromotionPreviewPlayers(\n  a: { points: number; gamesFor: number; gamesDifference: number; displayName: string },\n  b: { points: number; gamesFor: number; gamesDifference: number; displayName: string },\n): number {\n  if (b.points !== a.points) return b.points - a.points\n  if (b.gamesFor !== a.gamesFor) return b.gamesFor - a.gamesFor\n  if (b.gamesDifference !== a.gamesDifference) return b.gamesDifference - a.gamesDifference\n  return a.displayName.localeCompare(b.displayName)\n}\n\n/**\n * Siembra en el grupo destino (0 = 1.er lugar, 4 = 5.º):\n * - Bajan (4.º/5.º) → 1.º y 2.º\n * - Suben (1.º/2.º) → 4.º y 5.º\n * - Se queda (3.º) → 3.º\n */\nexport function targetSeedOrderForPromotionRow(row: {\n  fromPosition: number\n  movementType: TournamentMovementType\n}): number {\n  const { fromPosition, movementType } = row\n\n  if (movementType === ''demote'') {\n    if (fromPosition === 4) return 0\n    if (fromPosition === 5) return 1\n  }\n  if (movementType === ''promote'') {\n    if (fromPosition === 1) return 3\n    if (fromPosition === 2) return 4\n  }\n  if (movementType === ''stay'') {\n    if (fromPosition === 3) return 2\n  }\n  if (movementType === ''capped_top'') {\n    if (fromPosition === 1) return 0\n    if (fromPosition === 2) return 1\n  }\n  if (movementType === ''capped_bottom'') {\n    if (fromPosition === 4) return 3\n    if (fromPosition === 5) return 4\n  }\n\n  return Math.max(0, Math.min(4, fromPosition - 1))\n}\n\nexport function comparePromotionRowsForGroupAssignment(\n  a: { fromPosition: number; movementType: TournamentMovementType; points: number; gamesFor: number; gamesDifference: number; displayName: string },\n  b: { fromPosition: number; movementType: TournamentMovementType; points: number; gamesFor: number; gamesDifference: number; displayName: string },\n): number {\n  const seedA = targetSeedOrderForPromotionRow(a)\n  const seedB = targetSeedOrderForPromotionRow(b)\n  if (seedA !== seedB) return seedA - seedB\n  return comparePromotionPreviewPlayers(a, b)\n}", "old_string": "export function comparePromotionPreviewPlayers(\n  a: { points: number; gamesFor: number; gamesDifference: number; displayName: string },\n  b: { points: number; gamesFor: number; gamesDifference: number; displayName: string },\n): number {\n  if (b.points !== a.points) return b.points - a.points\n  if (b.gamesFor !== a.gamesFor) return b.gamesFor - a.gamesFor\n  if (b.gamesDifference !== a.gamesDifference) return b.gamesDifference - a.gamesDifference\n  return a.displayName.localeCompare(b.displayName)\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import {\n  chunkPlayersIntoGroups,\n  comparePromotionRowsForGroupAssignment,\n  generateTierGroupName,\n  getMaxPromotionTier,\n  getPromotionTierRankForGroup,\n  getTargetGroupOrder,\n  orderIndexForTierRank,\n  promotionTierLabel,\n  sortGroupStandingsForMovement,\n  targetSeedOrderForPromotionRow,\n  validatePromotionPreviewCascade,\n  type GroupTierInput,\n  type PromotionTierEntry,\n} from ''@/utils/nextTournamentPromotion''", "old_string": "import {\n  buildPromotionTierLadderEntries,\n  chunkPlayersIntoGroups,\n  comparePromotionPreviewPlayers,\n  generateTierGroupName,\n  getMaxPromotionTier,\n  getPromotionTierRankForGroup,\n  getTargetGroupOrder,\n  orderIndexForTierRank,\n  promotionTierLabel,\n  sortGroupStandingsForMovement,\n  validatePromotionPreviewCascade,\n  type GroupTierInput,\n  type PromotionTierEntry,\n} from ''@/utils/nextTournamentPromotion''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export type NextTournamentGroupPreview = {\n  targetOrderIndex: number\n  tierDisplayName: string\n  groups: {\n    name: string\n    players: { userId: string; displayName: string; seedOrder: number }[]\n    isComplete: boolean\n  }[]\n}", "old_string": "export type NextTournamentGroupPreview = {\n  targetOrderIndex: number\n  tierDisplayName: string\n  groups: {\n    name: string\n    players: { userId: string; displayName: string }[]\n    isComplete: boolean\n  }[]\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export type PlannedPersistGroup = {\n  tempId: string\n  name: string\n  tierDisplayName: string\n  targetOrderIndex: number\n  orderIndex: number\n  players: { userId: string; displayName: string; seedOrder: number }[]\n  isComplete: boolean\n}", "old_string": "export type PlannedPersistGroup = {\n  tempId: string\n  name: string\n  tierDisplayName: string\n  targetOrderIndex: number\n  orderIndex: number\n  players: { userId: string; displayName: string }[]\n  isComplete: boolean\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  for (const targetOrderIndex of tierKeys) {\n    const bucket = byTier.get(targetOrderIndex)!\n    const sorted = [...bucket].sort(comparePromotionRowsForGroupAssignment)\n    const tr = tierRankForOrderIndex(targetOrderIndex)\n    const tierDisplayName = promotionTierLabel(tr, undefined, getMaxPromotionTier(tierEntries))\n    const chunks = chunkPlayersIntoGroups(sorted, groupSize)\n    out.push({\n      targetOrderIndex,\n      tierDisplayName,\n      groups: chunks.map((chunk, idx) => ({\n        name: generateTierGroupName(tr, idx, chunks.length),\n        players: chunk.map((r) => ({\n          userId: r.userId,\n          displayName: r.displayName,\n          seedOrder: targetSeedOrderForPromotionRow(r),\n        })),\n        isComplete: chunk.length === groupSize,\n      })),\n    })\n  }", "old_string": "  for (const targetOrderIndex of tierKeys) {\n    const bucket = byTier.get(targetOrderIndex)!\n    const sorted = [...bucket].sort((a, b) => comparePromotionPreviewPlayers(a, b))\n    const tr = tierRankForOrderIndex(targetOrderIndex)\n    const tierDisplayName = promotionTierLabel(tr, undefined, getMaxPromotionTier(tierEntries))\n    const chunks = chunkPlayersIntoGroups(sorted, groupSize)\n    out.push({\n      targetOrderIndex,\n      tierDisplayName,\n      groups: chunks.map((chunk, idx) => ({\n        name: generateTierGroupName(tr, idx, chunks.length),\n        players: chunk.map((r) => ({ userId: r.userId, displayName: r.displayName })),\n        isComplete: chunk.length === groupSize,\n      })),\n    })\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "      p.players.forEach((pl) => {\n        gpRows.push({\n          group_id: gid,\n          user_id: pl.userId,\n          display_name: pl.displayName,\n          seed_order: pl.seedOrder,\n        })\n      })", "old_string": "      p.players.forEach((pl, seed) => {\n        gpRows.push({\n          group_id: gid,\n          user_id: pl.userId,\n          display_name: pl.displayName,\n          seed_order: seed,\n        })\n      })", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\nextTournamentFromPrevious.ts"}}]}}'
);

