rseGroupNameTierNumber,\n  promotionTierLabel,\n  targetSeedOrderForPromotionRow,\n  validatePromotionPreviewCascade,\n} from ''@/utils/nextTournamentPromotion''", "old_string": "import {\n  buildPromotionTierLadderEntries,\n  getMaxPromotionTier,\n  getPromotionTierRankForGroup,\n  getTargetGroupOrder,\n  isMbBottomTierGroupName,\n  orderIndexForTierRank,\n  parseGroupNameTierNumber,\n  promotionTierLabel,\n  validatePromotionPreviewCascade,\n} from ''@/utils/nextTournamentPromotion''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\utils\\nextTournamentPromotion.test.ts"}}, {"type": "tool_use", "name": "Shell", "input": {"block_until_ms": 90000, "command": "cd \"c:\\Users\\alpev\\tennis-tournament-app\"; npm test -- --run src/utils/nextTournamentPromotion.test.ts 2>&1", "description": "Run promotion seed order tests"}}]}}'
