INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0522',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  522,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Listo. Al crear el siguiente torneo, la **siembra** (`seed_order`) en el grupo destino sigue estas reglas:\n\n| Origen | Movimiento | Lugar en el grupo nuevo |\n|--------|------------|-------------------------|\n| **4.º** | Baja | **1.º** (seed 0) |\n| **5.º** | Baja | **2.º** (seed 1) |\n| **3.º** | Se queda | **3.º** (seed 2) |\n| **1.º** | Sube | **4.º** (seed 3) |\n| **2.º** | Sube | **5.º** (seed 4) |\n\nEjemplo: el **4.º del GRUPO 5** que baja al **GRUPO 6** queda en **1.º lugar**; el **1.º del GRUPO 7** que sube al **GRUPO 6** queda en **4.º lugar**.\n\nEn los topes (GRUPO 1 / MB) se mantiene la lógica: quien no puede subir/bajar conserva posiciones altas o bajas según corresponda.\n\nLos jugadores se ordenan por siembra al armar cada grupo, y al guardar en BD se usa ese `seed_order` (ya no el orden por puntos).\n\n[REDACTED]"}]}}'
);

