INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0569',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  569,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Mejoré el diseño del botón **Crear siguiente torneo** en el encabezado de `/admin/tournaments`:\n\n## Cambios\n\n- **CTA principal** con color de marca (`#1F5A4C`), gradiente suave y sombra para que destaque frente al resto de acciones.\n- **Layout en dos líneas**: título + subtítulo contextual (`Ascensos, grupos y round robin`).\n- **Icono en badge** a la izquierda y **chevron** a la derecha al pasar el cursor (estado habilitado).\n- **Estado deshabilitado** coherente: borde punteado, icono de candado y texto explicativo (`Cierra o activa el torneo abierto`).\n- **Tamaño más cómodo** (`min-h-11`, ancho mínimo en desktop) para mejor legibilidad y clic.\n\nRecarga la página para ver el nuevo diseño. Si quieres, puedo ajustar tono (más sobrio o más compacto) o alinearlo con otro botón del admin.\n\n[REDACTED]"}]}}'
);

