INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0582',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  582,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Homologué **Filtros** y **Listado** en `/admin/users` con el mismo patrón que Partidos.\n\n## Filtros\n- Usa `AdminMatchScopeFiltersBar`: encabezado + botón **Limpiar filtros** / **Restablecer**\n- Búsqueda arriba, desplegables en **rejilla con etiquetas** (Rol, Categoría, Estado, Grupo)\n- Tarjeta con borde, gradiente y sombra suave\n- Tooltip del filtro Grupo cuando hay nombres duplicados\n\n## Listado\n- Título compacto con descripción breve (sin párrafo largo)\n- **Panel de resumen** con:\n  - Contador destacado de resultados vs total del directorio\n  - Badge **Filtros activos** / **Sin filtros**\n  - Aviso de paginación cuando aplica («Ver más»)\n  - Leyenda estructurada para **Recuperación** y **Cuenta**\n- Barra de acciones masivas alineada al mismo estilo de tarjeta\n\nRecarga `/admin/users` para ver los cambios. Si quieres, el siguiente paso puede ser unificar métricas y filtros en una sola sección «Directorio».\n\n[REDACTED]"}]}}'
);

