    </li>\n                  <li>\n                    <ClubChip>{stats.groupCount} grupos</ClubChip>\n                  </li>\n                  {stats.format ? (\n                    <li>\n                      <ClubChip>{stats.format}</ClubChip>\n                    </li>\n                  ) : null}\n                </ul>\n              ) : null}\n\n              <div className=\"tournament-club-banner__status-row\">\n                <ClubStatusPill variant={statusVariant}>{statusLabel}</ClubStatusPill>\n              </div>\n\n              {structured ? (\n                <p className=\"tournament-club-banner__description\">{description}</p>\n              ) : showMetaLine ? (\n                <p className=\"tournament-club-banner__description tournament-club-banner__description--meta\">{meta}</p>\n              ) : null}\n            </>\n          )}\n        </div>\n      </div>\n    </header>\n  )\n}", "old_string": "export function TournamentClubBanner(props: Props) {\n  const {\n    title = TDASH_COPY.heroTitle,\n    meta = TDASH_COPY.heroMeta,\n    stats,\n    statusLabel = TDASH_COPY.status,\n    statusVariant = ''active'',\n    eyebrow = TDASH_COPY.heroEyebrow,\n    description = TDASH_COPY.heroDescriptionClub,\n  } = props\n\n  const structured = stats != null\n  const showMetaLine = Boolean(meta) && !structured\n\n  return (\n    <header className=\"tournament-club-banner group relative overflow-hidden\">\n      <div className=\"tournament-club-banner__radial\" aria-hidden />\n      <BannerAccentLine />\n\n      <div className=\"tournament-club-banner__inner\">\n        <BannerIconArea />\n\n        <div className=\"tournament-club-banner__content min-w-0\">\n          <span className=\"tournament-club-banner__eyebrow\">{eyebrow}</span>\n\n          <h1 className=\"tournament-club-banner__title\">{title}</h1>\n\n          {structured ? (\n            <ul\n              className=\"tournament-club-banner__chips flex list-none flex-wrap gap-2 p-0 sm:gap-2.5\"\n              aria-label=\"Resumen del torneo\"\n            >\n              <li>\n                <ClubChip>\n                  {stats.playerCount} jugadores\n                </ClubChip>\n              </li>\n              <li>\n                <ClubChip>\n                  {stats.groupCount} grupos\n                </ClubChip>\n              </li>\n              {stats.format ? (\n                <li>\n                  <ClubChip>{stats.format}</ClubChip>\n                </li>\n              ) : null}\n            </ul>\n          ) : null}\n\n          <div className=\"tournament-club-banner__status-row\">\n            <ClubStatusPill variant={statusVariant}>{statusLabel}</ClubStatusPill>\n          </div>\n\n          {structured ? (\n            <p className=\"tournament-club-banner__description\">{description}</p>\n          ) : showMetaLine ? (\n            <p className=\"tournament-club-banner__description tournament-club-banner__description--meta\">\n              {meta}\n            </p>\n          ) : null}\n        </div>\n      </div>\n    </header>\n  )\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\tournament-dashboard\\TournamentClubBanner.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "    <TournamentClubBanner\n      compact\n      eyebrow=\"Dashboard del torneo\"", "old_string": "    <TournamentClubBanner\n      eyebrow=\"Dashboard del torneo\"", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\dashboard\\TournamentDashboardHeaderCompact.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": ".tournament-club-banner__status-row {\n  margin-top: 0.15rem;\n}\n\n/* —— Compact dashboard header (menos altura, fila en móvil) —— */\n.tournament-club-banner--compact {\n  border-radius: 1rem;\n  box-shadow:\n    0 1px 2px rgba(16, 42, 67, 0.04),\n    0 6px 22px -6px rgba(16, 42, 67, 0.07);\n}\n\n.tournament-club-banner--compact:hover {\n  box-shadow:\n    0 1px 2px rgba(16, 42, 67, 0.05),\n    0 10px 28px -8px rgba(16, 42, 67, 0.09);\n}\n\n.tournament-club-banner--compact .tournament-club-banner__inner {\n  flex-direction: row;\n  align-items: flex-start;\n  gap: 0.75rem;\n  padding: 0.8rem 0.9rem 0.85rem 0.65rem;\n  padding-left: calc(0.55rem + 3px);\n}\n\n@media (min-width: 640px) {\n  .tournament-club-banner--compact .tournament-club-banner__inner {\n    align-items: center;\n    gap: 1rem;\n    padding: 0.95rem 1.1rem 1rem 0.85rem;\n    padding-left: calc(0.75rem + 4px);\n  }\n}\n\n.tournament-club-banner--compact .tournament-club-banner__icon-inner {\n  width: 2.65rem;\n  height: 2.65rem;\n  border-radius: 0.8rem;\n}\n\n@media (min-width: 640px) {\n  .tournament-club-banner--compact .tournament-club-banner__icon-inner {\n    width: 3.1rem;\n    height: 3.1rem;\n    border-radius: 0.9rem;\n  }\n}\n\n.tournament-club-banner--compact .tournament-club-banner__content {\n  gap: 0.35rem;\n}\n\n@media (min-width: 640px) {\n  .tournament-club-banner--compact .tournament-club-banner__content {\n    gap: 0.45rem;\n    padding-top: 0;\n  }\n}\n\n.tournament-club-banner--compact .tournament-club-banner__eyebrow {\n  font-size: 0.6rem;\n  letter-spacing: 0.16em;\n  line-height: 1.2;\n}\n\n@media (min-width: 640px) {\n  .tournament-club-banner--compact .tournament-club-banner__eyebrow {\n    font-size: 0.625rem;\n    letter-spacing: 0.18em;\n  }\n}\n\n.tournament-club-banner--compact .tournament-club-banner__title {\n  font-size: 1.0625rem;\n  line-height: 1.2;\n  letter-spacing: -0.025em;\n}\n\n@media (min-width: 640px) {\n  .tournament-club-banner--compact .tournament-club-banner__title {\n    font-size: 1.25rem;\n  }\n}\n\n@media (min-width: 1024px) {\n  .tournament-club-banner--compact .tournament-club-banner__title {\n    font-size: 1.375rem;\n  }\n}\n\n.tournament-club-banner--compact .tournament-club-banner__headline-row .club-status {\n  margin-top: 0.1rem;\n  flex-shrink: 0;\n}\n\n@media (min-width: 640px) {\n  .tournament-club-banner--compact .tournament-club-banner__headline-row .club-status {\n    margin-top: 0;\n  }\n}\n\n.tournament-club-banner--compact .tournament-club-banner__chips {\n  margin: 0;\n}\n\n.tournament-club-banner--compact .club-chip {\n  padding: 0.25rem 0.6rem 0.3rem;\n  font-size: 0.6875rem;\n}\n\n@media (min-width: 640px) {\n  .tournament-club-banner--compact .club-chip {\n    padding: 0.3rem 0.7rem 0.35rem;\n    font-size: 0.71875rem;\n  }\n}\n\n.tournament-club-banner--compact .club-status--active {\n  padding: 0.28rem 0.65rem 0.32rem 0.5rem;\n  font-size: 0.625rem;\n}\n\n@media (min-width: 640px) {\n  .tournament-club-banner--compact .club-status--active {\n    padding: 0.32rem 0.75rem 0.36rem 0.55rem;\n    font-size: 0.625rem;\n  }\n}\n\n.tournament-club-banner--compact .club-status__pulse {\n  width: 0.4rem;\n  height: 0.4rem;\n}\n\n.tournament-club-banner--compact .tournament-club-banner__description--inline {\n  margin: 0;\n  max-width: none;\n  flex: 1 1 12rem;\n  font-size: 0.75rem;\n  line-height: 1.4;\n  color: var(--club-muted);\n}\n\n@media (min-width: 1024px) {\n  .tournament-club-banner--compact .tournament-club-banner__description--inline {\n    font-size: 0.8125rem;\n  }\n}\n\n.club-chip {", "old_string": ".tournament-club-banner__status-row {\n  margin-top: 0.15rem;\n}\n\n.club-chip {", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\styles\\tournament-dashboard.css"}}]}}'
