  651,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Centralizando el cierre de sesión con limpieza optimista para que sea instantáneo y fiable.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "/** Elimina tokens de Supabase en storage (fallback si signOut falla). */\nexport function clearSupabaseAuthStorage(): void {\n  try {\n    const rm: string[] = []\n    for (let i = 0; i < localStorage.length; i++) {\n      const k = localStorage.key(i)\n      if (k && k.startsWith(''sb-'')) rm.push(k)\n    }\n    for (const k of rm) localStorage.removeItem(k)\n    const rs: string[] = []\n    for (let i = 0; i < sessionStorage.length; i++) {\n      const k = sessionStorage.key(i)\n      if (k && k.startsWith(''sb-'')) rs.push(k)\n    }\n    for (const k of rs) sessionStorage.removeItem(k)\n  } catch {\n    /* ignore */\n  }\n}\n\nasync function signOutLocalQuiet(): Promise<void> {\n  try {\n    await supabase.auth.signOut({ scope: ''local'' })\n  } catch {\n    /* ignore */\n  }\n}", "old_string": "export async function recoverFromAuthError(error: unknown): Promise<boolean> {\n  if (!isInvalidRefreshTokenError(error)) return false\n  try {\n    await supabase.auth.signOut({ scope: ''local'' })\n  } catch {\n    /* ignore */\n  }\n  try {\n    const prefix = ''sb-''\n    const keysToRemove: string[] = []\n    for (let i = 0; i < localStorage.length; i++) {\n      const k = localStorage.key(i)\n      if (k && k.startsWith(prefix)) keysToRemove.push(k)\n    }\n    for (const k of keysToRemove) localStorage.removeItem(k)\n    for (let i = 0; i < sessionStorage.length; i++) {\n      const k = sessionStorage.key(i)\n      if (k && k.startsWith(prefix)) sessionStorage.removeItem(k)\n    }\n  } catch {\n    /* ignore */\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\authSessionRecovery.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export async function recoverFromAuthError(error: unknown): Promise<boolean> {\n  if (!isInvalidRefreshTokenError(error)) return false\n  await signOutLocalQuiet()\n  clearSupabaseAuthStorage()", "old_string": "  useAuthStore.getState().setSession(null)\n  useAuthStore.getState().setProfile(null)\n  useAuthStore.getState().setInitialized(true)\n  if (typeof window !== ''undefined'' && !window.location.pathname.startsWith(''/login'')) {\n    window.location.assign(''/login'')\n  }\n  return true\n}\n\n/** Limpieza manual (p. ej. desde login). */\nexport async function clearLocalAuthAndGoToLogin(): Promise<void> {\n  try {\n    await supabase.auth.signOut({ scope: ''local'' })\n  } catch {\n    /* ignore */\n  }\n  try {\n    const rm: string[] = []\n    for (let i = 0; i < localStorage.length; i++) {\n      const k = localStorage.key(i)\n      if (k && k.startsWith(''sb-'')) rm.push(k)\n    }\n    for (const k of rm) localStorage.removeItem(k)\n    const rs: string[] = []\n    for (let i = 0; i < sessionStorage.length; i++) {\n      const k = sessionStorage.key(i)\n      if (k && k.startsWith(''sb-'')) rs.push(k)\n    }\n    for (const k of rs) sessionStorage.removeItem(k)\n  } catch {\n    /* ignore */\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\authSessionRecovery.ts"}}]}}'
);

