INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0653',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  653,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"contents": "import { supabase } from ''@/lib/supabase''\nimport { useAuthStore } from ''@/stores/authStore''\n\n/** Detecta refresh inválido / sesión corrupta en errores de Supabase Auth. */\nexport function isInvalidRefreshTokenError(error: unknown): boolean {\n  const msg = (error instanceof Error ? error.message : String(error ?? '''')).toLowerCase()\n  return msg.includes(''invalid refresh token'') || msg.includes(''refresh token not found'')\n}\n\n/** Elimina tokens de Supabase en storage (fallback si signOut falla). */\nexport function clearSupabaseAuthStorage(): void {\n  try {\n    const rm: string[] = []\n    for (let i = 0; i < localStorage.length; i++) {\n      const k = localStorage.key(i)\n      if (k && k.startsWith(''sb-'')) rm.push(k)\n    }\n    for (const k of rm) localStorage.removeItem(k)\n    const rs: string[] = []\n    for (let i = 0; i < sessionStorage.length; i++) {\n      const k = sessionStorage.key(i)\n      if (k && k.startsWith(''sb-'')) rs.push(k)\n    }\n    for (const k of rs) sessionStorage.removeItem(k)\n  } catch {\n    /* ignore */\n  }\n}\n\nasync function signOutLocalQuiet(): Promise<void> {\n  try {\n    await supabase.auth.signOut({ scope: ''local'' })\n  } catch {\n    /* ignore */\n  }\n}\n\n/**\n * Limpia sesión local y redirige a login si la sesión no es recuperable.\n * @returns true si se aplicó recuperación (no re-lanzar el error al caller).\n */\nexport async function recoverFromAuthError(error: unknown): Promise<boolean> {\n  if (!isInvalidRefreshTokenError(error)) return false\n  await signOutLocalQuiet()\n  clearSupabaseAuthStorage()\n  useAuthStore.getState().setSession(null)\n  useAuthStore.getState().setProfile(null)\n  useAuthStore.getState().setInitialized(true)\n  if (typeof window !== ''undefined'' && !window.location.pathname.startsWith(''/login'')) {\n    window.location.assign(''/login'')\n  }\n  return true\n}\n\n/** Limpieza manual (p. ej. desde login). */\nexport async function clearLocalAuthAndGoToLogin(): Promise<void> {\n  await signOutLocalQuiet()\n  clearSupabaseAuthStorage()\n  useAuthStore.getState().setSession(null)\n  useAuthStore.getState().setProfile(null)\n  useAuthStore.getState().setInitialized(true)\n  window.location.assign(''/login'')\n}\n"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "const profileRequests = new Map<string, Promise<Profile | null>>()\n\n/** Limpia deduplicación de perfil al cerrar sesión (evita datos obsoletos al re-entrar). */\nexport function clearProfileRequestCache(): void {\n  profileRequests.clear()\n}", "old_string": "const profileRequests = new Map<string, Promise<Profile | null>>()", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\stores\\authStore.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "      if (profile?.status === ''inactive'') {\n        await supabase.auth.signOut({ scope: ''local'' })\n        clearProfileRequestCache()\n        set({ session: null, user: null, profile: null, profileLoading: false })\n        return\n      }", "old_string": "      if (profile?.status === ''inactive'') {\n        await supabase.auth.signOut()\n        set({ session: null, user: null, profile: null, profileLoading: false })\n        return\n      }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\stores\\authStore.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  supabase.auth.onAuthStateChange(async (event, session) => {\n    useAuthStore.getState().setSession(session)\n    if (event === ''SIGNED_OUT'' || !session) {\n      clearProfileRequestCache()\n      useAuthStore.getState().setProfile(null)\n      return\n    }\n    try {\n      await useAuthStore.getState().refreshProfile()\n    } catch (e) {\n      void recoverFromAuthError(e)\n    }\n  })", "old_string": "  supabase.auth.onAuthStateChange(async (_event, session) => {\n    useAuthStore.getState().setSession(session)\n    try {\n      await useAuthStore.getState().refreshProfile()\n    } catch (e) {\n      void recoverFromAuthError(e)\n    }\n  })", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\stores\\authStore.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import type { AuthError } from ''@supabase/supabase-js''\nimport type { QueryClient } from ''@tanstack/react-query''\n\nimport { clearSupabaseAuthStorage } from ''@/lib/authSessionRecovery''\nimport { supabase } from ''@/lib/supabase''\nimport { isAdminRole } from ''@/lib/permissions''\nimport { formatAuthPasswordError } from ''@/lib/passwordPolicy''\nimport { invokeResolveAuthEmailByPhone } from ''@/services/authEdge''\nimport { clearProfileRequestCache, useAuthStore } from ''@/stores/authStore''\nimport type { Profile } from ''@/types/database''", "old_string": "import type { AuthError } from ''@supabase/supabase-js''\n\nimport { supabase } from ''@/lib/supabase''\nimport { isAdminRole } from ''@/lib/permissions''\nimport { formatAuthPasswordError } from ''@/lib/passwordPolicy''\nimport { invokeResolveAuthEmailByPhone } from ''@/services/authEdge''\nimport type { Profile } from ''@/types/database''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\auth.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "export async function signOut() {\n  const { error } = await supabase.auth.signOut({ scope: ''local'' })\n  if (error) throw error\n}\n\nexport type SignOutFromAppOptions = {\n  queryClient?: QueryClient\n  /** Navegación SPA inmediata tras limpiar estado en memoria. */\n  onNavigate?: () => void\n}\n\n/**\n * Cierre de sesión optimista: limpia store y navega al login de inmediato;\n * luego persiste signOut local en Supabase (sin round-trip global).\n */\nexport async function signOutFromApp(options?: SignOutFromAppOptions): Promise<void> {\n  clearProfileRequestCache()\n  useAuthStore.getState().setSession(null)\n  useAuthStore.getState().setProfile(null)\n\n  options?.queryClient?.cancelQueries()\n  options?.queryClient?.clear()\n  options?.onNavigate?.()\n\n  try {\n    await signOut()\n  } catch (error) {\n    clearSupabaseAuthStorage()\n    throw error\n  }\n}", "old_string": "export async function signOut() {\n  const { error } = await supabase.auth.signOut({ scope: ''local'' })\n  if (error) throw error\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\auth.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "import { signOutFromApp } from ''@/lib/auth''", "old_string": "import { signOut } from ''@/lib/auth''", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\layout\\AppHeader.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  const handleSignOut = async () => {\n    if (signingOut) return\n    setSigningOut(true)\n    try {\n      await signOutFromApp({\n        queryClient,\n        onNavigate: () => navigate(''/login'', { replace: true }),\n      })\n    } catch (e) {\n      toast.error(e instanceof Error ? e.message : ''No se pudo cerrar sesión'')\n    } finally {\n      setSigningOut(false)\n    }\n  }", "old_string": "  const handleSignOut = async () => {\n    setSigningOut(true)\n    try {\n      queryClient.clear()\n      await signOut()\n      useAuthStore.getState().setSession(null)\n      useAuthStore.getState().setProfile(null)\n      navigate(''/login'', { replace: true })\n    } catch (e) {\n      toast.error(e instanceof Error ? e.message : ''No se pudo cerrar sesión'')\n    } finally {\n      setSigningOut(false)\n    }\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\layout\\AppHeader.tsx"}}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
