  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\authSessionRecovery.ts", "contents": "import { supabase } from ''@/lib/supabase''\nimport { useAuthStore } from ''@/stores/authStore''\n\n/** Detecta refresh inválido / sesión corrupta en errores de Supabase Auth. */\nexport function isInvalidRefreshTokenError(error: unknown): boolean {\n  const msg = (error instanceof Error ? error.message : String(error ?? '''')).toLowerCase()\n  return msg.includes(''invalid refresh token'') || msg.includes(''refresh token not found'')\n}\n\n/** Elimina tokens de Supabase en storage (fallback si signOut falla). */\nexport function clearSupabaseAuthStorage(): void {\n  try {\n    const rm: string[] = []\n    for (let i = 0; i < localStorage.length; i++) {\n      const k = localStorage.key(i)\n      if (k && k.startsWith(''sb-'')) rm.push(k)\n    }\n    for (const k of rm) localStorage.removeItem(k)\n    const rs: string[] = []\n    for (let i = 0; i < sessionStorage.length; i++) {\n      const k = sessionStorage.key(i)\n      if (k && k.startsWith(''sb-'')) rs.push(k)\n    }\n    for (const k of rs) sessionStorage.removeItem(k)\n  } catch {\n    /* ignore */\n  }\n}\n\nasync function signOutLocalQuiet(): Promise<void> {\n  try {\n    await supabase.auth.signOut({ scope: ''local'' })\n  } catch {\n    /* ignore */\n  }\n}\n\n/**\n * Limpia sesión local y redirige a login si la sesión no es recuperable.\n * @returns true si se aplicó recuperación (no re-lanzar el error al caller).\n */\nexport async function recoverFromAuthError(error: unknown): Promise<boolean> {\n  if (!isInvalidRefreshTokenError(error)) return false\n  await signOutLocalQuiet()\n  clearSupabaseAuthStorage()\n  useAuthStore.getState().setSession(null)\n  useAuthStore.getState().setProfile(null)\n  useAuthStore.getState().setInitialized(true)\n  if (typeof window !== ''undefined'' && !window.location.pathname.startsWith(''/login'')) {\n    window.location.assign(''/login'')\n  }\n  return true\n}\n\n/** Limpieza manual (p. ej. desde login). */\nexport async function clearLocalAuthAndGoToLogin(): Promise<void> {\n  await signOutLocalQuiet()\n  clearSupabaseAuthStorage()\n  useAuthStore.getState().setSession(null)\n  useAuthStore.getState().setProfile(null)\n  useAuthStore.getState().setInitialized(true)\n  window.location.assign(''/login'')\n}\n"}}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\auth.signOut.test.ts", "contents": "import { beforeEach, describe, expect, it, vi } from ''vitest''\n\nimport type { Session } from ''@supabase/supabase-js''\n\nconst signOutMock = vi.fn()\nconst clearSupabaseAuthStorageMock = vi.fn()\n\nvi.mock(''@/lib/supabase'', () => ({\n  supabase: {\n    auth: {\n      signOut: signOutMock,\n    },\n  },\n}))\n\nvi.mock(''@/lib/authSessionRecovery'', () => ({\n  clearSupabaseAuthStorage: clearSupabaseAuthStorageMock,\n}))\n\nconst { useAuthStore, clearProfileRequestCache } = await import(''@/stores/authStore'')\nconst { signOutFromApp } = await import(''@/lib/auth'')\n\nfunction sessionFor(userId: string): Session {\n  return {\n    user: { id: userId, email: `${userId}@example.com` },\n  } as Session\n}\n\ndescribe(''signOutFromApp'', () => {\n  beforeEach(() => {\n    signOutMock.mockReset()\n    clearSupabaseAuthStorageMock.mockReset()\n    clearProfileRequestCache()\n    useAuthStore.setState({\n      session: null,\n      user: null,\n      profile: null,\n      profileLoading: false,\n      initialized: true,\n    })\n  })\n\n  it(''clears auth state and navigates before awaiting Supabase signOut'', async () => {\n    signOutMock.mockImplementation(\n      () =>\n        new Promise((resolve) => {\n          setTimeout(() => resolve({ error: null }), 20)\n        }),\n    )\n\n    useAuthStore.getState().setSession(sessionFor(''u1''))\n\n    const steps: string[] = []\n    const queryClient = {\n      cancelQueries: vi.fn(() => {\n        steps.push(''cancelQueries'')\n      }),\n      clear: vi.fn(() => {\n        steps.push(''clear'')\n      }),\n    }\n\n    const promise = signOutFromApp({\n      queryClient: queryClient as never,\n      onNavigate: () => steps.push(''navigate''),\n    })\n\n    expect(useAuthStore.getState().session).toBeNull()\n    expect(useAuthStore.getState().user).toBeNull()\n    expect(steps).toEqual([''cancelQueries'', ''clear'', ''navigate''])\n\n    await promise\n\n    expect(signOutMock).toHaveBeenCalledWith({ scope: ''local'' })\n    expect(clearSupabaseAuthStorageMock).not.toHaveBeenCalled()\n  })\n\n  it(''clears Supabase storage if local signOut fails'', async () => {\n    signOutMock.mockResolvedValue({ error: new Error(''storage error'') })\n\n    useAuthStore.getState().setSession(sessionFor(''u1''))\n\n    await expect(signOutFromApp()).rejects.toThrow(''storage error'')\n    expect(clearSupabaseAuthStorageMock).toHaveBeenCalled()\n  })\n})\n"}}]}}'
);

