INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0663',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  663,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Listo. La sección **Operación general** quedó más compacta y clara:\n\n## Cambios\n\n- **Panel único** con borde y fondo blanco (como en Vista general), en lugar de título suelto + 4 tarjetas grandes.\n- **Torneo activo** en un chip lateral con nombre truncado, icono y badge de estado — ya no ocupa una tarjeta KPI entera.\n- **3 KPIs compactos** (Jugadores, Grupos, Partidos) con iconos y detalle en ℹ️ (`descriptionMode=\"info\"`), menos texto repetido.\n- **Partidos** muestra `jugados/total` + trend con % jugados.\n- **Barra de avance** fina bajo los KPIs cuando hay partidos (ámbar si faltan marcadores, verde si está al día).\n- **Responsive**: 1 columna en móvil estrecho, 2 en tablet, 3 en desktop; skeleton de carga más bajo.\n\nRecarga `/admin/tournaments` para ver el nuevo diseño.\n\n[REDACTED]"}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0664',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  664,
  '<user_query>
