ia-label=\"Partidos jugados del torneo activo\"\n              >\n                <div className=\"flex items-center justify-between gap-2 text-[11px] font-medium text-slate-600\">\n                  <span>Avance de partidos</span>\n                  <span className=\"tabular-nums text-slate-800\">\n                    {overview.playedMatches} / {overview.totalMatches}\n                  </span>\n                </div>\n                <div className=\"h-1.5 overflow-hidden rounded-full bg-slate-200/90\">\n                  <div\n                    className={cn(\n                      ''h-full rounded-full transition-[width] duration-500'',\n                      overview.matchesWithoutDate > 0 ? ''bg-amber-500'' : ''bg-emerald-600'',\n                    )}\n                    style={{\n                      width: `${Math.min(100, Math.round((overview.playedMatches / overview.totalMatches) * 100))}%`,\n                    }}\n                  />\n                </div>\n              </div>\n            ) : null}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminTournamentsPage.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "        <div id=\"admin-tournaments-loading\" className=\"space-y-3\">\n          <Skeleton className=\"h-24 w-full rounded-xl\" />\n        </div>", "old_string": "        <div id=\"admin-tournaments-loading\" className=\"space-y-3\">\n          <Skeleton className=\"h-28 w-full rounded-xl sm:h-32\" />\n        </div>", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminTournamentsPage.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "            className=\"scroll-mt-3 space-y-2.5 rounded-xl border border-slate-200/70 bg-white p-2.5 shadow-sm sm:space-y-3 sm:rounded-2xl sm:p-3.5\"", "old_string": "            className=\"scroll-mt-3 space-y-3 rounded-xl border border-slate-200/70 bg-white p-3 shadow-sm sm:rounded-2xl sm:p-4\"", "path": 