INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0693',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  693,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Listo. El formato **«2 de 3 sets»** (`best_of_3`) ya acepta **1-0 en el tercer set** cuando van 1-1 en sets.\n\n### Qué fallaba\nLa validación solo permitía 1-0 en el set decisivo para `best_of_3_short_tiebreak`, no para `best_of_3` (la opción «2 de 3 sets» en la UI).\n\n### Cambios\n\n1. **`src/utils/score.ts`** — Con `allowShortDecisiveSet: true`, el set 3 a 1-1 acepta **1-0**            0-1** (super tie-break) **o** un set clásico (p. ej. 6-4).\n\n2. **`src/services/matches.ts`** y **`ScoreSubmissionModal.tsx`** — `best_of_3` envía con `allowShortDecisiveSet: true`.\n\n3. **UI** — Si van 1-1 en sets, el set 3 muestra el mismo selector de ganador del mini tie-break (como en muerte súbita), en lugar de campos numéricos.\n\n4. **Tests** — `src/utils/score.bestOf3.test.ts` cubre `6-4, 4-6, 1-0` y casos relacionados (9 tests pasan).\n\n### Cómo probarlo\n1. Abre un partido y elige **2 de 3 sets**.\n2. Captura **6-4** y **4-6** en los dos primeros sets.\n3. En el set 3, elige quién ganó el super tie-break → se guarda como **1-0**.\n\nSi quieres, también puedo alinear la importación masiva CSV para `best_of_3` con la misma regla.\n\n[REDACTED]"}]}}'
