INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0706',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  706,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\supabase\\migrations\\052_decisive_set_short_or_classic.sql", "contents": "-- Set decisivo en 2 de 3: acepta super tie-break (1-0) o marcador clásico (6-0…6-4, 7-5, 7-6).\n-- Alineado con src/lib/tournamentRulesEngine.ts\n\ncreate or replace function public.validate_match_score_against_tournament_rules(\n  p_tournament_id uuid,\n  p_score jsonb,\n  p_winner_group_player_id uuid,\n  p_player_a_id uuid,\n  p_player_b_id uuid\n)\nreturns void\nlanguage plpgsql\nstable\nas $$\ndeclare\n  v_best_of int;\n  games_i int;\n  max_sets int;\n  need int;\n  n int;\n  i int;\n  a int;\n  b int;\n  a_wins int := 0;\n  b_wins int := 0;\n  winner uuid;\n  deciding boolean;\n  use_short boolean;\n  final_fmt text;\n  short_ok boolean;\n  classic_ok boolean;\nbegin\n  if p_score is null or jsonb_typeof(p_score) <> ''array'' or jsonb_array_length(p_score) = 0 then\n    raise exception ''Indica el marcador por sets'';\n  end if;\n\n  select\n    tr.best_of_sets,\n    coalesce(nullif(tr.games_per_set, 0), tr.set_points, 6),\n    coalesce(tr.final_set_format, case when tr.super_tiebreak_final_set then ''super_tiebreak'' else ''sudden_death'' end)\n  into strict v_best_of, games_i, final_fmt\n  from public.tournament_rules tr\n  where tr.tournament_id = p_tournament_id;\n\n  games_i := greatest(games_i, 1);\n  max_sets := v_best_of;\n  need := floor(max_sets::float / 2.0)::int + 1;\n\n  n := jsonb_array_length(p_score);\n  if n > max_sets then\n    raise exception ''Máximo % sets según el torneo'', max_sets;\n  end if;\n\n  for i in 0..(n - 1) loop\n    a := (jsonb_array_element(p_score, i)->>''a'')::int;\n    b := (jsonb_array_element(p_score, i)->>''b'')::int;\n    if a is null or b is null then\n      raise exception ''Cada set debe tener valores a y b'';\n    end if;\n    if a < 0 or b < 0 then\n      raise exception ''Los valores no pueden ser negativos'';\n    end if;\n    if a = b then\n      raise exception ''Un set no puede terminar empatado'';\n    end if;\n\n    deciding := (need > 1 and a_wins = need - 1 and b_wins = need - 1);\n    use_short := deciding and final_fmt in (''sudden_death'', ''super_tiebreak'');\n\n    if use_short then\n      short_ok := (a = 1 and b = 0) or (a = 0 and b = 1);\n      classic_ok := games_i = 6 and public.is_valid_classic_six_game_set(a, b);\n      if not (short_ok or classic_ok) then\n        raise exception ''Set decisivo: super tie-break (1-0) o marcador clásico (6-0…6-4, 7-5, 7-6)'';\n      end if;\n    elsif games_i = 6 then\n      if not public.is_valid_classic_six_game_set(a, b) then\n        raise exception ''Set inválido: use 6-0…6-4, 7-5 o 7-6 (tie-break como 7-6)'';\n      end if;\n    end if;\n\n    if a > b then\n      a_wins := a_wins + 1;\n    else\n      b_wins := b_wins + 1;\n    end if;\n  end loop;\n\n  if a_wins < need and b_wins < need then\n    raise exception ''El marcador no define un ganador según el formato del torneo'';\n  end if;\n\n  if a_wins >= need then\n    winner := p_player_a_id;\n  else\n    winner := p_player_b_id;\n  end if;\n\n  if p_winner_group_player_id is distinct from winner then\n    raise exception ''El ganador no coincide con el marcador (sets)'';\n  end if;\nend;\n$$;\n"}}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\lib\\tournamentRulesEngine.decisiveSet.test.ts", "contents": "import { describe, expect, it } from ''vitest''\n\nimport { validateTennisScore } from ''@/lib/tournamentRulesEngine''\nimport type { TournamentRules } from ''@/types/database''\n\nconst bo3Rules = {\n  best_of_sets: 3,\n  set_points: 6,\n  games_per_set: 6,\n  min_game_difference: 2,\n  tiebreak_enabled: true,\n  tiebreak_at: 6,\n  final_set_format: ''super_tiebreak'',\n  super_tiebreak_final_set: true,\n} as TournamentRules\n\ndescribe(''validateTennisScore — set decisivo'', () => {\n  it(''acepta super tie-break 1-0 en set 3'', () => {\n    const result = validateTennisScore(\n      [\n        { a: 6, b: 4 },\n        { a: 4, b: 6 },\n        { a: 1, b: 0 },\n      ],\n      bo3Rules,\n    )\n    expect(result.ok).toBe(true)\n  })\n\n  it(''acepta marcador clásico 6-2 en set 3'', () => {\n    const result = validateTennisScore(\n      [\n        { a: 6, b: 4 },\n        { a: 4, b: 6 },\n        { a: 6, b: 2 },\n      ],\n      bo3Rules,\n    )\n    expect(result.ok).toBe(true)\n  })\n})\n"}}, {"type": "tool_use", "name": "Shell", "input": {"command": "cd \"c:\\Users\\alpev\\tennis-tournament-app\"; npm test -- --run src/utils/score.bestOf3.test.ts src/lib/tournamentRulesEngine.decisiveSet.test.ts 2>&1", "description": "Run decisive set validation tests"}}]}}'
);

