 (prev) => {\n        const n = new URLSearchParams(prev)\n        n.delete(''category'')\n        n.delete(''categoria'')\n        n.delete(''group'')\n        n.delete(''grupo'')\n        return n\n      },\n      { replace: true },\n    )\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\dashboard\\TournamentDashboardPage.tsx"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "      <TournamentFiltersBar\n        tournaments={tournaments}\n        tournamentId={tournamentId}\n        groups={data.groups}\n        groupId={selectedGroupId}\n        defaultGroupId={data.groups[0]?.id ?? ''all''}\n        isFetching={filtersBarShowRefreshing}\n        onTournamentChange={(id) => {\n          setSelectedTournamentId(id)\n          setGroupId(''all'')\n          setSearchParams(\n            (prev) => {\n              const n = new URLSearchParams(prev)\n              n.set(''tournament'', id)\n              n.delete(''torneo'')\n              n.delete(''group'')\n              n.delete(''grupo'')\n              return n\n            },\n            { replace: true },\n          )\n        }}\n        onGroupChange={(id) => {", "old_string": "      <TournamentFiltersBar\n        tournaments={tournaments}\n        tournamentId={tournamentId}\n        groupCategories={groupCategories}\n        groupCategoryId={effectiveGroupCategoryId}\n        groups={data.groups}\n        groupId={selectedGroupId}\n        defaultGroupId={data.groups[0]?.id ?? ''all''}\n        isFetching={filtersBarShowRefreshing}\n        onTournamentChange={(id) => {\n          setSelectedTournamentId(id)\n          setGroupCategoryId(''all'')\n          setGroupId(''all'')\n          setSearchParams(\n            (prev) => {\n              const n = new URLSearchParams(prev)\n              n.set(''tournament'', id)\n              n.delete(''torneo'')\n              n.delete(''category'')\n              n.delete(''categoria'')\n              n.delete(''group'')\n              n.delete(''grupo'')\n              return n\n            },\n            { replace: true },\n          )\n        }}\n        onGroupCategoryChange={(id) => {\n          setGroupCategoryId(id)\n          setGroupId(''all'')\n          setSearchParams(\n            (prev) => {\n              const n = new URLSearchParams(prev)\n              if (id === ''all'') {\n                n.delete(''category'')\n                n.delete(''categoria'')\n              } else {\n                n.set(''category'', id)\n                n.delete(''categoria'')\n              }\n              n.delete(''group'')\n              n.delete(''grupo'')\n              return n\n            },\n            { replace: true },\n          )\n        }}\n        onGroupChange={(id) => {", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\dashboard\\TournamentDashboardPage.tsx"}}]}}'
