INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0777',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  777,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Corregido. Las acciones rápidas ya no dejan las secciones vacías al navegar.\n\n### Causa\n- React Query tenía `refetchOnMount: false` globalmente, así que al cambiar de ruta a veces no se volvían a pedir los datos.\n- En **Grupos**, el torneo se asignaba con un `setTimeout` y podía quedarse en `null` un momento (pantalla vacía/skeletons).\n- El `Outlet` del admin no forzaba remontaje al cambiar de subruta.\n\n### Cambios\n\n1. **Acciones rápidas** — Antes de navegar invalidan las queries de la sección destino y pasan el torneo seleccionado en la URL (`/admin/groups?tournament=…`, `/admin/matches?tournament=…`).\n\n2. **`AdminShell`** — `Outlet` con `key={pathname}` + `Suspense` para remontar y mostrar carga al cambiar de página admin.\n\n3. **Grupos** — Torneo resuelto de forma síncrona (URL → override → activo), sin esperar al efecto async.\n\n4. **Usuarios / Partidos / Grupos** — `refetchOnMount: true` en las queries principales; Partidos también espera a que carguen grupos antes de mostrar vacío.\n\nPrueba otra vez desde **Acciones rápidas** en el overview: debería cargar con datos sin refrescar manualmente.\n\n[REDACTED]"}]}}'
);

