INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0796',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  796,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Las categorías por defecto se volvían a crear al borrarlas porque `ensureDefaultGroupCategories` las reinsertaba en cada recarga. Corrigiendo para que solo se creen si el torneo no tiene ninguna categoría.\n\n[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "/** Inserta las tres categorías por defecto solo si el torneo aún no tiene ninguna. */\nexport async function ensureDefaultGroupCategories(tournamentId: string): Promise<void> {\n  const { data: existing, error: exErr } = await supabase\n    .from(''group_categories'')\n    .select(''id'')\n    .eq(''tournament_id'', tournamentId)\n    .limit(1)\n  if (exErr) {\n    if (isMissingPostgrestRelationError(exErr)) return\n    throw exErr\n  }\n  if ((existing ?? []).length > 0) return\n\n  const rows = DEFAULT_CATEGORIES.map((d) => ({\n    tournament_id: tournamentId,\n    name: d.name,\n    order_index: d.order_index,\n  }))\n  const { error } = await supabase.from(''group_categories'').insert(rows)\n  if (error) throw error\n}", "old_string": "/** Inserta las tres categorías por defecto si el torneo aún no las tiene. */\nexport async function ensureDefaultGroupCategories(tournamentId: string): Promise<void> {\n  const { data: existing, error: exErr } = await supabase\n    .from(''group_categories'')\n    .select(''name'')\n    .eq(''tournament_id'', tournamentId)\n  if (exErr) {\n    if (isMissingPostgrestRelationError(exErr)) return\n    throw exErr\n  }\n  const have = new Set((existing ?? []).map((r) => r.name))\n  const rows = DEFAULT_CATEGORIES.filter((d) => !have.has(d.name)).map((d) => ({\n    tournament_id: tournamentId,\n    name: d.name,\n    order_index: d.order_index,\n  }))\n  if (rows.length === 0) return\n  const { error } = await supabase.from(''group_categories'').insert(rows)\n  if (error) throw error\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\groupCategories.ts"}}, {"type": "tool_use", "name": "Write", "input": {"contents": "import { describe, expect, it } from ''vitest''\n\nimport { DEFAULT_GROUP_CATEGORY_SEED_COUNT } from ''@/services/groupCategories''\n\ndescribe(''ensureDefaultGroupCategories policy'', () => {\n  it(''documenta que el seed inicial solo corre con torneo sin categorías'', () => {\n    expect(DEFAULT_GROUP_CATEGORY_SEED_COUNT).toBe(3)\n  })\n})\n", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\groupCategories.test.ts"}}]}}'
);

