gnados.''\n                      if (typeof window !== ''undefined'' && window.confirm(confirmMessage)) {\n                        onDelete(category.id)\n                      }\n                    }}\n                    aria-label=\"Eliminar categoría\"\n                  >\n                    <Trash2 className=\"size-3.5\" />\n                  </button>\n                </div>\n              </div>\n                )\n              })()\n            ),\n          )}\n        </div>", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminGroupsPage.tsx"}}, {"type": "tool_use", "name": "Grep", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminGroupsPage.tsx", "pattern": "const groupsInTournament"}}]}}'
