INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0829',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  829,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Identificando dos causas: las políticas RLS bloquean el borrado en cascada de partidos al eliminar grupos, y `ensureDefaultGroupCategories` vuelve a crear categorías si se borran todas. Aplicando correcciones.\n\n[REDACTED]"}, {"type": "tool_use", "name": "Write", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\supabase\\migrations\\057_admin_delete_matches_for_group_cleanup.sql", "contents": "-- Permite a administradores eliminar grupos vacíos aunque tengan partidos generados.\n-- Sin políticas DELETE en tablas hijas, el ON DELETE CASCADE desde groups/matches falla bajo RLS.\n\ndrop policy if exists matches_delete_admin on public.matches;\ncreate policy matches_delete_admin\n  on public.matches for delete\n  to authenticated\n  using (public.is_admin());\n\ndrop policy if exists match_score_logs_delete_admin on public.match_score_logs;\ncreate policy match_score_logs_delete_admin\n  on public.match_score_logs for delete\n  to authenticated\n  using (public.is_admin());\n\ndrop policy if exists staff_match_notifications_delete_admin on public.staff_match_notifications;\ncreate policy staff_match_notifications_delete_admin\n  on public.staff_match_notifications for delete\n  to authenticated\n  using (public.is_admin());\n"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\groupCategories.ts", "old_string": "export async function deleteGroupCategory(id: string): Promise<void> {\n  const { error } = await supabase.from(''group_categories'').delete().eq(''id'', id)\n  if (error) throw error\n}", "new_string": "export async function deleteGroupCategory(id: string): Promise<void> {\n  const { data, error } = await supabase.from(''group_categories'').delete().eq(''id'', id).select(''id'')\n  if (error) throw error\n  if (!data?.length) {\n    throw new Error(''No se pudo eliminar la categoría. Verifica permisos de administrador.'')\n  }\n}"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\groups.ts", "old_string": "/** Elimina el grupo solo si no tiene jugadores inscritos. `matches` vacíos pueden eliminarse en cascada con el grupo. */\nexport async function deleteGroup(groupId: string): Promise<void> {\n  const { count, error: countErr } = await supabase\n    .from(''group_players'')\n    .select(''*'', { count: ''exact'', head: true })\n    .eq(''group_id'', groupId)\n  if (countErr) throw countErr\n  if ((count ?? 0) > 0) {\n    throw new Error(\n      ''No puedes eliminar un grupo con jugadores inscritos. Quita primero a todos los jugadores del grupo.'',\n    )\n  }\n  const { error } = await supabase.from(''groups'').delete().eq(''id'', groupId)\n  if (error) throw error\n}", "new_string": "function mapGroupDeleteError(error: { message: string; code?: string }): string {\n  const message = error.message ?? ''''\n  if (error.code === ''42501'' || message.toLowerCase().includes(''row-level security'')) {\n    return ''No se pudo eliminar el grupo: faltan permisos para borrar partidos vinculados. Aplica la migración 057 en Supabase.''\n  }\n  return message || ''No se pudo eliminar el grupo.''\n}\n\n/** Elimina el grupo solo si no tiene jugadores inscritos. Los partidos se eliminan en cascada. */\nexport async function deleteGroup(groupId: string): Promise<void> {\n  const { count, error: countErr } = await supabase\n    .from(''group_players'')\n    .select(''*'', { count: ''exact'', head: true })\n    .eq(''group_id'', groupId)\n  if (countErr) throw countErr\n  if ((count ?? 0) > 0) {\n    throw new Error(\n      ''No puedes eliminar un grupo con jugadores inscritos. Quita primero a todos los jugadores del grupo.'',\n    )\n  }\n  const { data, error } = await supabase.from(''groups'').delete().eq(''id'', groupId).select(''id'')\n  if (error) throw new Error(mapGroupDeleteError(error))\n  if (!data?.length) {\n    throw new Error(\n      ''No se pudo eliminar el grupo. Si tiene partidos generados, aplica la migración 057 en Supabase.'',\n    )\n  }\n}"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\components\\admin\\shared\\AdminConfirmDialog.tsx", "old_string": "        <DialogFooter>\n          <DialogClose render={<Button variant=\"outline\" />}>Cancelar</DialogClose>\n          <DialogClose\n            render={<Button variant=\"destructive\" disabled={disabled} />}\n            onClick={onConfirm}\n          >\n            {confirmLabel}\n          </DialogClose>\n        </DialogFooter>", "new_string": "        <DialogFooter>\n          <Button type=\"button\" variant=\"outline\" onClick={() => setOpen(false)}>\n            Cancelar\n          </Button>\n          <Button\n            type=\"button\"\n            variant=\"destructive\"\n            disabled={disabled}\n            onClick={() => {\n              onConfirm()\n              setOpen(false)\n            }}\n          >\n            {confirmLabel}\n          </Button>\n        </DialogFooter>"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminGroupsPage.tsx", "old_string": "  const categoriesQ = useQuery({\n    queryKey: [''group-categories'', tournamentId],\n    queryFn: async () => {\n      await ensureDefaultGroupCategories(tournamentId!)\n      return listGroupCategories(tournamentId!)\n    },\n    enabled: Boolean(tournamentId),\n    staleTime: 10 * 60_000,\n  })", "new_string": "  const categoriesQ = useQuery({\n    queryKey: [''group-categories'', tournamentId],\n    queryFn: () => listGroupCategories(tournamentId!),\n    enabled: Boolean(tournamentId),\n    staleTime: 10 * 60_000,\n  })"}}, {"type": "tool_use", "name": "StrReplace", "input": {"path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\pages\\admin\\AdminGroupsPage.tsx", "old_string": "  const modalGroupCategoriesQ = useQuery({\n    queryKey: [''group-categories'', ''manager'', managedGroup?.tournament_id],\n    queryFn: async () => {\n      const tid = managedGroup!.tournament_id\n      await ensureDefaultGroupCategories(tid)\n      return listGroupCategories(tid)\n    },\n    enabled: Boolean(managerOpen && managedGroup?.tournament_id),\n    staleTime: 15_000,\n  })", "new_string": "  const modalGroupCategoriesQ = useQuery({\n    queryKey: [''group-categories'', ''manager'', managedGroup?.tournament_id],\n    queryFn: () => listGroupCategories(managedGroup!.tournament_id),\n    enabled: Boolean(managerOpen && managedGroup?.tournament_id),\n    staleTime: 15_000,\n  })"}}]}}'
);

