INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0833',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  833,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "[REDACTED]"}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "function mapGroupDeleteError(error: { message: string; code?: string }): string {\n  const message = error.message ?? ''''\n  if (error.code === ''42501'' || message.toLowerCase().includes(''row-level security'')) {\n    return ''No se pudo eliminar el grupo ni sus partidos vinculados por permisos del servidor.''\n  }\n  return message || ''No se pudo eliminar el grupo.''\n}", "old_string": "function mapGroupDeleteError(error: { message: string; code?: string }): string {\n  const message = error.message ?? ''''\n  if (error.code === ''42501'' || message.toLowerCase().includes(''row-level security'')) {\n    return ''No se pudo eliminar el grupo: faltan permisos para borrar partidos vinculados. Aplica la migración 057 en Supabase.''\n  }\n  return message || ''No se pudo eliminar el grupo.''\n}", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\groups.ts"}}, {"type": "tool_use", "name": "StrReplace", "input": {"new_string": "  if (!data?.length) {\n    throw new Error(''No se pudo eliminar el grupo ni sus partidos vinculados.'')\n  }", "old_string": "  if (!data?.length) {\n    throw new Error(\n      ''No se pudo eliminar el grupo. Si tiene partidos generados, aplica la migración 057 en Supabase.'',\n    )\n  }", "path": "c:\\Users\\alpev\\tennis-tournament-app\\src\\services\\groups.ts"}}]}}'
);

INSERT INTO jsonl_raw_text (id, source_path, line_index, line_text, line_json) VALUES (
  '829c44e6-5361-4d91-bf06-58ffed8d77a8-0834',
  '829c44e6-5361-4d91-bf06-58ffed8d77a8/829c44e6-5361-4d91-bf06-58ffed8d77a8.jsonl',
  834,
  '[REDACTED]',
  '{"role": "assistant", "message": {"content": [{"type": "text", "text": "Encontré y corregí **dos causas** distintas:\n\n### 1. Categorías «sin grupos» que reaparecían\nAl recargar la página, `ensureDefaultGroupCategories` se ejecutaba en cada consulta. Si borrabas **todas** las categorías, al refrescar se volvían a crear las 3 por defecto.\n\n**Cambio:** esas categorías solo se crean al **crear el torneo**; ya no se reinsertan al abrir `/admin/groups`.\n\n### 2. Grupos vacíos con cruces generados\nUn grupo sin jugadores pero con partidos generados no se podía borrar: PostgreSQL intenta eliminar los partidos en cascada, pero **no había políticas RLS de DELETE** en `matches`, `match_score_logs` ni `staff_match_notifications`.\n\n**Cambio:** nueva migración `057_admin_delete_matches_for_group_cleanup.sql` con permisos de borrado para administradores.\n\n### Otros ajustes\n- El diálogo de confirmación de grupos no ejecutaba bien la acción; ahora el botón «Eliminar» llama `onConfirm` correctamente.\n- Los servicios de borrado verifican que la fila se eliminó y muestran un error claro si no.\n\n---\n\n**Importante:** para que el borrado de grupos con partidos funcione en tu Supabase, aplica la migración:\n\n```bash\nsupabase db push\n```\n\n(o despliega `057_admin_delete_matches_for_group_cleanup.sql` en el panel de Supabase).\n\n**Recordatorio:** solo puedes eliminar un grupo si **no tiene jugadores inscritos** (aunque sí pueda tener cruces generados). Para categorías marcadas como «Sin grupos», el borrado debería funcionar de inmediato tras recargar la app.\n\n[REDACTED]"}]}}'
);

